                                                                                                                                                                   0
                                                                                                                                                               )
                                                                                                                                                         - ISNULL(
                                                                                                                                                                     cast(replace(
                                                                                                                                                                                     PSP_ZEIT_MINUTEN_GESAMT_SOLL,
                                                                                                                                                                                     ',',
                                                                                                                                                                                     '.'
                                                                                                                                                                                 ) as float),
                                                                                                                                                                     0
                                                                                                                                                                 )
                                                                                                                                                        ) AS FLOAT)
                                                                                                                                               Else
                                                                                                                                                   CAST('' AS VARCHAR(50))
                                                                                                                                           END,
                                                                                                                                           ',',
                                                                                                                                           '.'
                                                                                                                                       ) as float)
                                                                                                                           * 100
                                                                                                                          )
                                                                                                                          / ISNULL(
                                                                                                                                      cast(replace(
                                                                                                                                                      PSP_ZEIT_MINUTEN_GESAMT_SOLL,
                                                                                                                                                      ',',
                                                                                                                                                      '.'
                                                                                                                                                  ) as float),
                                                                                                                                      0
                                                                                                                                  ),
                                                                                                                          2
                                                                                                                      ),
                                                                                                                 0
                                                                                                             )
                                                                                                   ELSE
                                                                                                       CASE
                                                                                                           WHEN ISNULL(
                                                                                                                          cast(replace(
                                                                                                                                          CASE
                                                                                                                                              WHEN D4IV_TYP_HERKUNFT = 0 THEN
                                                                                                                                                  CAST((ISNULL(
                                                                                                                                                                  cast(replace(
                                                                                                                                                                                  PSP_ZEIT_MINUTEN_GESAMT_IST,
                                                                                                                                                                                  ',',
                                                                                                                                                                                  '.'
                                                                                                                                                                              ) as float),
                                                                                                                                                                  0
                                                                                                                                                              )
                                                                                                                                                        - ISNULL(
                                                                                                                                                                    cast(replace(
                                                                                                                                                                                    PSP_ZEIT_MINUTEN_GESAMT_SOLL,
                                                                                                                                                                                    ',',
                                                                                                                                                                                    '.'
                                                                                                                                                                                ) as float),
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                       ) AS FLOAT)
                                                                                                                                              Else
                                                                                                                                                  CAST('' AS VARCHAR(50))
                                                                                                                                          END,
                                                                                                                                          ',',
                                                                                                                                          '.'
                                                                                                                                      ) as float),
                                                                                                                          0
                                                                                                                      ) <> 0 THEN
                                                                                                               100
                                                                                                           ELSE
                                                                                                               0
                                                                                                       END
                                                                                               END
                                                                                           Else
                                                                                               ''
                                                                                       END < -30 THEN
                                                                                      3
                                                                                  ELSE
                                                                                      0
                                                                              END
                                                                      END
                                                              END
                                                      END
                                              END
                                          ELSE
                                              0
                                      END,
       KP_STATUS_LAGER_KOERPERLICH,
       KP_STATUS_LAGER,
       KP_STATUS_BESTELLUNG,
       PSP_MENGE_SOLL,
       PSP_MENGE_IST_WERT,
       D4IV_TYP_POSITION,
       D4IV_PSP_TYP_MODUS_EINGABE,
       D4IV_TYP_HERKUNFT,
       D4IV_TYP_SPERRE,
       MATERIAL_STATUS_LAGER AS D4IV_MATERIAL_STATUS_LAGER,
       MATERIAL_STATUS_ARID AS D4IV_MATERIAL_STATUS_ARID,
       PSP_TYP_POSITION AS D4IV_PSP_TYP_POSITION,
       PSP_POSITION_NUMMER AS D4IV_PSP_POSITION_NUMMER,
       PSKALK_IDBEBP AS D4IV_IDBEBP_PP,
       STATUS_ZEITERFASSUNG AS D4IV_TYP_STATUS_ZEITERFASSUNG,
       D4IV_PSP_ZEIT_MINUTEN_GESAMT_IST,
       tPPS_SKKALP.ID AS ID
FROM
(
    SELECT CAST(PSP_POSITION_NUMMER AS VARCHAR(20)) AS PSP_POSITION_NUMMER,
           CAST(PSP_TYP_POSITION AS SMALLINT) AS PSP_TYP_POSITION,
           '' AS KP_INTERNTEXT,
           tPRP_AW.PRP_AW AS PRP_AW,
           tPRP_AW.PRP_AW_INDIKATOR AS PRP_AW_INDIKATOR,
           0 AS KP_FLAG_AKT_PREIS_EINKAUF,
           CAST(PSP_PP_STATUS_PRODUKTION AS SMALLINT) AS PSP_PP_STATUS_PRODUKTION,
           CAST(PSP_ZEIT_TAGE_DURCHLAUFZEIT AS FLOAT) AS PSP_ZEIT_TAGE_DURCHLAUFZEIT,
           CAST(PSP_ZEIT_UEBERLAPPUNG_PROZENT AS FLOAT) AS PSP_ZEIT_UEBERLAPPUNG_PROZENT,
           CAST(PSP_PP_STATUS_ANZAHL_TAGE_PRODUKTION AS SMALLINT) AS PSP_PP_STATUS_ANZAHL_TAGE_PRODUKTION,
           CAST(CASE
                    WHEN ISDATE(PSP_PP_DATUM_START) = 1 THEN
                        CAST((CONVERT(varchar, PSP_PP_DATUM_START, 104)) as datetime)
                END AS datetime) AS PSP_PP_DATUM_START,
           CAST(PSP_PP_DATUM_START_STATUS AS SMALLINT) AS PSP_PP_DATUM_START_STATUS,
           CAST(tPPS_ARBSCHR.AS_NUMMER AS VARCHAR(50)) AS PSP_ARBEITSSCHRITT_NUMMER,
           CAST(PSP_BEZEICHNUNG AS VARCHAR(4000)) AS PSP_BEZEICHNUNG,
           CAST('' AS VARCHAR(4000)) AS PSP_INTERNTEXT,
           CAST(PSP_BEZEICHNUNG AS VARCHAR(4000)) AS PSP_BEZEICHNUNG_FORMEL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_MENGE_SOLL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_MENGE_SOLL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL,
           REPLACE(CONVERT(   VARCHAR,
                              CASE
                                  WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                      PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL
                                  ELSE
                                      ''
                              END,
                              128
                          ),
                   '.',
                   ','
                  ) AS PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL,
           REPLACE(CONVERT(   VARCHAR,
                              CASE
                                  WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                      PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL
                                  ELSE
                                      ''
                              END,
                              128
                          ),
                   '.',
                   ','
                  ) AS PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL,
           REPLACE(   CAST(CASE
                               WHEN PSP_TYP_ERFASSUNG_ZEIT = 0 THEN
                      (ROUND(   (CASE
                                     WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                         PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL
                                     ELSE
                                         ''
                                 END * CASE
                                           WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                               PSP_MENGE_SOLL
                                           ELSE
                                               ''
                                       END
                                ),
                                0
                            ) + CASE
                                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                        PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                                    ELSE
                                        ''
                                END
                      )
                               ELSE
                                   CASE
                                       WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN
                                           CASE
                                               WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                                   PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL
                                               ELSE
                                                   ''
                                           END + CASE
                                                     WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                                         PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                                                     ELSE
                                                         ''
                                                 END
                                   END
                           END AS VARCHAR(50)),
                      '.',
                      ','
                  ) AS PSP_ZEIT_MINUTEN_GESAMT_SOLL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_PREIS_HK_FK_EK_GP
                    ELSE
                        ''
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_PREIS_VK_IDEAL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_PREIS_VK_IDEAL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_PREIS_VK_MINIMAL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_PREIS_VK_MINIMAL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_PREIS_HK_MIN_SATZ_FK_EK_EP
                    ELSE
                        ''
                END AS MONEY) AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                    ELSE
                        ''
                END AS MONEY) AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_MENGE_SOLL
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS FLOAT) AS PSP_MENGE_SOLL_GK,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS FLOAT) AS PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL_GK,
           REPLACE(CONVERT(   VARCHAR,
                              CASE
                                  WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                                      CASE
                                          WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                              PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL
                                          ELSE
                                              ''
                                      END
                                  ELSE
                                      ''
                              END,
                              128
                          ),
                   '.',
                   ','
                  ) AS PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL_GK,
           REPLACE(CONVERT(   VARCHAR,
                              CASE
                                  WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                                      CASE
                                          WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                              PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL
                                          ELSE
                                              ''
                                      END
                                  ELSE
                                      ''
                              END,
                              128
                          ),
                   '.',
                   ','
                  ) AS PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL_GK,
           REPLACE(   CAST(CASE
                               WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                                   CASE
                                       WHEN PSP_TYP_ERFASSUNG_ZEIT = 0 THEN
                      (ROUND(   (CASE
                                     WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                         PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL
                                     ELSE
                                         0
                                 END * CASE
                                           WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                               PSP_MENGE_SOLL
                                           ELSE
                                               0
                                       END
                                ),
                                0
                            ) + CASE
                                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                        PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                                    ELSE
                                        0
                                END
                      )
                                       ELSE
                                           CASE
                                               WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN
                                                   CASE
                                                       WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                                           PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL
                                                       ELSE
                                                           0
                                                   END + CASE
                                                             WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                                                 PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                                                             ELSE
                                                                 0
                                                         END
                                           END
                                   END
                               ELSE
                                   ''
                           END AS VARCHAR(50)),
                      '.',
                      ','
                  ) AS PSP_ZEIT_MINUTEN_GESAMT_SOLL_GK,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_PREIS_HK_FK_EK_GP
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_GK,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_PREIS_VK_IDEAL
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS FLOAT) AS PSP_PREIS_VK_IDEAL_GK,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_PREIS_VK_MINIMAL
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS FLOAT) AS PSP_PREIS_VK_MINIMAL_GK,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_PREIS_HK_MIN_SATZ_FK_EK_EP
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS MONEY) AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_GK,
           CAST(CASE
                    WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 0 THEN
                        CASE
                            WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                                PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS MONEY) AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_GK,
           CAST(CASE
                    WHEN PSP_TYP_POSITION = 0 THEN
                        'Stück'
                    ELSE
                        ''
                END AS VARCHAR(10)) AS PSP_DIMENSION_BEZEICHNUNG,
           CAST(PSP_NEUER_FERTIGUNGSABSCHNITT AS SMALLINT) AS PSP_NEUER_FERTIGUNGSABSCHNITT,
           CAST(PSP_TYP_POSITION AS SMALLINT) AS D4IV_TYP_POSITION,
           CAST(0 AS SMALLINT) AS D4IV_TYP_HERKUNFT,
           CAST(PSP_IDAS AS INT) AS PSP_IDAS,
           CAST(0 AS SMALLINT) AS PSP_IDSKKK,
           CAST(PSP_TYP_SPERRE AS INT) AS D4IV_TYP_SPERRE,
           CAST(PSP_IDPSKKK AS INT) AS PSP_IDPSKKK,
           CAST(PSK_IDBEBK AS INT) AS PSKALK_IDBEBK,
           CAST(tPPS_SKKALP.ID AS INT) AS ID,
           CAST(PSK_IDBEBP AS INT) AS PSKALK_IDBEBP,
           CASE
               WHEN tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0 THEN
                   CAST(CASE
                            WHEN BP_STATUS_ZEITERFASSUNG = 2
                                 AND GETDATE() < CONVERT(DATETIME, BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM, 104) THEN
                                0
                            ELSE
                                BP_STATUS_ZEITERFASSUNG
                        END AS INT)
               ELSE
                   CAST(CASE
                            WHEN tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2
                                 AND GETDATE() < CONVERT(
                                                            DATETIME,
                                                            tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                            104
                                                        ) THEN
                                0
                            ELSE
                                tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG
                        END AS INT)
           END AS STATUS_ZEITERFASSUNG,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_HK_FK_EK_GP_IST
                        END
                    ELSE
                        PSP_PREIS_HK_FK_EK_GP_IST
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_IST,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST
                        END
                    ELSE
                        PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST
                        END
                    ELSE
                        PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST
                        END
                    ELSE
                        PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST
                        END
                    ELSE
                        PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST
                END AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_VK_MINIMAL_IST
                        END
                    ELSE
                        PSP_PREIS_VK_MINIMAL_IST
                END AS FLOAT) AS PSP_PREIS_VK_MINIMAL_IST,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) <> 0 THEN
                        CASE
                            WHEN ISNULL(tSTATUS_ZEIT_FK_SOLL_GEPLANT.ZEIT_SOLL_FK_GEPLANT, 0) = 1
                                 AND PSP_TYP_POSITION <> 0 THEN
                                0
                            ELSE
                                PSP_PREIS_VK_IDEAL_IST
                        END
                    ELSE
                        PSP_PREIS_VK_IDEAL_IST
                END AS FLOAT) AS PSP_PREIS_VK_IDEAL_IST,
           CAST(CASE
                    WHEN PSP_TYP_HERKUNFT_IST_WERTE = 1 THEN
                        PSP_MENGE_IST
                    ELSE
                        CASE
                            WHEN PSP_TYP_HERKUNFT_IST_WERTE = 0 THEN
                                ZE_BUCH_SUMME_MENGE_IST
                            ELSE
                                NULL
                        END
                END AS FLOAT) AS PSP_MENGE_IST_WERT,
           CAST(tPPS_SKKALP.IDTR AS VARCHAR(30)) AS IDTR,
           CAST(PSP_IDPSKKK_POS AS INT) AS PSP_IDPSKKK_POS,
           CAST(PSP_IDMS AS INT) AS PSP_IDMS,
           CAST(PSP_IDMP AS INT) AS PSP_IDMP,
           CAST(PSP_IDMR AS INT) AS PSP_IDMR,
           CAST(PSP_PP_ZEIT_MINUTEN_MAX_PROD_TAG AS FLOAT) AS PSP_PP_ZEIT_MINUTEN_MAX_PROD_TAG,
           CAST(PSP_TYP_HK_VK_PREIS_AKTUALISIERUNG AS SMALLINT) AS PSP_TYP_HK_VK_PREIS_AKTUALISIERUNG,
           CAST(PSP_TYP_ARBEITSSCHRITT_TEXT_AKTUALISIERUNG AS SMALLINT) AS PSP_TYP_ARBEITSSCHRITT_TEXT_AKTUALISIERUNG,
           CAST(PSP_TYP_EINSTELLUNG_BUCHUNG_AKTUALISIERUNG AS SMALLINT) AS PSP_TYP_EINSTELLUNG_BUCHUNG_AKTUALISIERUNG,
           CAST(PSP_TYP_LAYOUT_POSITION AS SMALLINT) AS PSP_TYP_LAYOUT_POSITION,
           CAST(PSP_ZEIT_TAGE_UEBERLAPPUNG AS FLOAT) AS PSP_ZEIT_TAGE_UEBERLAPPUNG,
           CAST(PSP_BUCHUNG_TYP_ZEIT AS SMALLINT) AS PSP_BUCHUNG_TYP_ZEIT,
           CAST(PSP_BUCHUNG_TYP_PRODUKTION AS SMALLINT) AS PSP_BUCHUNG_TYP_PRODUKTION,
           CAST(PSP_TYP_ERFASSUNG_ZEIT AS SMALLINT) AS PSP_TYP_ERFASSUNG_ZEIT,
           CAST(PSP_ZEIT_TAGE_PRODUKTION AS FLOAT) AS PSP_ZEIT_TAGE_PRODUKTION,
           CAST(PSP_MENGE_IST AS FLOAT) AS PSP_MENGE_IST,
           CAST(PSP_TYP_HERKUNFT_IST_WERTE AS SMALLINT) AS PSP_TYP_HERKUNFT_IST_WERTE,
           CAST(PSP_TYP_ERFASSUNG_IST_MENGE AS SMALLINT) AS PSP_TYP_ERFASSUNG_IST_MENGE,
           CAST(PSP_TYP_AKT_SOLL_MENGE AS SMALLINT) AS PSP_TYP_AKT_SOLL_MENGE,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_ZEIT_MINUTEN_PRODUKTION_AK_EINZEL_SOLL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_AK_EINZEL_SOLL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_ZEIT_MINUTEN_PRODUKTION_MS_EINZEL_SOLL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_MS_EINZEL_SOLL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL
                    ELSE
                        ''
                END AS FLOAT) AS PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL,
           CAST(CASE
                    WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                        PSP_PREIS_VK_MINIMAL_RUESTUNG
