                                            WHEN PSP_TYP_ERFASSUNG_ZEIT = 0 THEN
                         (ROUND(   (CASE
                                        WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                            PSP_ZEIT_MINUTEN_PRODUKTION_EINZEL_SOLL
                                        ELSE
                                            ''
                                    END * CASE
                                              WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                                  PSP_MENGE_SOLL
                                              ELSE
                                                  ''
                                          END
                                   ),
                                   0
                               ) + CASE
                                       WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                           PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                                       ELSE
                                           ''
                                   END
                         )
                                            ELSE
                                                CASE
                                                    WHEN PSP_TYP_ERFASSUNG_ZEIT = 1 THEN
                                                        CASE
                                                            WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                                                PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL
                                                            ELSE
                                                                ''
                                                        END + CASE
                                                                  WHEN ISNULL(PSK_IDBEBK, 0) = 0 THEN
                                                                      PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL
                                                                  ELSE
                                                                      ''
                                                              END
                                                END
                                        END
                          END
                         ) * 100,
                         0
                     ) AS INT) AS PSP_FORTSCHRITT_PROZENT,
           CAST(tPPS_ARBSCHR.AS_TYP_FARBE_ARBEITSSCHRITT AS INT) AS AS_TYP_FARBE_ARBEITSSCHRITT,
           CASE
               WHEN EXISTS
                    (
                        SELECT tZE_BUCH_BEWE.ID
                        FROM tZE_BUCH
                            INNER JOIN tZE_BUCH_BEWE
                                ON tZE_BUCH_BEWE.ZBUBW_IDZBU = tZE_BUCH.ID
                        WHERE tZE_BUCH.ZBU_IDPSKP = tPPS_SKKALP.ID
                              AND ISNULL(tZE_BUCH_BEWE.ZBUBW_DATUM_ZEIT_START, '') <> ''
                              AND ISNULL(tZE_BUCH_BEWE.ZBUBW_DATUM_ZEIT_STOP, '') = ''
                    ) THEN
                   1
               ELSE
                   0
           END AS PSP_AKTIV,
           CAST(PSP_PP_NLZ_PROZENT AS FLOAT) AS PSP_PP_NLZ_PROZENT,
           CAST(PSP_TYP_BERECHNUNG_STUECKKOSTEN AS INT) AS PSP_TYP_BERECHNUNG_STUECKKOSTEN,
           CAST(0 AS FLOAT) AS KP_GEWICHT_KG_NETTO,
           CAST(0 AS FLOAT) AS KP_GEWICHT_KG_BRUTTO,
           CAST(0 AS FLOAT) AS KP_GEWICHT_KG_NETTO_GES,
           CAST(0 AS FLOAT) AS KP_GEWICHT_KG_BRUTTO_GES
    FROM(((((((((((
    (
        SELECT tPPS_SKKALP.*,
               PSP_MENGE_IST_WERT_HK,
               PSP_PREIS_VK_IDEAL_IST,
               PSP_PREIS_VK_MINIMAL_IST,
               PSP_PREIS_HK_FK_EK_GP_IST,
               PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST,
               PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST,
               PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST,
               PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST,
               ZE_BUCH_SUMME_MENGE_AUSSCHUSS,
               ZE_BUCH_SUMME_MENGE_IST,
               ZE_BUCH_SUMME_ZEIT_RUESTUNG,
               ZE_BUCH_SUMME_ZEIT_PRODUKTION,
               ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
               ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS
        FROM tPPS_SKKALP
            LEFT JOIN
            (
                SELECT ID AS IDPSP_TEMP,
                       SUM(ISNULL(PSP_MENGE_IST_WERT_HK, 0)) AS PSP_MENGE_IST_WERT_HK,
                       SUM(ISNULL(PSP_PREIS_VK_IDEAL_IST, 0)) AS PSP_PREIS_VK_IDEAL_IST,
                       SUM(ISNULL(PSP_PREIS_VK_MINIMAL_IST, 0)) AS PSP_PREIS_VK_MINIMAL_IST,
                       SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_IST,
                       SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST,
                       SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST,
                       SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST,
                       SUM(ISNULL(PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST, 0)) AS PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST,
                       SUM(ISNULL(ZE_BUCH_SUMME_MENGE_AUSSCHUSS, 0)) AS ZE_BUCH_SUMME_MENGE_AUSSCHUSS,
                       SUM(ISNULL(ZE_BUCH_SUMME_MENGE_IST, 0)) AS ZE_BUCH_SUMME_MENGE_IST,
                       SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG, 0)) AS ZE_BUCH_SUMME_ZEIT_RUESTUNG,
                       SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION, 0)) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION,
                       SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK, 0)) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                       SUM(ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS, 0)) AS ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS
                FROM
                (
                    SELECT *,
                           CASE
                               WHEN PSP_TYP_HERKUNFT_IST_WERTE = 1 THEN
                                   PSP_MENGE_IST
                               ELSE
                                   CASE
                                       WHEN PSP_TYP_HERKUNFT_IST_WERTE = 0 THEN
                                           ZE_BUCH_SUMME_MENGE_IST
                                       ELSE
                                           NULL
                                   END
                           END AS PSP_MENGE_IST_WERT_HK
                    FROM
                    (
                        SELECT *,
                               'PSP_PREIS_VK_IDEAL_IST' = CASE
                                                              WHEN PSP_TYP_POSITION = 0 THEN
                                                                  CASE
                                                                      WHEN ISNULL(PSP_PREIS_VK_IDEAL, 0) > 0
                                                                           AND ISNULL(PSP_PREIS_HK_FK_EK_GP, 0) > 0 THEN
                                                                          CASE
                                                                              WHEN ISNULL(PSP_PREIS_HK_FK_EK_GP, 0) <> ISNULL(
                                                                                                                                 PSP_PREIS_VK_IDEAL,
                                                                                                                                 0
                                                                                                                             ) THEN
                                                                                  PSP_PREIS_HK_FK_EK_GP_IST
                                                                                  + ((PSP_PREIS_HK_FK_EK_GP_IST
                                                                                      * ((PSP_PREIS_VK_IDEAL
                                                                                          - PSP_PREIS_HK_FK_EK_GP
                                                                                         )
                                                                                         * 100 / PSP_PREIS_HK_FK_EK_GP
                                                                                        )
                                                                                     )
                                                                                     / 100
                                                                                    )
                                                                              ELSE
                                                                                  PSP_PREIS_HK_FK_EK_GP_IST
                                                                          END
                                                                      ELSE
                                                                          CASE
                                                                              WHEN PSK_TYP_KALK_PREIS_TYP = 0 THEN
                                                                                  ISNULL(PSP_PREIS_HK_FK_EK_GP_IST, 0)
                                                                              ELSE
                                                                                  CASE
                                                                                      WHEN PSP_TYP_POSITION = 0 THEN
                                                                                          CASE
                                                                                              WHEN ISNULL(
                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                             0
                                                                                                         ) <> 0 THEN
                                                                                                  PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG
                                                                                              ELSE
                                                                                                  CASE
                                                                                                      WHEN ISNULL(
                                                                                                                     PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                     0
                                                                                                                 ) = 0
                                                                                                           AND ISNULL(
                                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                         0
                                                                                                                     ) = 0
                                                                                                           AND ISNULL(
                                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                         0
                                                                                                                     ) = 0 THEN
                                                                                                          PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                                                                                      ELSE
                                                                                                          0
                                                                                                  END
                                                                                          END
                                                                                          * ISNULL(
                                                                                                      ZE_BUCH_SUMME_ZEIT_RUESTUNG,
                                                                                                      0
                                                                                                  )
                                                                                          + CASE
                                                                                                WHEN ISNULL(
                                                                                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                               0
                                                                                                           ) <> 0 THEN
                                                                                                    PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK
                                                                                                ELSE
                                                                                                    CASE
                                                                                                        WHEN ISNULL(
                                                                                                                       PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                       0
                                                                                                                   ) = 0
                                                                                                             AND ISNULL(
                                                                                                                           PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                           0
                                                                                                                       ) = 0
                                                                                                             AND ISNULL(
                                                                                                                           PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                           0
                                                                                                                       ) = 0 THEN
                                                                                                            PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                                                                                        ELSE
                                                                                                            0
                                                                                                    END
                                                                                            END
                                                                                          * ISNULL(
                                                                                                      ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                                                                                      0
                                                                                                  )
                                                                                          + CASE
                                                                                                WHEN ISNULL(
                                                                                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                               0
                                                                                                           ) <> 0 THEN
                                                                                                    PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS
                                                                                                ELSE
                                                                                                    CASE
                                                                                                        WHEN ISNULL(
                                                                                                                       PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                       0
                                                                                                                   ) = 0
                                                                                                             AND ISNULL(
                                                                                                                           PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                           0
                                                                                                                       ) = 0
                                                                                                             AND ISNULL(
                                                                                                                           PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                           0
                                                                                                                       ) = 0 THEN
                                                                                                            PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                                                                                        ELSE
                                                                                                            0
                                                                                                    END
                                                                                            END
                                                                                          * ISNULL(
                                                                                                      ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,
                                                                                                      0
                                                                                                  )
                                                                                      ELSE
                                                                                          ISNULL(
                                                                                                    PSP_PREIS_VK_MINIMAL,
                                                                                                    0
                                                                                                )
                                                                                  END
                                                                          END
                                                                  END
                                                              ELSE
                                                                  ISNULL(PSP_PREIS_VK_IDEAL, 0)
                                                          END,
                               'PSP_PREIS_VK_MINIMAL_IST' = CASE
                                                                WHEN PSK_TYP_KALK_PREIS_TYP = 0 THEN
                                                                    ISNULL(PSP_PREIS_HK_FK_EK_GP_IST, 0)
                                                                ELSE
                                                                    CASE
                                                                        WHEN PSP_TYP_POSITION = 0 THEN
                                                                            CASE
                                                                                WHEN ISNULL(
                                                                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                               0
                                                                                           ) <> 0 THEN
                                                                                    PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG
                                                                                ELSE
                                                                                    CASE
                                                                                        WHEN ISNULL(
                                                                                                       PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                       0
                                                                                                   ) = 0
                                                                                             AND ISNULL(
                                                                                                           PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                           0
                                                                                                       ) = 0
                                                                                             AND ISNULL(
                                                                                                           PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                           0
                                                                                                       ) = 0 THEN
                                                                                            PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                                                                        ELSE
                                                                                            0
                                                                                    END
                                                                            END
                                                                            * ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG, 0)
                                                                            + CASE
                                                                                  WHEN ISNULL(
                                                                                                 PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                 0
                                                                                             ) <> 0 THEN
                                                                                      PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK
                                                                                  ELSE
                                                                                      CASE
                                                                                          WHEN ISNULL(
                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                         0
                                                                                                     ) = 0
                                                                                               AND ISNULL(
                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                             0
                                                                                                         ) = 0
                                                                                               AND ISNULL(
                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                             0
                                                                                                         ) = 0 THEN
                                                                                              PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                                                                          ELSE
                                                                                              0
                                                                                      END
                                                                              END
                                                                            * ISNULL(
                                                                                        ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                                                                        0
                                                                                    )
                                                                            + CASE
                                                                                  WHEN ISNULL(
                                                                                                 PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                 0
                                                                                             ) <> 0 THEN
                                                                                      PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS
                                                                                  ELSE
                                                                                      CASE
                                                                                          WHEN ISNULL(
                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                         0
                                                                                                     ) = 0
                                                                                               AND ISNULL(
                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                             0
                                                                                                         ) = 0
                                                                                               AND ISNULL(
                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                             0
                                                                                                         ) = 0 THEN
                                                                                              PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                                                                          ELSE
                                                                                              0
                                                                                      END
                                                                              END
                                                                            * ISNULL(
                                                                                        ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,
                                                                                        0
                                                                                    )
                                                                        ELSE
                                                                            ISNULL(PSP_PREIS_VK_MINIMAL, 0)
                                                                    END
                                                            END
                        FROM
                        (
                            SELECT *,
                                   'PSP_PREIS_HK_FK_EK_GP_IST' = CASE
                                                                     WHEN PSP_TYP_POSITION = 0 THEN
                                                                         CASE
                                                                             WHEN (
                                                                                      PSK_TYP_KALK_PREIS_TYP = 0
                                                                                      AND ISNULL(
                                                                                                    PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                                                                                    0
                                                                                                ) <> 0
                                                                                  )
                                                                                  OR (
                                                                                         PSK_TYP_KALK_PREIS_TYP = 1
                                                                                         AND ISNULL(
                                                                                                       PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                       0
                                                                                                   ) <> 0
                                                                                     ) THEN
                                                                                 PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG
                                                                             ELSE
                                                                                 CASE
                                                                                     WHEN (
                                                                                              PSK_TYP_KALK_PREIS_TYP = 0
                                                                                              AND (
                                                                                                      ISNULL(
                                                                                                                PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                                                                                                0
                                                                                                            ) = 0
                                                                                                      AND ISNULL(
                                                                                                                    PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                    0
                                                                                                                ) = 0
                                                                                                      AND ISNULL(
                                                                                                                    PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                    0
                                                                                                                ) = 0
                                                                                                  )
                                                                                          )
                                                                                          OR (
                                                                                                 PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                 AND (
                                                                                                         ISNULL(
                                                                                                                   PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                   0
                                                                                                               ) = 0
                                                                                                         AND ISNULL(
                                                                                                                       PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                       0
                                                                                                                   ) = 0
                                                                                                         AND ISNULL(
                                                                                                                       PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                       0
                                                                                                                   ) = 0
                                                                                                     )
                                                                                             ) THEN
                                                                                         PSP_PREIS_HK_MIN_SATZ_FK_EK_EP
                                                                                     ELSE
                                                                                         0
                                                                                 END
                                                                         END * ISNULL(ZE_BUCH_SUMME_ZEIT_RUESTUNG, 0)
                                                                         + CASE
                                                                               WHEN (
                                                                                        PSK_TYP_KALK_PREIS_TYP = 0
                                                                                        AND ISNULL(
                                                                                                      PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                      0
                                                                                                  ) <> 0
                                                                                    )
                                                                                    OR (
                                                                                           PSK_TYP_KALK_PREIS_TYP = 1
                                                                                           AND ISNULL(
                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                         0
                                                                                                     ) <> 0
                                                                                       ) THEN
                                                                                   PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                                                               ELSE
                                                                                   CASE
                                                                                       WHEN (
                                                                                                PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                AND (
                                                                                                        ISNULL(
                                                                                                                  PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                                                                                                  0
                                                                                                              ) = 0
                                                                                                        AND ISNULL(
                                                                                                                      PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                      0
                                                                                                                  ) = 0
                                                                                                        AND ISNULL(
                                                                                                                      PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                      0
                                                                                                                  ) = 0
                                                                                                    )
                                                                                            )
                                                                                            OR (
                                                                                                   PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                   AND (
                                                                                                           ISNULL(
                                                                                                                     PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                     0
                                                                                                                 ) = 0
                                                                                                           AND ISNULL(
                                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                         0
                                                                                                                     ) = 0
                                                                                                           AND ISNULL(
                                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                         0
                                                                                                                     ) = 0
                                                                                                       )
                                                                                               ) THEN
                                                                                           PSP_PREIS_HK_MIN_SATZ_FK_EK_EP
                                                                                       ELSE
                                                                                           0
                                                                                   END
                                                                           END
                                                                         * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK, 0)
                                                                         + CASE
                                                                               WHEN (
                                                                                        PSK_TYP_KALK_PREIS_TYP = 0
                                                                                        AND ISNULL(
                                                                                                      PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                      0
                                                                                                  ) <> 0
                                                                                    )
                                                                                    OR (
                                                                                           PSK_TYP_KALK_PREIS_TYP = 1
                                                                                           AND ISNULL(
                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                         0
                                                                                                     ) <> 0
                                                                                       ) THEN
                                                                                   PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                                                               ELSE
                                                                                   CASE
                                                                                       WHEN (
                                                                                                PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                AND (
                                                                                                        ISNULL(
                                                                                                                  PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                                                                                                  0
                                                                                                              ) = 0
                                                                                                        AND ISNULL(
                                                                                                                      PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                      0
                                                                                                                  ) = 0
                                                                                                        AND ISNULL(
                                                                                                                      PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                      0
                                                                                                                  ) = 0
                                                                                                    )
                                                                                            )
                                                                                            OR (
                                                                                                   PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                   AND (
                                                                                                           ISNULL(
                                                                                                                     PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                     0
                                                                                                                 ) = 0
                                                                                                           AND ISNULL(
                                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                         0
                                                                                                                     ) = 0
                                                                                                           AND ISNULL(
                                                                                                                         PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                         0
                                                                                                                     ) = 0
                                                                                                       )
                                                                                               ) THEN
                                                                                           PSP_PREIS_HK_MIN_SATZ_FK_EK_EP
                                                                                       ELSE
                                                                                           0
                                                                                   END
                                                                           END
                                                                         * ISNULL(ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS, 0)
                                                                     ELSE
                                                                         ISNULL(PSP_PREIS_HK_FK_EK_GP, 0)
                                                                 END,
                                   'PSP_PREIS_HK_FK_EK_GP_PRODUKTION_IST' = CASE
                                                                                WHEN PSP_TYP_POSITION = 0 THEN
                                                                                    CASE
                                                                                        WHEN (
                                                                                                 PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                 AND ISNULL(
                                                                                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                               0
                                                                                                           ) <> 0
                                                                                             )
                                                                                             OR (
                                                                                                    PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                    AND ISNULL(
                                                                                                                  PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                  0
                                                                                                              ) <> 0
                                                                                                ) THEN
                                                                                            PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                                                                        ELSE
                                                                                            CASE
                                                                                                WHEN (
                                                                                                         PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                         AND (
                                                                                                                 ISNULL(
                                                                                                                           PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                           0
                                                                                                                       ) = 0
                                                                                                                 AND ISNULL(
                                                                                                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                               0
                                                                                                                           ) = 0
                                                                                                             )
                                                                                                     )
                                                                                                     OR (
                                                                                                            PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                            AND (
                                                                                                                    ISNULL(
                                                                                                                              PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                              0
                                                                                                                          ) = 0
                                                                                                                    AND ISNULL(
                                                                                                                                  PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                                  0
                                                                                                                              ) = 0
                                                                                                                )
                                                                                                        ) THEN
                                   (PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                    + PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                   )
                                                                                                ELSE
                                                                                                    0
                                                                                            END
                                                                                    END
                                                                                    * ISNULL(
                                                                                                ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                                                                                0
                                                                                            )
                                                                                    + CASE
                                                                                          WHEN (
                                                                                                   PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                   AND ISNULL(
                                                                                                                 PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                 0
                                                                                                             ) <> 0
                                                                                               )
                                                                                               OR (
                                                                                                      PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                      AND ISNULL(
                                                                                                                    PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                    0
                                                                                                                ) <> 0
                                                                                                  ) THEN
                                                                                              PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                                                                          ELSE
                                                                                              CASE
                                                                                                  WHEN (
                                                                                                           PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                           AND (
                                                                                                                   ISNULL(
                                                                                                                             PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                             0
                                                                                                                         ) = 0
                                                                                                                   AND ISNULL(
                                                                                                                                 PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                                 0
                                                                                                                             ) = 0
                                                                                                               )
                                                                                                       )
                                                                                                       OR (
                                                                                                              PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                              AND (
                                                                                                                      ISNULL(
                                                                                                                                PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                                0
                                                                                                                            ) = 0
                                                                                                                      AND ISNULL(
                                                                                                                                    PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                                    0
                                                                                                                                ) = 0
                                                                                                                  )
                                                                                                          ) THEN
                                   (PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                    + PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                   )
                                                                                                  ELSE
                                                                                                      0
                                                                                              END
                                                                                      END
                                                                                    * ISNULL(
                                                                                                ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,
                                                                                                0
                                                                                            )
                                                                                ELSE
                                                                                    ISNULL(
                                                                                              PSP_PREIS_HK_FK_EK_GP_PRODUKTION,
                                                                                              0
                                                                                          )
                                                                            END,
                                   'PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK_IST' = CASE
                                                                                   WHEN PSP_TYP_POSITION = 0 THEN
                                                                                       CASE
                                                                                           WHEN (
                                                                                                    PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                    AND ISNULL(
                                                                                                                  PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                  0
                                                                                                              ) <> 0
                                                                                                )
                                                                                                OR (
                                                                                                       PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                       AND ISNULL(
                                                                                                                     PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                     0
                                                                                                                 ) <> 0
                                                                                                   ) THEN
                                                                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                                                                           ELSE
                                                                                               CASE
                                                                                                   WHEN (
                                                                                                            PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                            AND ISNULL(
                                                                                                                          PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                                                                                                          0
                                                                                                                      ) = 0
                                                                                                        )
                                                                                                        OR (
                                                                                                               PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                               AND ISNULL(
                                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                                                                                                             0
                                                                                                                         ) = 0
                                                                                                           ) THEN
                                                                                                       PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                                                                                   ELSE
                                                                                                       0
                                                                                               END
                                                                                       END
                                                                                       * ISNULL(
                                                                                                   ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                                                                                   0
                                                                                               )
                                                                                   ELSE
                                                                                       ISNULL(
                                                                                                 PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK,
                                                                                                 0
                                                                                             )
                                                                               END,
                                   'PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS_IST' = CASE
                                                                                   WHEN PSP_TYP_POSITION = 0 THEN
                                                                                       CASE
                                                                                           WHEN (
                                                                                                    PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                    AND ISNULL(
                                                                                                                  PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                  0
                                                                                                              ) <> 0
                                                                                                )
                                                                                                OR (
                                                                                                       PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                       AND ISNULL(
                                                                                                                     PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                     0
                                                                                                                 ) <> 0
                                                                                                   ) THEN
                                                                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                                                                           ELSE
                                                                                               CASE
                                                                                                   WHEN (
                                                                                                            PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                            AND ISNULL(
                                                                                                                          PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                                                                                                          0
                                                                                                                      ) = 0
                                                                                                        )
                                                                                                        OR (
                                                                                                               PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                               AND ISNULL(
                                                                                                                             PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                                                                                                             0
                                                                                                                         ) = 0
                                                                                                           ) THEN
                                                                                                       PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                                                                                   ELSE
                                                                                                       0
                                                                                               END
                                                                                       END
                                                                                       * ISNULL(
                                                                                                   ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,
                                                                                                   0
                                                                                               )
                                                                                   ELSE
                                                                                       ISNULL(
                                                                                                 PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS,
                                                                                                 0
                                                                                             )
                                                                               END,
                                   'PSP_PREIS_HK_FK_EK_GP_RUESTUNG_IST' = CASE
                                                                              WHEN PSP_TYP_POSITION = 0 THEN
                                                                                  CASE
                                                                                      WHEN (
                                                                                               PSK_TYP_KALK_PREIS_TYP = 0
                                                                                               AND ISNULL(
                                                                                                             PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                                                                                             0
                                                                                                         ) <> 0
                                                                                           )
                                                                                           OR (
                                                                                                  PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                  AND ISNULL(
                                                                                                                PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                0
                                                                                                            ) <> 0
                                                                                              ) THEN
                                                                                          PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG
                                                                                      ELSE
                                                                                          CASE
                                                                                              WHEN (
                                                                                                       PSK_TYP_KALK_PREIS_TYP = 0
                                                                                                       AND ISNULL(
                                                                                                                     PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                                                                                                     0
                                                                                                                 ) = 0
                                                                                                   )
                                                                                                   OR (
                                                                                                          PSK_TYP_KALK_PREIS_TYP = 1
                                                                                                          AND ISNULL(
                                                                                                                        PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                                                                                                        0
                                                                                                                    ) = 0
                                                                                                      ) THEN
                                                                                                  PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG
                                                                                              ELSE
                                                                                                  0
                                                                                          END
                                                                                  END
                                                                                  * ISNULL(
                                                                                              ZE_BUCH_SUMME_ZEIT_RUESTUNG,
                                                                                              0
                                                                                          )
                                                                              ELSE
                                                                                  ISNULL(
                                                                                            PSP_PREIS_HK_FK_EK_GP_RUESTUNG,
                                                                                            0
                                                                                        )
                                                                          END
                            FROM
                            (
                                SELECT tPPS_SKKALP.ID,
                                       PSP_IDPSKKK,
                                       PSP_TYP_POSITION,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_KOSTEN_R
                                           ELSE
                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG
                                       END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_RUESTUNG,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_PREIS_R
                                           ELSE
                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG
                                       END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_RUESTUNG,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_KOSTEN_PA
                                           ELSE
                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK
                                       END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_AK,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_PREIS_PA
                                           ELSE
                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK
                                       END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_AK,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_KOSTEN_PM
                                           ELSE
                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS
                                       END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP_PRODUKTION_MS,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_PREIS_PM
                                           ELSE
                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS
                                       END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP_PRODUKTION_MS,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_KOSTEN
                                           ELSE
                                               PSP_PREIS_HK_MIN_SATZ_FK_EK_EP
                                       END AS PSP_PREIS_HK_MIN_SATZ_FK_EK_EP,
                                       CASE
                                           WHEN ISNULL(ZBU_IDMS, 0) <> 0
                                                AND ISNULL(ZBU_IDMS, 0) <> ISNULL(tPPS_SKKALP.PSP_IDMS, 0)
                                                AND ISNULL(tPPS_MASTA.MS_TYP_KOSTENSAETZE, 0) = 1 THEN
                                               MS_PREIS
                                           ELSE
                                               PSP_PREIS_VK_MIN_SATZ_FK_VK_EP
                                       END AS PSP_PREIS_VK_MIN_SATZ_FK_VK_EP,
                                       PSP_PREIS_HK_FK_EK_GP,
                                       PSP_PREIS_HK_FK_EK_GP_PRODUKTION,
                                       PSP_PREIS_HK_FK_EK_GP_PRODUKTION_AK,
                                       PSP_PREIS_HK_FK_EK_GP_PRODUKTION_MS,
                                       PSP_PREIS_HK_FK_EK_GP_RUESTUNG,
                                       PSP_PREIS_VK_IDEAL,
                                       PSP_PREIS_VK_MINIMAL,
                                       PSP_TYP_HERKUNFT_IST_WERTE,
                                       PSP_MENGE_IST,
                                       PSK_TYP_KALK_PREIS_TYP,
                                       ZE_BUCH_SUMME_MENGE_AUSSCHUSS,
                                       ZE_BUCH_SUMME_MENGE_IST,
                                       ZE_BUCH_SUMME_ZEIT_RUESTUNG,
                                       ZE_BUCH_SUMME_ZEIT_PRODUKTION,
                                       ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                       ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS
                                FROM(tPPS_SKKALP
                                    LEFT JOIN
                                    (
                                        SELECT PSK_TYP_KALK_PREIS AS PSK_TYP_KALK_PREIS_TYP,
                                               ID AS PSK_TYP_KALK_PREIS_ID
                                        FROM tPPS_SKKALK
                                    ) AS tPPS_SKKALK_TYP_KALK_PREIS
                                        ON tPPS_SKKALK_TYP_KALK_PREIS.PSK_TYP_KALK_PREIS_ID = tPPS_SKKALP.PSP_IDPSKKK)
                                    left join
                                    (
                                        select tZE_BUCH.ZBU_IDPSKP,
                                               tZE_BUCH.ZBU_IDMS,
                                               ZBU_MENGE_AUSSCHUSS AS ZE_BUCH_SUMME_MENGE_AUSSCHUSS,
                                               ZBU_MENGE_IST AS ZE_BUCH_SUMME_MENGE_IST,
                                               case
                                                   when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 0 then
                                                       isnull(ZBUBW_ZEIT, 0)
                                                   else
                                                       0
                                               end as ZE_BUCH_SUMME_ZEIT_RUESTUNG,
                                               case
                                                   when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then
                                                       isnull(ZBUBW_ZEIT, 0)
                                                   else
                                                       0
                                               end as ZE_BUCH_SUMME_ZEIT_PRODUKTION,
                                               case
                                                   when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then
                                                       case
                                                           when tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION = 0 then
                                                               isnull(ZBUBW_ZEIT, 0)
                                                           else
                                                               0
                                                       end
                                                   else
                                                       0
                                               end as ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                               case
                                                   when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then
                                                       case
                                                           when tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION = 1 then
                                                               isnull(ZBUBW_ZEIT, 0)
                                                           else
                                                               0
                                                       end
                                                   else
                                                       0
                                               end as ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS
                                        from tZE_BUCH
                                            left join tPPS_SKKALP
                                                on tPPS_SKKALP.ID = tZE_BUCH.ZBU_IDPSKP
                                            left join
                                            (
                                                select case
                                                           when isnull(ZBUBW_DATUM_ZEIT_START, 0) <> 0
                                                                and isnull(ZBUBW_DATUM_ZEIT_STOP, 0) <> 0 then
                                                               ROUND(
                                                                        CAST(datediff(
                                                                                         ss,
                                                                                         ZBUBW_DATUM_ZEIT_START,
                                                                                         ZBUBW_DATUM_ZEIT_STOP
                                                                                     ) AS FLOAT) / 60,
                                                                        4
                                                                    )
                                                           else
                                                               case
                                                                   when isnull(ZBUBW_DATUM_ZEIT_START, 0) <> 0
                                                                        and isnull(ZBUBW_DATUM_ZEIT_STOP, 0) = 0 then
                                                                       ROUND(
                                                                                CAST(datediff(
                                                                                                 ss,
                                                                                                 ZBUBW_DATUM_ZEIT_START,
                                                                                                 getdate()
                                                                                             ) AS FLOAT) / 60,
                                                                                4
                                                                            )
                                                                   else
                                                                       0
                                                               end
                                                       end as ZBUBW_ZEIT,
                                                       tZE_BUCH_BEWE.ZBUBW_IDZBU,
                                                       tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT,
                                                       tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION,
                                                       tZE_BUCH_BEWE.ZBUBW_DATUM_ZEIT_STOP
                                                from tZE_BUCH_BEWE
                                            ) as tZE_BUCH_BEWE
                                                on tZE_BUCH_BEWE.ZBUBW_IDZBU = tZE_BUCH.ID
                                    ) AS tZE_BUCH
                                        ON tZE_BUCH.ZBU_IDPSKP = tPPS_SKKALP.ID
                                    LEFT JOIN tPPS_MASTA
                                        ON tPPS_MASTA.ID = tZE_BUCH.ZBU_IDMS
                            ) AS MATRIX3
                        ) AS MATRIX2
                    ) AS MATRIX3
                ) AS TEMP
                GROUP BY ID
            ) AS tPPS_SKKALP_TEMP
                ON tPPS_SKKALP_TEMP.IDPSP_TEMP = tPPS_SKKALP.ID
    ) AS tPPS_SKKALP
        LEFT JOIN tPPS_ARBSCHR
            ON tPPS_ARBSCHR.ID = tPPS_SKKALP.PSP_IDAS)
        LEFT JOIN tPPS_SKKALK
            ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK)
        LEFT JOIN tPPS_SKKALV
            ON tPPS_SKKALV.ID = tPPS_SKKALK.PSK_IDPSKKV)
        LEFT JOIN tBE_BELP
            ON tBE_BELP.ID = tPPS_SKKALK.PSK_IDBEBP)
        LEFT JOIN tBE_BELP_MESU
            ON tBE_BELP_MESU.BP_MESU_IDBEBP = tBE_BELP.ID)
        LEFT JOIN
        (
            SELECT BK_BKBE_IDBEBK,
                   BK_BKBE_STATUS_ZEITERFASSUNG,
                   BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM
            FROM tBE_BELK_BKBE
        ) AS tBE_BELK_BKBE_OFFEN
            ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
               OR tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tPPS_SKKALK.PSK_IDBEBK)
        LEFT JOIN
        (
            SELECT tPPS_SKKALP.ID,
                   'PSP_ZEIT_SOLL_RUESTUNG' = SUM(PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL),
                   'PSP_ZEIT_SOLL_PRODUKTION' = SUM(PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL),
                   'PSP_ZEIT_SOLL_PRODUKTION_AK' = SUM(PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL),
                   'PSP_ZEIT_SOLL_PRODUKTION_MS' = SUM(PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL),
                   'PSP_ZEIT_SOLL_OFFEN' = SUM(   CASE
                                                      WHEN (
                                                               tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0
                                                               OR (
                                                                      tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2
                                                                      AND GETDATE() < CONVERT(
                                                                                                 DATETIME,
                                                                                                 BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                 104
                                                                                             )
                                                                  )
                                                           )
                                                           AND (
                                                                   tBE_BELP.BP_STATUS_ZEITERFASSUNG = 0
                                                                   OR (
                                                                          BP_STATUS_ZEITERFASSUNG = 2
                                                                          AND GETDATE() < CONVERT(
                                                                                                     DATETIME,
                                                                                                     BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                     104
                                                                                                 )
                                                                      )
                                                               ) THEN
                                                          ISNULL(PSP_ZEIT_SOLL_OFFEN, 0)
                                                      ELSE
                                                          0
                                                  END
                                              ),
                   'PSP_ZEIT_RUESTUNG_SOLL_OFFEN' = SUM(   CASE
                                                               WHEN (
                                                                        tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0
                                                                        OR (
                                                                               tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2
                                                                               AND GETDATE() < CONVERT(
                                                                                                          DATETIME,
                                                                                                          BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                          104
                                                                                                      )
                                                                           )
                                                                    )
                                                                    AND (
                                                                            tBE_BELP.BP_STATUS_ZEITERFASSUNG = 0
                                                                            OR (
                                                                                   BP_STATUS_ZEITERFASSUNG = 2
                                                                                   AND GETDATE() < CONVERT(
                                                                                                              DATETIME,
                                                                                                              BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                              104
                                                                                                          )
                                                                               )
                                                                        ) THEN
                                                                   ISNULL(PSP_ZEIT_RUESTUNG_SOLL_OFFEN, 0)
                                                               ELSE
                                                                   0
                                                           END
                                                       ),
                   'PSP_ZEIT_PRODUKTION_SOLL_OFFEN' = SUM(   CASE
                                                                 WHEN (
                                                                          tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0
                                                                          OR (
                                                                                 tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2
                                                                                 AND GETDATE() < CONVERT(
                                                                                                            DATETIME,
                                                                                                            BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                            104
                                                                                                        )
                                                                             )
                                                                      )
                                                                      AND (
                                                                              tBE_BELP.BP_STATUS_ZEITERFASSUNG = 0
                                                                              OR (
                                                                                     BP_STATUS_ZEITERFASSUNG = 2
                                                                                     AND GETDATE() < CONVERT(
                                                                                                                DATETIME,
                                                                                                                BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                                104
                                                                                                            )
                                                                                 )
                                                                          ) THEN
                                                                     ISNULL(PSP_ZEIT_PRODUKTION_SOLL_OFFEN, 0)
                                                                 ELSE
                                                                     0
                                                             END
                                                         ),
                   'PSP_ZEIT_PRODUKTION_AK_SOLL_OFFEN' = SUM(   CASE
                                                                    WHEN (
                                                                             tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0
                                                                             OR (
                                                                                    tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2
                                                                                    AND GETDATE() < CONVERT(
                                                                                                               DATETIME,
                                                                                                               BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                               104
                                                                                                           )
                                                                                )
                                                                         )
                                                                         AND (
                                                                                 tBE_BELP.BP_STATUS_ZEITERFASSUNG = 0
                                                                                 OR (
                                                                                        BP_STATUS_ZEITERFASSUNG = 2
                                                                                        AND GETDATE() < CONVERT(
                                                                                                                   DATETIME,
                                                                                                                   BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                                   104
                                                                                                               )
                                                                                    )
                                                                             ) THEN
                                                                        ISNULL(PSP_ZEIT_PRODUKTION_AK_SOLL_OFFEN, 0)
                                                                    ELSE
                                                                        0
                                                                END
                                                            ),
                   'PSP_ZEIT_PRODUKTION_MS_SOLL_OFFEN' = SUM(   CASE
                                                                    WHEN (
                                                                             tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 0
                                                                             OR (
                                                                                    tBE_BELK_BKBE_OFFEN.BK_BKBE_STATUS_ZEITERFASSUNG = 2
                                                                                    AND GETDATE() < CONVERT(
                                                                                                               DATETIME,
                                                                                                               BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                               104
                                                                                                           )
                                                                                )
                                                                         )
                                                                         AND (
                                                                                 tBE_BELP.BP_STATUS_ZEITERFASSUNG = 0
                                                                                 OR (
                                                                                        BP_STATUS_ZEITERFASSUNG = 2
                                                                                        AND GETDATE() < CONVERT(
                                                                                                                   DATETIME,
                                                                                                                   BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM,
                                                                                                                   104
                                                                                                               )
                                                                                    )
                                                                             ) THEN
                                                                        ISNULL(PSP_ZEIT_PRODUKTION_MS_SOLL_OFFEN, 0)
                                                                    ELSE
                                                                        0
                                                                END
                                                            )
            FROM tPPS_SKKALP
                left join
                (
                    select tPPS_SKKALP.ID,
                           'PSP_ZEIT_SOLL_OFFEN' = case
                                                       when sum(isnull(PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL, 0))
                                                            + sum(isnull(PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL, 0)) > sum(isnull(
                                                                                                                                      ZBUBW_ZEIT_GESAMT,
                                                                                                                                      0
                                                                                                                                  )
                                                                                                                           ) then
                                                           sum(isnull(PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL, 0))
                                                           + sum(isnull(PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL, 0))
                                                           - sum(isnull(ZBUBW_ZEIT_GESAMT, 0))
                                                       else
                                                           0
                                                   end,
                           'PSP_ZEIT_RUESTUNG_SOLL_OFFEN' = case
                                                                when sum(isnull(
                                                                                   PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL,
                                                                                   0
                                                                               )
                                                                        ) > sum(isnull(
                                                                                          ZBUBW_ZEIT_RUESTUNG_GESAMT,
                                                                                          0
                                                                                      )
                                                                               ) then
                                                                    sum(isnull(PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL, 0))
                                                                    - sum(isnull(ZBUBW_ZEIT_RUESTUNG_GESAMT, 0))
                                                                else
                                                                    0
                                                            end,
                           'PSP_ZEIT_PRODUKTION_SOLL_OFFEN' = case
                                                                  when sum(isnull(
                                                                                     PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL,
                                                                                     0
                                                                                 )
                                                                          ) > sum(isnull(
                                                                                            ZBUBW_ZEIT_PRODUKTION_GESAMT,
                                                                                            0
                                                                                        )
                                                                                 ) then
                                                                      sum(isnull(
                                                                                    PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL,
                                                                                    0
                                                                                )
                                                                         )
                                                                      - sum(isnull(ZBUBW_ZEIT_PRODUKTION_GESAMT, 0))
                                                                  else
                                                                      0
                                                              end,
                           'PSP_ZEIT_PRODUKTION_AK_SOLL_OFFEN' = case
                                                                     when sum(isnull(
                                                                                        PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL,
                                                                                        0
                                                                                    )
                                                                             ) > sum(isnull(
                                                                                               ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                                                                               0
                                                                                           )
                                                                                    ) then
                                                                         sum(isnull(
                                                                                       PSP_ZEIT_MINUTEN_PRODUKTION_AK_GESAMT_SOLL,
                                                                                       0
                                                                                   )
                                                                            )
                                                                         - sum(isnull(
                                                                                         ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                                                                         0
                                                                                     )
                                                                              )
                                                                     else
                                                                         0
                                                                 end,
                           'PSP_ZEIT_PRODUKTION_MS_SOLL_OFFEN' = case
                                                                     when sum(isnull(
                                                                                        PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL,
                                                                                        0
                                                                                    )
                                                                             ) > sum(isnull(
                                                                                               ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,
                                                                                               0
                                                                                           )
                                                                                    ) then
                                                                         sum(isnull(
                                                                                       PSP_ZEIT_MINUTEN_PRODUKTION_MS_GESAMT_SOLL,
                                                                                       0
                                                                                   )
                                                                            )
                                                                         - sum(isnull(
                                                                                         ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS,
                                                                                         0
                                                                                     )
                                                                              )
                                                                     else
                                                                         0
                                                                 end
                    from tPPS_SKKALP
                        left join
                        (
                            select ZBU_IDPSKP,
                                   sum(isnull(ZBUBW_ZEIT_GESAMT, 0)) as ZBUBW_ZEIT_GESAMT,
                                   sum(   case
                                              when ZBUBW_TYP_ZEIT = 0 then
                                                  isnull(ZBUBW_ZEIT_GESAMT, 0)
                                              else
                                                  0
                                          end
                                      ) as ZBUBW_ZEIT_RUESTUNG_GESAMT,
                                   sum(   case
                                              when ZBUBW_TYP_ZEIT = 1 then
                                                  isnull(ZBUBW_ZEIT_GESAMT, 0)
                                              else
                                                  0
                                          end
                                      ) as ZBUBW_ZEIT_PRODUKTION_GESAMT,
                                   sum(   case
                                              when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then
                                                  case
                                                      when tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION = 0 then
                                                          isnull(ZBUBW_ZEIT_GESAMT, 0)
                                                      else
                                                          0
                                                  end
                                              else
                                                  0
                                          end
                                      ) as ZE_BUCH_SUMME_ZEIT_PRODUKTION_AK,
                                   sum(   case
                                              when tZE_BUCH_BEWE.ZBUBW_TYP_ZEIT = 1 then
                                                  case
                                                      when tZE_BUCH_BEWE.ZBUBW_TYP_PRODUKTION = 1 then
                                                          isnull(ZBUBW_ZEIT_GESAMT, 0)
                                                      else
                                                          0
                                                  end
                                              else
                                                  0
                                          end
                                      ) as ZE_BUCH_SUMME_ZEIT_PRODUKTION_MS
                            from tZE_BUCH
                                left join
                                (
                                    select ZBUBW_IDZBU,
                                           ZBUBW_TYP_ZEIT,
                                           ZBUBW_TYP_PRODUKTION,
                                           case
                                               when isnull(ZBUBW_DATUM_ZEIT_START, 0) <> 0
                                                    and isnull(ZBUBW_DATUM_ZEIT_STOP, 0) <> 0 then
                                                   ROUND(
                                                            CAST(datediff(
                                                                             ss,
                                                                             ZBUBW_DATUM_ZEIT_START,
                                                                             ZBUBW_DATUM_ZEIT_STOP
                                                                         ) AS FLOAT) / 60,
                                                            4
                                                        )
                                               else
                                                   0
                                           end as ZBUBW_ZEIT_GESAMT
                                    from tZE_BUCH_BEWE
                                ) as tZE_BUCH_BEWE
                                    on tZE_BUCH_BEWE.ZBUBW_IDZBU = tZE_BUCH.ID
                            group by tZE_BUCH.ZBU_IDPSKP
                        ) as tZE_BUCH_OFFEN
                            on tZE_BUCH_OFFEN.ZBU_IDPSKP = tPPS_SKKALP.ID
                    where PSP_TYP_POSITION = 0
                          and PSP_PP_STATUS_PRODUKTION = 0
                    group by tPPS_SKKALP.ID
                ) as tPPS_SKKALP_OFFEN
                    on tPPS_SKKALP_OFFEN.ID = tPPS_SKKALP.ID
                LEFT JOIN
                (
                    SELECT ID AS IDPSKKK,
                           PSK_IDBEBP,
                           PSK_IDBEBK
                    FROM tPPS_SKKALK
                ) AS tPPS_SKKALK
                    ON tPPS_SKKALK.IDPSKKK = tPPS_SKKALP.PSP_IDPSKKK
                LEFT JOIN
                (
                    SELECT ID AS IDBEBP,
                           BP_IDBEBK,
                           BP_STATUS_ZEITERFASSUNG,
                           BP_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM
                    FROM tBE_BELP
                ) AS tBE_BELP
                    ON tBE_BELP.IDBEBP = tPPS_SKKALK.PSK_IDBEBP
                LEFT JOIN
                (
                    SELECT BK_BKBE_IDBEBK,
                           BK_BKBE_STATUS_ZEITERFASSUNG,
                           BK_BKBE_STATUS_ZEITERFASSUNG_ERLEDIGT_DATUM
                    FROM tBE_BELK_BKBE
                ) AS tBE_BELK_BKBE_OFFEN
                    ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                       OR tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tPPS_SKKALK.PSK_IDBEBK
            WHERE PSP_TYP_POSITION = 0
            GROUP BY tPPS_SKKALP.ID
        ) AS tPPS_SKKALP_2
            ON tPPS_SKKALP_2.ID = tPPS_SKKALP.ID)
        LEFT JOIN
        (
            SELECT PSP_IDAS AS STATUS_FK_ZEIT_SOLL_IDAS,
                   CASE
                       WHEN ISNULL(ZEIT_SOLL_GESAMT_SUM, 0) > 0
                            OR ISNULL(HK_GP_SOLL_GESAMT_SUM, 0) > 0 THEN
                           1
                       ELSE
                           0
                   END AS ZEIT_SOLL_FK_GEPLANT
            FROM
            (
                SELECT PSP_IDAS,
                       SUM(ZEIT_SOLL_GESAMT) AS ZEIT_SOLL_GESAMT_SUM,
                       SUM(HK_GP_SOLL_GESAMT) AS HK_GP_SOLL_GESAMT_SUM
                FROM
                (
                    SELECT PSP_IDAS,
                           ISNULL(PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL, 0)
                           + ISNULL(PSP_ZEIT_MINUTEN_PRODUKTION_GESAMT_SOLL, 0) AS ZEIT_SOLL_GESAMT,
                           ISNULL(PSP_PREIS_HK_FK_EK_GP, 0) AS HK_GP_SOLL_GESAMT
                    FROM tPPS_SKKALP
                        LEFT JOIN tPPS_SKKALK
                            ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK
                    WHERE ISNULL(tPPS_SKKALK.PSK_IDBEBK, 0) = 0
                          AND tPPS_SKKALP.PSP_IDPSKKK = 0
                ) AS tSUM
                GROUP BY PSP_IDAS
            ) AS tSTATUS_ZEIT_FK_SOLL_GEPLANT_TEMP
        ) AS tSTATUS_ZEIT_FK_SOLL_GEPLANT
            ON tSTATUS_ZEIT_FK_SOLL_GEPLANT.STATUS_FK_ZEIT_SOLL_IDAS = tPPS_SKKALP.PSP_IDAS
        LEFT JOIN
        (
            SELECT CASE
                       WHEN COUNT_NOT_OK > 0 THEN
                           2
                       ELSE
                           1
                   END AS [STATUS],
                   PREK_IDPSP
            FROM
            (
                SELECT PREK_IDPSP,
                       SUM(ISNULL(COUNT_OK, 0)) AS COUNT_OK,
                       SUM(ISNULL(COUNT_NOT_OK, 0)) AS COUNT_NOT_OK
                FROM
                (
                    SELECT PREK_IDPSP,
                           (
                               SELECT COUNT(ID)
                               FROM tPRP_ERGBP
                               WHERE (
                                         PREP_FELD_VALID <> 0
                                         OR (
                                                PREP_FELD_VALID <> 0
                                                AND CAST(PREP_FELD_VALID_FORMEL AS VARCHAR(2000)) = ''
                                            )
                                     )
                                     AND PREP_IDPREK = tPRP_ERGBK.ID
                           ) AS COUNT_OK,
                           (
                               SELECT COUNT(ID)
                               FROM tPRP_ERGBP
                               WHERE PREP_FELD_VALID = 0
                                     AND CAST(PREP_FELD_VALID_FORMEL AS VARCHAR(2000)) <> ''
                                     AND PREP_IDPREK = tPRP_ERGBK.ID
                           ) AS COUNT_NOT_OK
                    FROM tPRP_ERGBK
                    WHERE PREK_PRPK_TYP = 0
                ) AS TEMP
                GROUP BY PREK_IDPSP
            ) AS TEMP
        ) AS tPRP
            ON tPRP.PREK_IDPSP = tPPS_SKKALP.ID)
        LEFT JOIN
        (
            SELECT PSMZ_IDPSKP,
                   CNT_MARB_ZU,
                   AD_NAME1 + CASE
                                  WHEN CNT_MARB_ZU > 1 THEN
                                      ' (...)'
                                  ELSE
                                      ''
                              END AS MIN_MARB_ZU
            FROM
            (
                SELECT COUNT(ID) AS CNT_MARB_ZU,
                       MIN(PSMZ_IDMR) AS MIN_IDMR,
                       PSMZ_IDPSKP
                FROM tPPS_SKKALP_MARB_ZU
                GROUP BY PSMZ_IDPSKP
            ) AS GRP_MARB_ZU
                LEFT JOIN
                (SELECT ID, MA_IDAD FROM tMARB) AS tMARB
                    ON tMARB.ID = GRP_MARB_ZU.MIN_IDMR
                LEFT JOIN
                (SELECT ID, AD_NAME1 FROM tADRS) AS tADRS
                    ON tADRS.ID = tMARB.MA_IDAD
        ) AS tMARB_ZU_GRP
            ON tMARB_ZU_GRP.PSMZ_IDPSKP = tPPS_SKKALP.ID)
        LEFT JOIN
        (
            SELECT ID_PSP,
                   CASE
                       WHEN CNT_PRP > 1 THEN
                           '...'
                       ELSE
                           SUBSTRING(PRV_NUMMER, 1, 5)
                   END AS PRP_AW,
                   CASE
                       WHEN CNT_PRP > 0 THEN
                           1
                       ELSE
                           0
                   END AS PRP_AW_INDIKATOR
            FROM
            (
                SELECT ID_PSP,
                       MAX(ID_PRP) AS ID_PRP,
                       MAX(CNT_PRP) AS CNT_PRP
                FROM
                (
                    SELECT ID_PSP,
                           MAX(ID_PRP) AS ID_PRP,
                           COUNT(ID_PRP) AS CNT_PRP
                    FROM
                    (
                        SELECT tPPS_SKKALP.ID AS ID_PSP,
                               CASE
                                   WHEN ISNULL(tPRP_PLANK.ID, 0) <> 0 THEN
                                       ISNULL(tPRP_PLANK.ID, 0)
                                   WHEN ISNULL(tPRP_PLANK_V.ID, 0) <> 0 THEN
                                       ISNULL(tPRP_PLANK_V.ID, 0)
                                   WHEN ISNULL(tPRP_PLANK_V_ARST.ID, 0) <> 0 THEN
                                       ISNULL(tPRP_PLANK_V_ARST.ID, 0)
                                   WHEN ISNULL(tPRP_PLANK_V_ARGR.ID, 0) <> 0 THEN
                                       ISNULL(tPRP_PLANK_V_ARGR.ID, 0)
                                   ELSE
                                       0
                               END AS ID_PRP
                        FROM
                        (SELECT * FROM tPPS_SKKALP) tPPS_SKKALP
                            LEFT JOIN tPPS_SKKALK
                                ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK
                            LEFT JOIN
                            (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK
                                ON tPRP_PLANK.PRK_IDPSP = tPPS_SKKALP.ID
                            LEFT JOIN
                            (
                                SELECT *
                                FROM tPRP_PRVZU
                                WHERE PRVZ_TYP_PRUEFUNG = 4
                                      AND CASE
                                              WHEN PRVZ_DATUM_BIS IS NULL THEN
                                                  1
                                              ELSE
                                                  CASE
                                                      WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN
                                                          1
                                                      ELSE
                                                          0
                                                  END
                                          END = 1
                                      AND CASE
                                              WHEN PRVZ_DATUM_VON IS NULL THEN
                                                  1
                                              ELSE
                                                  CASE
                                                      WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN
                                                          1
                                                      ELSE
                                                          0
                                                  END
                                          END = 1
                                      AND (
                                              (
                                                  ISNULL(PRVZ_IDMR, 0) = 0
                                                  AND ISNULL(PRVZ_IDMG, 0) = 0
                                              )
                                              OR ISNULL(PRVZ_IDMR, 0) IN (
                                                                             SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                         )
                                              OR ISNULL(PRVZ_IDMG, 0) IN (
                                                                             SELECT ID
                                                                             FROM tMGMI
                                                                             WHERE MM_IDMR =
                                                                             (
                                                                                 SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                             )
                                                                         )
                                          )
                            ) AS tPRP_PRVZU
                                ON tPRP_PRVZU.PRVZ_IDPSP = tPPS_SKKALP.ID
                            LEFT JOIN tPRP_PLANV
                                ON tPRP_PLANV.ID = tPRP_PRVZU.PRVZ_IDPRPPV
                            LEFT JOIN
                            (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK_V
                                ON tPRP_PLANK_V.PRK_IDPRPPV = tPRP_PLANV.ID
                            LEFT JOIN tBE_BELP
                                ON tBE_BELP.ID = tPPS_SKKALK.PSK_IDBEBP
                            LEFT JOIN
                            (
                                SELECT *
                                FROM tPRP_PRVZU
                                WHERE PRVZ_TYP_PRUEFUNG = 4
                                      AND CASE
                                              WHEN PRVZ_DATUM_BIS IS NULL THEN
                                                  1
                                              ELSE
                                                  CASE
                                                      WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN
                                                          1
                                                      ELSE
                                                          0
                                                  END
                                          END = 1
                                      AND CASE
                                              WHEN PRVZ_DATUM_VON IS NULL THEN
                                                  1
                                              ELSE
                                                  CASE
                                                      WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN
                                                          1
                                                      ELSE
                                                          0
                                                  END
                                          END = 1
                                      AND (
                                              (
                                                  ISNULL(PRVZ_IDMR, 0) = 0
                                                  AND ISNULL(PRVZ_IDMG, 0) = 0
                                              )
                                              OR ISNULL(PRVZ_IDMR, 0) IN (
                                                                             SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                         )
                                              OR ISNULL(PRVZ_IDMG, 0) IN (
                                                                             SELECT ID
                                                                             FROM tMGMI
                                                                             WHERE MM_IDMR =
                                                                             (
                                                                                 SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                             )
                                                                         )
                                          )
                            ) AS tPRP_PRVZU_ARST
                                ON tPRP_PRVZU_ARST.PRVZ_IDAR = tBE_BELP.BP_IDAR
                            LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARST
                                ON tPRP_PLANV_ARST.ID = tPRP_PRVZU_ARST.PRVZ_IDPRPPV
                            LEFT JOIN
                            (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK_V_ARST
                                ON tPRP_PLANK_V_ARST.PRK_IDPRPPV = tPRP_PLANV_ARST.ID
                            LEFT JOIN
                            (
                                SELECT *
                                FROM tPRP_PRVZU
                                WHERE PRVZ_TYP_PRUEFUNG = 4
                                      AND CASE
                                              WHEN PRVZ_DATUM_BIS IS NULL THEN
                                                  1
                                              ELSE
                                                  CASE
                                                      WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN
                                                          1
                                                      ELSE
                                                          0
                                                  END
                                          END = 1
                                      AND CASE
                                              WHEN PRVZ_DATUM_VON IS NULL THEN
                                                  1
                                              ELSE
                                                  CASE
                                                      WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN
                                                          1
                                                      ELSE
                                                          0
                                                  END
                                          END = 1
                                      AND (
                                              (
                                                  ISNULL(PRVZ_IDMR, 0) = 0
                                                  AND ISNULL(PRVZ_IDMG, 0) = 0
                                              )
                                              OR ISNULL(PRVZ_IDMR, 0) IN (
                                                                             SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                         )
                                              OR ISNULL(PRVZ_IDMG, 0) IN (
                                                                             SELECT ID
                                                                             FROM tMGMI
                                                                             WHERE MM_IDMR =
                                                                             (
                                                                                 SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                             )
                                                                         )
                                          )
                            ) AS tPRP_PRVZU_ARGR
                                ON tPRP_PRVZU_ARGR.PRVZ_IDAG IN (
                                                                    SELECT AM_IDAG
                                                                    FROM tAGMI
                                                                    WHERE AM_IDAR = tBE_BELP.BP_IDAR
                                                                          AND CASE
                                                                                  WHEN AM_DATUM_BIS IS NULL THEN
                                                                                      1
                                                                                  ELSE
                                                                                      CASE
                                                                                          WHEN CONVERT(
                                                                                                          DATETIME,
                                                                                                          GETDATE(),
                                                                                                          104
                                                                                                      ) <= AM_DATUM_BIS THEN
                                                                                              1
                                                                                          ELSE
                                                                                              0
                                                                                      END
                                                                              END = 1
                                                                          AND CASE
                                                                                  WHEN AM_DATUM_VON IS NULL THEN
                                                                                      1
                                                                                  ELSE
                                                                                      CASE
                                                                                          WHEN CONVERT(
                                                                                                          DATETIME,
                                                                                                          GETDATE(),
                                                                                                          104
                                                                                                      ) >= AM_DATUM_VON THEN
                                                                                              1
                                                                                          ELSE
                                                                                              0
                                                                                      END
                                                                              END = 1
                                                                )
                            LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARGR
                                ON tPRP_PLANV_ARGR.ID = tPRP_PRVZU_ARGR.PRVZ_IDPRPPV
                            LEFT JOIN
                            (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 1) AS tPRP_PLANK_V_ARGR
                                ON tPRP_PLANK_V_ARGR.PRK_IDPRPPV = tPRP_PRVZU_ARGR.ID
                    ) AS tPRPK_TEMP
                    WHERE tPRPK_TEMP.ID_PRP != 0
                    GROUP BY ID_PSP
                ) AS TEMP
                GROUP BY ID_PSP
            ) AS T
                LEFT JOIN
                (SELECT * FROM tPRP_PLANK) AS tPRP_PLANK
                    ON tPRP_PLANK.ID = ID_PRP
                LEFT JOIN
                (SELECT * FROM tPRP_PLANV) AS tPRP_PLANV
                    ON tPRP_PLANV.ID = tPRP_PLANK.PRK_IDPRPPV
        ) AS tPRP_AW
            ON tPRP_AW.ID_PSP = tPPS_SKKALP.ID)
        LEFT JOIN
        (
            SELECT ID_PSP,
                   MAX(ID_PRP) AS ID_PRP
            FROM
            (
                SELECT ID_PSP,
                       MAX(ID_PRP) AS ID_PRP
                FROM
                (
                    SELECT tPPS_SKKALP.ID AS ID_PSP,
                           CASE
                               WHEN ISNULL(tPRP_PLANK.ID, 0) <> 0 THEN
                                   ISNULL(tPRP_PLANK.ID, 0)
                               WHEN ISNULL(tPRP_PLANK_V.ID, 0) <> 0 THEN
                                   ISNULL(tPRP_PLANK_V.ID, 0)
                               WHEN ISNULL(tPRP_PLANK_V_ARST.ID, 0) <> 0 THEN
                                   ISNULL(tPRP_PLANK_V_ARST.ID, 0)
                               WHEN ISNULL(tPRP_PLANK_V_ARGR.ID, 0) <> 0 THEN
                                   ISNULL(tPRP_PLANK_V_ARGR.ID, 0)
                               ELSE
                                   0
                           END AS ID_PRP
                    FROM
                    (SELECT * FROM tPPS_SKKALP) tPPS_SKKALP
                        LEFT JOIN tPPS_SKKALK
                            ON tPPS_SKKALK.ID = tPPS_SKKALP.PSP_IDPSKKK
                        LEFT JOIN
                        (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK
                            ON tPRP_PLANK.PRK_IDPSP = tPPS_SKKALP.ID
                        LEFT JOIN
                        (
                            SELECT *
                            FROM tPRP_PRVZU
                            WHERE PRVZ_TYP_PRUEFUNG = 4
                                  AND CASE
                                          WHEN PRVZ_DATUM_BIS IS NULL THEN
                                              1
                                          ELSE
                                              CASE
                                                  WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN
                                                      1
                                                  ELSE
                                                      0
                                              END
                                      END = 1
                                  AND CASE
                                          WHEN PRVZ_DATUM_VON IS NULL THEN
                                              1
                                          ELSE
                                              CASE
                                                  WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN
                                                      1
                                                  ELSE
                                                      0
                                              END
                                      END = 1
                                  AND (
                                          (
                                              ISNULL(PRVZ_IDMR, 0) = 0
                                              AND ISNULL(PRVZ_IDMG, 0) = 0
                                          )
                                          OR ISNULL(PRVZ_IDMR, 0) IN (
                                                                         SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                     )
                                          OR ISNULL(PRVZ_IDMG, 0) IN (
                                                                         SELECT ID
                                                                         FROM tMGMI
                                                                         WHERE MM_IDMR =
                                                                         (
                                                                             SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                         )
                                                                     )
                                      )
                        ) AS tPRP_PRVZU
                            ON tPRP_PRVZU.PRVZ_IDPSP = tPPS_SKKALP.ID
                        LEFT JOIN tPRP_PLANV
                            ON tPRP_PLANV.ID = tPRP_PRVZU.PRVZ_IDPRPPV
                        LEFT JOIN
                        (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK_V
                            ON tPRP_PLANK_V.PRK_IDPRPPV = tPRP_PLANV.ID
                        LEFT JOIN tBE_BELP
                            ON tBE_BELP.ID = tPPS_SKKALK.PSK_IDBEBP
                        LEFT JOIN
                        (
                            SELECT *
                            FROM tPRP_PRVZU
                            WHERE PRVZ_TYP_PRUEFUNG = 4
                                  AND CASE
                                          WHEN PRVZ_DATUM_BIS IS NULL THEN
                                              1
                                          ELSE
                                              CASE
                                                  WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN
                                                      1
                                                  ELSE
                                                      0
                                              END
                                      END = 1
                                  AND CASE
                                          WHEN PRVZ_DATUM_VON IS NULL THEN
                                              1
                                          ELSE
                                              CASE
                                                  WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN
                                                      1
                                                  ELSE
                                                      0
                                              END
                                      END = 1
                                  AND (
                                          (
                                              ISNULL(PRVZ_IDMR, 0) = 0
                                              AND ISNULL(PRVZ_IDMG, 0) = 0
                                          )
                                          OR ISNULL(PRVZ_IDMR, 0) IN (
                                                                         SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                     )
                                          OR ISNULL(PRVZ_IDMG, 0) IN (
                                                                         SELECT ID
                                                                         FROM tMGMI
                                                                         WHERE MM_IDMR =
                                                                         (
                                                                             SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                         )
                                                                     )
                                      )
                        ) AS tPRP_PRVZU_ARST
                            ON tPRP_PRVZU_ARST.PRVZ_IDAR = tBE_BELP.BP_IDAR
                        LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARST
                            ON tPRP_PLANV_ARST.ID = tPRP_PRVZU_ARST.PRVZ_IDPRPPV
                        LEFT JOIN
                        (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK_V_ARST
                            ON tPRP_PLANK_V_ARST.PRK_IDPRPPV = tPRP_PLANV_ARST.ID
                        LEFT JOIN
                        (
                            SELECT *
                            FROM tPRP_PRVZU
                            WHERE PRVZ_TYP_PRUEFUNG = 4
                                  AND CASE
                                          WHEN PRVZ_DATUM_BIS IS NULL THEN
                                              1
                                          ELSE
                                              CASE
                                                  WHEN CONVERT(DATETIME, GETDATE(), 104) <= PRVZ_DATUM_BIS THEN
                                                      1
                                                  ELSE
                                                      0
                                              END
                                      END = 1
                                  AND CASE
                                          WHEN PRVZ_DATUM_VON IS NULL THEN
                                              1
                                          ELSE
                                              CASE
                                                  WHEN CONVERT(DATETIME, GETDATE(), 104) >= PRVZ_DATUM_VON THEN
                                                      1
                                                  ELSE
                                                      0
                                              END
                                      END = 1
                                  AND (
                                          (
                                              ISNULL(PRVZ_IDMR, 0) = 0
                                              AND ISNULL(PRVZ_IDMG, 0) = 0
                                          )
                                          OR ISNULL(PRVZ_IDMR, 0) IN (
                                                                         SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                     )
                                          OR ISNULL(PRVZ_IDMG, 0) IN (
                                                                         SELECT ID
                                                                         FROM tMGMI
                                                                         WHERE MM_IDMR =
                                                                         (
                                                                             SELECT ID FROM tMARB WHERE MA_IDBE = 0
                                                                         )
                                                                     )
                                      )
                        ) AS tPRP_PRVZU_ARGR
                            ON tPRP_PRVZU_ARGR.PRVZ_IDAG IN (
                                                                SELECT AM_IDAG
                                                                FROM tAGMI
                                                                WHERE AM_IDAR = tBE_BELP.BP_IDAR
                                                                      AND CASE
                                                                              WHEN AM_DATUM_BIS IS NULL THEN
                                                                                  1
                                                                              ELSE
                                                                                  CASE
                                                                                      WHEN CONVERT(
                                                                                                      DATETIME,
                                                                                                      GETDATE(),
                                                                                                      104
                                                                                                  ) <= AM_DATUM_BIS THEN
                                                                                          1
                                                                                      ELSE
                                                                                          0
                                                                                  END
                                                                          END = 1
                                                                      AND CASE
                                                                              WHEN AM_DATUM_VON IS NULL THEN
                                                                                  1
                                                                              ELSE
                                                                                  CASE
                                                                                      WHEN CONVERT(
                                                                                                      DATETIME,
                                                                                                      GETDATE(),
                                                                                                      104
                                                                                                  ) >= AM_DATUM_VON THEN
                                                                                          1
                                                                                      ELSE
                                                                                          0
                                                                                  END
                                                                          END = 1
                                                            )
                        LEFT JOIN tPRP_PLANV AS tPRP_PLANV_ARGR
                            ON tPRP_PLANV_ARGR.ID = tPRP_PRVZU_ARGR.PRVZ_IDPRPPV
                        LEFT JOIN
                        (SELECT * FROM tPRP_PLANK WHERE PRK_TYP = 0) AS tPRP_PLANK_V_ARGR
                            ON tPRP_PLANK_V_ARGR.PRK_IDPRPPV = tPRP_PRVZU_ARGR.ID
                ) AS tPRPK_TEMP
                WHERE tPRPK_TEMP.ID_PRP != 0
                GROUP BY ID_PSP
            ) AS TEMP
            GROUP BY ID_PSP
        ) AS tPRPK
            ON tPRPK.ID_PSP = tPPS_SKKALP.ID)
    WHERE tPPS_SKKALP.PSP_IDPSKKK = 70153
    UNION ALL
    SELECT CAST(KP_POSITION_NUMMER AS VARCHAR(20)) AS PSP_POSITION_NUMMER,
           CASE
               WHEN tARST.AR_ART = 3 THEN
                   6
               ELSE
                   case
                       when tARST.AR_ART = 1 then
                           1
                       else
                           CASE
                               WHEN KP_BG_TYP <> 2 THEN
                                   CASE
                                       WHEN ISNULL(tARST.AR_IDPV_PROD, 0) <> 0 THEN
                                           4
                                       ELSE
                                           5
                                   END
                               ELSE
                                   2
                           END
                   end
           END as PSP_TYP_POSITION,
           KP_INTERNTEXT AS KP_INTERNTEXT,
           '' AS PRP_AW,
           '' AS PRP_AW_INDIKATOR,
           KP_FLAG_AKT_PREIS_EINKAUF AS KP_FLAG_AKT_PREIS_EINKAUF,
           CAST(CASE
                    WHEN AR_ART = 0
                         AND PSK_TYP_PP_BER_MATERIAL_VERFUEGBARKEIT = 1
                         AND (
                                 (
                                     tSK_KALP.KP_TYP_LAGER_BUCHUNG_AUFTRAG = 0
                                     AND tSK_KALK.KK_TYP_LAGER_BUCHUNG_AUFTRAG = 1
                                 )
                                 OR tSK_KALP.KP_TYP_LAGER_BUCHUNG_AUFTRAG = 2
                             ) THEN
                        CASE
                            WHEN ISNULL(
                                 (
                                     SELECT SUM(KPLG_MENGE) AS KPLG_MENGE_SUM
                                     FROM tSK_KALP_LGBEWE
                                     WHERE tSK_KALP_LGBEWE.KPLG_IDSKKP = tSK_KALP.ID
                                 ),
                                 0
                                       ) >= ROUND(
                                                     KP_MENGE
                                                     * ISNULL(
                                                                 CASE
                                                                     WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                         CASE
                                                                             WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                                 tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                             ELSE
                                                                                 ROUND(
                                                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                          * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                                          4
                                                                                      )
                                                                         END
                                                                     ELSE
                                                                         1
                                                                 END,
                                                                 0
                                                             ),
                                                     2
                                                 ) THEN
                                1
                            ELSE
                                0
                        END
                    WHEN AR_ART = 1
                         AND PSK_TYP_PP_BER_FREMDLEISTUNG_VERFUEGBARKEIT = 1 THEN
                        CASE
                            WHEN ISNULL(
                                 (
                                     SELECT SUM(KP_BEST_MENGE) AS MENGE_BESTELLT
                                     FROM tSK_KALP_BEST
                                     WHERE KP_BEST_IDSKKP = tSK_KALP.ID
                                           AND KP_BEST_TYP <> 2
                                           AND KP_BEST_TYP_BEARBEITUNG = 0
                                 ),
                                 0
                                       ) >= ROUND(
                                                     KP_MENGE
                                                     * ISNULL(
                                                                 CASE
                                                                     WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                         CASE
                                                                             WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                                 tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                             ELSE
                                                                                 ROUND(
                                                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                          * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                                          4
                                                                                      )
                                                                         END
                                                                     ELSE
                                                                         1
                                                                 END,
                                                                 0
                                                             ),
                                                     2
                                                 ) THEN
                                CASE
                                    WHEN ISNULL(
                                         (
                                             SELECT SUM(BP_LIEF_MENGE) AS MENGE_GELIEFERT
                                             FROM tSK_KALP_BEST
                                                 LEFT JOIN tEK_BELP_LIEF
                                                     ON tEK_BELP_LIEF.BP_LIEF_IDEKBP = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                                             WHERE KP_BEST_IDSKKP = tSK_KALP.ID
                                                   AND KP_BEST_TYP <> 2
                                                   AND ISNULL(KP_BEST_IDEKBP_BEST, 0) <> 0
                                                   AND BP_LIEF_TYP_BEARBEITUNG = 0
                                         ),
                                         0
                                               ) >= ISNULL(
                                                    (
                                                        SELECT SUM(KP_BEST_MENGE) AS MENGE_BESTELLT_BELEG
                                                        FROM tSK_KALP_BEST
                                                        WHERE KP_BEST_IDSKKP = tSK_KALP.ID
                                                              AND KP_BEST_TYP <> 2
                                                              AND ISNULL(KP_BEST_IDEKBP_BEST, 0) <> 0
                                                    ),
                                                    0
                                                          ) THEN
                                        1
                                    ELSE
                                        0
                                END
                            ELSE
                                0
                        END
                    ELSE
                        CASE
                            WHEN EXISTS
                                 (
                                     SELECT *
                                     FROM tSK_KALP_BEST
                                     WHERE KP_BEST_IDSKKP = tSK_KALP.ID
                                           AND KP_BEST_TYP <> 2
                                           AND KP_BEST_TYP_BEARBEITUNG = 0
                                 ) THEN
                                CASE
                                    WHEN EXISTS
                                         (
                                             SELECT tSK_KALP_BEST.*
                                             FROM tSK_KALP_BEST
                                                 LEFT JOIN
                                                 (
                                                     SELECT tEK_BELP_LIEF.*
                                                     FROM tEK_BELP_LIEF
                                                         LEFT JOIN
                                                         (SELECT ID, BP_IDEKBK FROM tEK_BELP) AS tEK_BELP
                                                             ON tEK_BELP.ID = BP_LIEF_IDEKBP_LIEF
                                                         LEFT JOIN
                                                         (
                                                             SELECT BK_BKBE_IDEKBK
                                                             FROM tEK_BELK_BKBE
                                                             WHERE BK_BKBE_TYP_BELEG = 3
                                                         ) AS tEK_BELK_BKBE
                                                             ON tEK_BELK_BKBE.BK_BKBE_IDEKBK = tEK_BELP.BP_IDEKBK
                                                         LEFT JOIN
                                                         (SELECT BP_LIEF_IDEKBP FROM tEK_BELP_LIEF) AS tEK_BELP_LIEF_LI
                                                             ON tEK_BELP_LIEF_LI.BP_LIEF_IDEKBP = tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF
                                                     WHERE ISNULL(tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF, 0) <> 0
                                                           AND (
                                                                   ISNULL(BK_BKBE_IDEKBK, 0) <> 0
                                                                   OR ISNULL(tEK_BELP_LIEF_LI.BP_LIEF_IDEKBP, 0) <> 0
                                                               )
                                                 ) AS tEK_BELP_LIEF
                                                     ON tEK_BELP_LIEF.BP_LIEF_IDEKBP = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                                             WHERE KP_BEST_IDSKKP = tSK_KALP.ID
                                                   AND KP_BEST_TYP <> 2
                                                   AND KP_BEST_TYP_BEARBEITUNG = 0
                                                   AND ISNULL(tEK_BELP_LIEF.ID, 0) <> 0
                                         ) THEN
                                        1
                                    ELSE
                                        0
                                END
                            ELSE
                                CASE
                                    WHEN
                                    (
                                        SELECT COUNT(tPPS_SKKALP.PSP_POSITION_NUMMER) AS POS_NUMMER_ERLEDIGT
                                        FROM tPPS_SKKALP
                                        WHERE PSP_IDPSKKK = tPPS_SKKALK_SK.KK_IDPSKKK
                                              And PSP_POSITION_NUMMER > KP_POSITION_NUMMER
                                              AND CASE
                                                      WHEN EXISTS
                                        (
                                            SELECT * FROM tPPS_SKKALP_ZU WHERE tPPS_SKKALP_ZU.PSZ_IDSKP = tSK_KALP.ID
                                        )   THEN
                                                          CASE
                                                              WHEN tPPS_SKKALP.ID IN (
                                                                                         SELECT PSZ_IDPSP_ZU
                                                                                         FROM tPPS_SKKALP_ZU
                                                                                         WHERE tPPS_SKKALP_ZU.PSZ_IDSKP = tSK_KALP.ID
                                                                                     ) THEN
                                                                  1
                                                              ELSE
                                                                  0
                                                          END
                                                      ELSE
                                                          CASE
                                                              WHEN tPPS_SKKALP.PSP_POSITION_NUMMER >=
                                                              (
                                                                  SELECT MIN(PSP_POSITION_NUMMER) AS PSP_POSITION_NUMMER_MIN_FA
                                                                  FROM tPPS_SKKALP AS tPPS_SKKALP_FA
                                                                  WHERE tPPS_SKKALP_FA.PSP_IDPSKKK = tPPS_SKKALK_SK.KK_IDPSKKK
                                                                        AND tPPS_SKKALP_FA.PSP_POSITION_NUMMER > KP_POSITION_NUMMER
                                                                        AND tPPS_SKKALP_FA.PSP_NEUER_FERTIGUNGSABSCHNITT = 1
                                                              ) THEN
                                                                  0
                                                              ELSE
                                                                  CASE
                                                                      WHEN tPPS_SKKALP.PSP_POSITION_NUMMER >=
                                                                      (
                                                                          SELECT MIN(KP_POSITION_NUMMER) AS KP_POSITION_NUMMER_MIN_FA
                                                                          FROM tSK_KALP AS tSK_KALP_FA
                                                                          WHERE tSK_KALP_FA.KP_IDSKKK = tSK_KALP.KP_IDSKKK
                                                                                AND tSK_KALP_FA.KP_POSITION_NUMMER > tSK_KALP.KP_POSITION_NUMMER
                                                                                AND tSK_KALP_FA.KP_NEUER_FERTIGUNGSABSCHNITT = 1
                                                                      ) THEN
                                                                          0
                                                                      ELSE
                                                                          1
                                                                  END
                                                          END
                                                  END = 1
                                              AND (
                                                      PSP_PP_STATUS_PRODUKTION = 1
                                                      OR (CASE
                                                              WHEN PSP_TYP_POSITION = 0
                                                                   AND (
                                                                       (
                                                                           SELECT SUM(ISNULL(BUCH_BEWE_TEMP.ZEIT, 0)) AS SUM_ZEIT
                                                                           FROM tZE_BUCH
                                                                               LEFT JOIN
                                                                               (
                                                                                   SELECT ZBUBW_IDZBU,
                                                                                          DATEDIFF(
                                                                                                      SECOND,
                                                                                                      ZBUBW_DATUM_ZEIT_START,
                                                                                                      ZBUBW_DATUM_ZEIT_STOP
                                                                                                  ) AS ZEIT
                                                                                   FROM tZE_BUCH_BEWE
                                                                               ) AS BUCH_BEWE_TEMP
                                                                                   ON BUCH_BEWE_TEMP.ZBUBW_IDZBU = tZE_BUCH.ID
                                                                           WHERE ZBU_IDPSKP = tPPS_SKKALP.ID
                                                                           GROUP BY ZBU_IDPSKP
                                                                       )   <> 0
                                                                       OR
                                                                       (
                                                                           SELECT SUM(ISNULL(tZE_BUCH.ZBU_MENGE_IST, 0)) AS SUM_MENGE_IST
                                                                           FROM tZE_BUCH
                                                                               LEFT JOIN
                                                                               (
                                                                                   SELECT ZBUBW_IDZBU,
                                                                                          DATEDIFF(
                                                                                                      SECOND,
                                                                                                      ZBUBW_DATUM_ZEIT_START,
                                                                                                      ZBUBW_DATUM_ZEIT_STOP
                                                                                                  ) AS ZEIT
                                                                                   FROM tZE_BUCH_BEWE
                                                                               ) AS BUCH_BEWE_TEMP
                                                                                   ON BUCH_BEWE_TEMP.ZBUBW_IDZBU = tZE_BUCH.ID
                                                                           WHERE ZBU_IDPSKP = tPPS_SKKALP.ID
                                                                           GROUP BY ZBU_IDPSKP
                                                                       )   <> 0
                                                                       OR
                                                                       (
                                                                           SELECT SUM(ISNULL(
                                                                                                tZE_BUCH.ZBU_MENGE_AUSSCHUSS,
                                                                                                0
                                                                                            )
                                                                                     ) AS SUM_MENGE_AUSSCHUSS
                                                                           FROM tZE_BUCH
                                                                               LEFT JOIN
                                                                               (
                                                                                   SELECT ZBUBW_IDZBU,
                                                                                          DATEDIFF(
                                                                                                      SECOND,
                                                                                                      ZBUBW_DATUM_ZEIT_START,
                                                                                                      ZBUBW_DATUM_ZEIT_STOP
                                                                                                  ) AS ZEIT
                                                                                   FROM tZE_BUCH_BEWE
                                                                               ) AS BUCH_BEWE_TEMP
                                                                                   ON BUCH_BEWE_TEMP.ZBUBW_IDZBU = tZE_BUCH.ID
                                                                           WHERE ZBU_IDPSKP = tPPS_SKKALP.ID
                                                                           GROUP BY ZBU_IDPSKP
                                                                       )   <> 0
                                                                       ) THEN
                                                                  1
                                                              ELSE
                                                                  0
                                                          END = 1
                                                         )
                                                  )
                                    ) >= CASE
                                             WHEN EXISTS
                                                  (
                                                      SELECT * FROM tPPS_SKKALP_ZU WHERE tPPS_SKKALP_ZU.PSZ_IDSKP = tSK_KALP.ID
                                                  ) THEN
                                             (
                                                 SELECT COUNT(PSZ_IDPSP_ZU)
                                                 FROM tPPS_SKKALP_ZU
                                                 WHERE tPPS_SKKALP_ZU.PSZ_IDSKP = tSK_KALP.ID
                                             )
                                             ELSE
                                                 1
                                         END THEN
                                        1
                                    ELSE
                                        0
                                END
                        END
                END AS SMALLINT) AS PSP_PP_STATUS_PRODUKTION,
           CAST(KP_PP_ZEIT_TAGE_DURCHLAUFZEIT AS FLOAT) AS PSP_ZEIT_TAGE_DURCHLAUFZEIT,
           CAST(0 AS FLOAT) AS PSP_ZEIT_UEBERLAPPUNG_PROZENT,
           CAST(0 AS SMALLINT) AS PSP_PP_STATUS_ANZAHL_TAGE_PRODUKTION,
           CAST(CASE
                    WHEN ISDATE(KP_PP_DATUM_START) = 1 THEN
                        CAST((CONVERT(varchar, KP_PP_DATUM_START, 104)) as datetime)
                END AS datetime) AS PSP_PP_DATUM_START,
           CAST(KP_PP_DATUM_START_STATUS AS SMALLINT) AS PSP_PP_DATUM_START_STATUS,
           CAST(CASE
                    WHEN KP_IDAR IS NOT NULL THEN
                        tARST.AR_NUMMER
                    ELSE
                        CASE
                            WHEN KP_IDSKKV_POS IS NOT NULL THEN
                                tSK_KALV_UNTEREBENE.KV_UNTEREBENE_NUMMER
                        END
                END AS VARCHAR(50)) AS PSP_ARBEITSSCHRITT_NUMMER,
           CAST(CASE
                    WHEN tSK_KALP.KP_TYP_POSITION = 0
                         AND KP_TYP_KALK_POS = 1 THEN
                        tARST.AR_BEZEICHNUNG
                    ELSE
                        KP_BEZEICHNUNG
                END AS VARCHAR(4000)) AS PSP_BEZEICHNUNG,
           CAST(CASE
                    WHEN tSK_KALP.KP_TYP_POSITION = 0
                         AND KP_TYP_KALK_POS = 1 THEN
                        tARST.AR_BEZEICHNUNG
                    ELSE
                        KP_INTERNTEXT
                END AS VARCHAR(4000)) AS PSP_INTERNTEXT,
           CAST(CAST(KP_BEZEICHNUNG AS VARCHAR(4000)) + CHAR(10)
                + IsNull(JOIN_TABLE_FORMEL.JOIN_KP_FORMEL_AUFBEREITET, '') AS VARCHAR(4000)) AS PSP_BEZEICHNUNG_FORMEL,
           CAST(case
                    when tSK_KALP.KP_TYP_MENGE_BASIS = 0 then
                        case
                            when tSK_KALP.KP_HK_MENGE_BASIS = 0 then
                                case
                                    when isnull(tSK_KALK.KK_IDBEBP, 0) <> 0 then
                                        tBE_BELP_MESU.BP_MESU_FE_MENGE
                                    when isnull(tPPS_SKKALV.ID, 0) <> 0 then
                                        tPPS_SKKALV.PSV_MENGE_BASIS
                                    else
                                        0
                                end
                            else
                                case
                                    when isnull(tSK_KALK.KK_IDBEBP, 0) <> 0 then
                                        tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO * tBE_BELP_MESU.BP_MESU_FE_MENGE
                                    when isnull(tPPS_SKKALV.ID, 0) <> 0 then
                                        tPPS_SKKALV.PSV_GEWICHT_BASIS * tPPS_SKKALV.PSV_MENGE_BASIS
                                    else
                                        0
                                end
                        end
                    else
                        1
                end AS FLOAT) AS PSP_MENGE_SOLL,
           CAST(0 AS FLOAT) AS PSP_ZEIT_MINUTEN_RUESTUNG_GESAMT_SOLL,
           REPLACE(CAST(ROUND(ISNULL(KP_MENGE, 0), 4) AS VARCHAR(39)), '.', ',') + ' '
