                                END
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS SMALLINT) AS KP_STATUS_LAGER_KOERPERLICH,
           CAST(CASE
                    WHEN tSK_KALK.KK_TYP_LAGER_BUCHUNG = 1 THEN
                        CASE
                            WHEN tARST.AR_TYP_LAGER_BUCHUNG = 1 THEN
                                CASE
                                    WHEN LG_BESTAND_LAGER_VERFÜGBAR + KP_MENGE_SUM <= 0 THEN
                                        1
                                    WHEN LG_BESTAND_LAGER_VERFÜGBAR + KP_MENGE_SUM < KP_MENGE_SUM THEN
                                        2
                                    WHEN LG_BESTAND_LAGER_VERFÜGBAR + KP_MENGE_SUM >= KP_MENGE_SUM THEN
                                        3
                                    ELSE
                                        0
                                END
                            ELSE
                                0
                        END
                    ELSE
                        0
                END AS SMALLINT) AS KP_STATUS_LAGER,
           CAST(AR_TYP_LAGER_BUCHUNG_EK_PROJEKT AS INT) AS AR_TYP_LAGER_BUCHUNG_EK_PROJEKT,
           CAST(CASE
                    WHEN BP_LIEF_MENGE_SUM + KP_BEST_MENGE_ERLEDIGT_SUM >= CAST(ROUND(
                                                                                         ISNULL(KP_MENGE, 0)
                                                                                         * case
                                                                                               when tSK_KALP.KP_TYP_MENGE_BASIS = 0 then
                                                                                                   case
                                                                                                       when tSK_KALP.KP_HK_MENGE_BASIS = 0 then
                                                                                                           case
                                                                                                               when isnull(
                                                                                                                              tSK_KALK.KK_IDBEBP,
                                                                                                                              0
                                                                                                                          ) <> 0 then
                                                                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                                               when isnull(
                                                                                                                              tPPS_SKKALV.ID,
                                                                                                                              0
                                                                                                                          ) <> 0 then
                                                                                                                   tPPS_SKKALV.PSV_MENGE_BASIS
                                                                                                               else
                                                                                                                   0
                                                                                                           end
                                                                                                       else
                                                                                                           case
                                                                                                               when isnull(
                                                                                                                              tSK_KALK.KK_IDBEBP,
                                                                                                                              0
                                                                                                                          ) <> 0 then
                                                                                                                   tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO
                                                                                                                   * tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                                               when isnull(
                                                                                                                              tPPS_SKKALV.ID,
                                                                                                                              0
                                                                                                                          ) <> 0 then
                                                                                                                   tPPS_SKKALV.PSV_GEWICHT_BASIS
                                                                                                                   * tPPS_SKKALV.PSV_MENGE_BASIS
                                                                                                               else
                                                                                                                   0
                                                                                                           end
                                                                                                   end
                                                                                               else
                                                                                                   1
                                                                                           end,
                                                                                         10
                                                                                     ) AS FLOAT) THEN
                        7
                    WHEN KP_BEST_MENGE_SUM >= CAST(ROUND(
                                                            ISNULL(KP_MENGE, 0)
                                                            * case
                                                                  when tSK_KALP.KP_TYP_MENGE_BASIS = 0 then
                                                                      case
                                                                          when tSK_KALP.KP_HK_MENGE_BASIS = 0 then
                                                                              case
                                                                                  when isnull(tSK_KALK.KK_IDBEBP, 0) <> 0 then
                                                                                      tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                  when isnull(tPPS_SKKALV.ID, 0) <> 0 then
                                                                                      tPPS_SKKALV.PSV_MENGE_BASIS
                                                                                  else
                                                                                      0
                                                                              end
                                                                          else
                                                                              case
                                                                                  when isnull(tSK_KALK.KK_IDBEBP, 0) <> 0 then
                                                                                      tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO
                                                                                      * tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                  when isnull(tPPS_SKKALV.ID, 0) <> 0 then
                                                                                      tPPS_SKKALV.PSV_GEWICHT_BASIS
                                                                                      * tPPS_SKKALV.PSV_MENGE_BASIS
                                                                                  else
                                                                                      0
                                                                              end
                                                                      end
                                                                  else
                                                                      1
                                                              end,
                                                            10
                                                        ) AS FLOAT)
                         AND BP_LIEF_MENGE_SUM + KP_BEST_MENGE_ERLEDIGT_SUM <> 0 THEN
                        6
                    WHEN KP_BEST_MENGE_SUM >= CAST(ROUND(
                                                            ISNULL(KP_MENGE, 0)
                                                            * case
                                                                  when tSK_KALP.KP_TYP_MENGE_BASIS = 0 then
                                                                      case
                                                                          when tSK_KALP.KP_HK_MENGE_BASIS = 0 then
                                                                              case
                                                                                  when isnull(tSK_KALK.KK_IDBEBP, 0) <> 0 then
                                                                                      tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                  when isnull(tPPS_SKKALV.ID, 0) <> 0 then
                                                                                      tPPS_SKKALV.PSV_MENGE_BASIS
                                                                                  else
                                                                                      0
                                                                              end
                                                                          else
                                                                              case
                                                                                  when isnull(tSK_KALK.KK_IDBEBP, 0) <> 0 then
                                                                                      tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO
                                                                                      * tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                  when isnull(tPPS_SKKALV.ID, 0) <> 0 then
                                                                                      tPPS_SKKALV.PSV_GEWICHT_BASIS
                                                                                      * tPPS_SKKALV.PSV_MENGE_BASIS
                                                                                  else
                                                                                      0
                                                                              end
                                                                      end
                                                                  else
                                                                      1
                                                              end,
                                                            10
                                                        ) AS FLOAT) THEN
                        5
                    WHEN KP_BEST_MENGE_SUM <> 0
                         AND BP_LIEF_MENGE_SUM + KP_BEST_MENGE_ERLEDIGT_SUM <> 0 THEN
                        4
                    WHEN KP_BEST_MENGE_SUM <> 0 THEN
                        3
                    WHEN KP_ANGEBOT_MENGE_SUM > 0 THEN
                        2
                    ELSE
                        1
                END AS SMALLINT) AS KP_STATUS_BESTELLUNG,
           CAST(tBE_BELP.BP_PP_PRIORITAET_PLANUNG AS INT) AS BP_PP_PRIORITAET_PLANUNG,
           CAST(0 AS FLOAT) AS PSP_IDFO_AK,
           CAST('' AS VARCHAR(4000)) AS PSP_VARIABLEN_AK,
           CAST('' AS VARCHAR(4000)) AS PSP_DIMENSIONEN_AK,
           CAST('' AS VARCHAR(4000)) AS PSP_WERTE_AK,
           CAST('' AS VARCHAR(100)) AS PSP_FORMEL_AK,
           CAST(0 AS FLOAT) AS PSP_IDFO_MS,
           CAST('' AS VARCHAR(4000)) AS PSP_VARIABLEN_MS,
           CAST('' AS VARCHAR(4000)) AS PSP_DIMENSIONEN_MS,
           CAST('' AS VARCHAR(4000)) AS PSP_WERTE_MS,
           CAST('' AS VARCHAR(100)) AS PSP_FORMEL_MS,
           CAST(0 AS SMALLINT) AS PSP_TYP_RUECKMELDUNG_BEMERKUNG,
           CAST(0 AS FLOAT) AS PSP_TYP_RUECKMELDUNG_PROZENT_DIFFERENZ_ZEIT,
           CAST(0 AS FLOAT) AS PSP_TYP_RUECKMELDUNG_PROZENT_DIFFERENZ_MENGE,
           CAST(0 AS SMALLINT) AS PSP_TYP_EINSTELLUNG_RUECKMELDUNG,
           CAST(0 AS SMALLINT) AS PSP_TYP_RUECKMELDUNG_MENGE_ZWINGEND,
           CAST(0 AS FLOAT) AS PSP_TYP_RUECKMELDUNG_PROZENT_DIFFERENZ_ZEIT_UEBERPRODUKTION,
           CAST(0 AS FLOAT) AS PSP_TYP_RUECKMELDUNG_PROZENT_DIFFERENZ_MENGE_UEBERPRODUKTION,
           CAST(NULL AS DATETIME) AS PSP_DATUM_START,
           CAST(NULL AS DATETIME) AS PSP_DATUM_STOP,
           CAST('' AS VARCHAR(4000)) AS BP_ARTIKEL_BEZEICHNUNG,
           CAST(CASE
                    WHEN
                    (
                        (
                            tSK_KALP.KP_TYP_LAGER_BUCHUNG_AUFTRAG = 0
                            AND tSK_KALK.KK_TYP_LAGER_BUCHUNG_AUFTRAG = 1
                        )
                        OR tSK_KALP.KP_TYP_LAGER_BUCHUNG_AUFTRAG = 2
                    ) THEN
                        STATUS_ARID
                    ELSE
                        -1
                END AS SMALLINT) AS MATERIAL_STATUS_ARID,
           CAST(CASE
                    WHEN
                    (
                        (
                            tSK_KALP.KP_TYP_LAGER_BUCHUNG_AUFTRAG = 0
                            AND tSK_KALK.KK_TYP_LAGER_BUCHUNG_AUFTRAG = 1
                        )
                        OR tSK_KALP.KP_TYP_LAGER_BUCHUNG_AUFTRAG = 2
                    ) THEN
                        CASE
                            WHEN ISNULL(STATUS_LAGER, 0) = 0 THEN
                                CASE
                                    WHEN EXISTS
                                         (
                                             SELECT ID FROM tBE_BELP_LIEF WHERE BP_LIEF_IDBEBP = tBE_BELP.ID
                                         ) THEN
                                        CASE
                                            WHEN tSK_KALP.KP_LAGER_STATUS_BUCHUNG = 0 THEN
                                                3
                                            ELSE
                                                4
                                        END
                                    ELSE
                                        0
                                END
                            ELSE
                                STATUS_LAGER
                        END
                    ELSE
                        -1
                END AS SMALLINT) AS MATERIAL_STATUS_LAGER,
           CAST(KP_TYP_SPERRE_WEITERVERARBEITUNG AS SMALLINT) AS PSP_TYP_SPERRE_WEITERVERARBEITUNG,
           CAST(KP_TYP_SPERRE_WEITERVERARBEITUNG_BELEGPOSITION AS SMALLINT) AS PSP_TYP_SPERRE_WEITERVERARBEITUNG_BELP,
           CAST((CASE
                     WHEN tARST.AR_ART = 1 THEN
                         ISNULL(SKKALK_IST.KP_SUMME_PREIS_EK_GP_LEISTUNG, 0)
                     ELSE
                         CASE
                             WHEN tARST.AR_ART = 3 THEN
                                 ISNULL(SKKALK_IST.KP_SUMME_PREIS_EK_GP_KOSTEN, 0)
                             ELSE
                                 ISNULL(SKKALK_IST.KP_SUMME_PREIS_EK_GP_MATERIAL, 0)
                         END
                 END - CASE
                           WHEN tARST.AR_ART = 1 THEN
                               ISNULL(SKKALK_IST.KP_SUMME_PREIS_EK_GP_LEISTUNG_IST, 0)
                           ELSE
                               CASE
                                   WHEN tARST.AR_ART = 3 THEN
                                       ISNULL(SKKALK_IST.KP_SUMME_PREIS_EK_GP_KOSTEN_IST, 0)
                                   ELSE
                                       ISNULL(SKKALK_IST.KP_SUMME_PREIS_EK_GP_MATERIAL_IST, 0)
                               END
                       END
                ) AS FLOAT) AS PSP_PREIS_HK_FK_EK_GP_DIFF,
           0 AS PSP_TYP_KOSTENTYP,
           0 AS PSP_PREIS_HK_FK_EK_EP_EINMAL,
           KP_PREIS_EK_EP AS PSP_PREIS_HK_FK_EK_EP,
           0 AS PSP_PREIS_HK_FK_EK_EP_RUESTUNG,
           0 AS PSP_PREIS_HK_FK_EK_EP_PRODUKTION,
           0 AS PSP_PREIS_HK_FK_EK_EP_PRODUKTION_AK,
           0 AS PSP_PREIS_HK_FK_EK_EP_PRODUKTION_MS,
           tBE_BELP.BP_IDAR AS BP_IDAR,
           0 AS PSP_MENGE_IST_FAKTOR,
           CASE
               WHEN RTRIM(LTRIM(ISNULL(KP_PREIS_EK_EP_STAFFEL, ''))) <> '' THEN
                   1
               ELSE
                   0
           END AS PSP_STATUS_MINDERMENGE_MATERIAL,
           0 AS PRP_STATUS,
           0 AS ID_PRP,
           CAST(0 AS FLOAT) AS ZE_BUCH_SUMME_ZEIT_EINZEL,
           CAST(KP_TYP_ANZEIGE_BDE AS INT) AS PSP_TYP_ANZEIGE_BDE,
           CAST(KP_TYP_KOSTEN_KALKULATION AS INT) AS PSP_TYP_KOSTEN_KALKULATION,
           CAST(KP_TYP_IST_KOSTEN_ERMITTLUNG AS INT) AS PSP_TYP_IST_KOSTEN_ERMITTLUNG,
           CAST(-1 AS INT) AS CNT_MARB_ZU,
           CAST('' AS VARCHAR(100)) AS MIN_MARB_ZU,
           CAST(-99 AS INT) AS PSP_FORTSCHRITT_PROZENT,
           CAST(0 AS INT) AS AS_TYP_FARBE_ARBEITSSCHRITT,
           CAST(0 AS INT) AS PSP_AKTIV,
           CAST(0 AS FLOAT) AS PSP_PP_NLZ_PROZENT,
           CAST(0 AS INT) AS PSP_TYP_BERECHNUNG_STUECKKOSTEN,
           CAST(KP_GEWICHT_KG_NETTO AS FLOAT) AS KP_GEWICHT_KG_NETTO,
           CAST(KP_GEWICHT_KG_BRUTTO AS FLOAT) AS KP_GEWICHT_KG_BRUTTO,
           CAST(ROUND(ISNULL(KP_MENGE, 0) * ISNULL(KP_GEWICHT_KG_NETTO, 0), KK_NK_GEW) AS FLOAT) AS KP_GEWICHT_KG_NETTO_GES,
           CAST(ROUND(ISNULL(KP_MENGE, 0) * ISNULL(KP_GEWICHT_KG_BRUTTO, 0), KK_NK_GEW) AS FLOAT) AS KP_GEWICHT_KG_BRUTTO_GES
    FROM(((((((((((((((tSK_KALP
        LEFT JOIN tARST
            ON tARST.ID = tSK_KALP.KP_IDAR)
        LEFT JOIN tLG_ORTE
            ON tLG_ORTE.ID = tSK_KALP.KP_IDLGOR)
        LEFT JOIN
        (
            SELECT ID AS KV_UNTEREBENE_ID,
                   KV_NUMMER As KV_UNTEREBENE_NUMMER
            FROM tSK_KALV
        ) AS tSK_KALV_UNTEREBENE
            ON tSK_KALV_UNTEREBENE.KV_UNTEREBENE_ID = tSK_KALP.KP_IDSKKV_POS)
        LEFT JOIN tARDI
            ON tARDI.ID = tSK_KALP.KP_IDAD)
        LEFT JOIN tSK_KALK
            ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK)
        LEFT JOIN
        (
            SELECT ID AS KK_IDPSKKK,
                   PSK_IDBEBP AS KK_PSK_IDBEBP,
                   PSK_TYP_PP_BER_MATERIAL_VERFUEGBARKEIT,
                   PSK_TYP_PP_BER_FREMDLEISTUNG_VERFUEGBARKEIT
            FROM tPPS_SKKALK
        ) AS tPPS_SKKALK_SK
            ON tPPS_SKKALK_SK.KK_PSK_IDBEBP = tSK_KALK.KK_IDBEBP)
        LEFT JOIN tBE_BELP_MESU
            ON tBE_BELP_MESU.BP_MESU_IDBEBP = tSK_KALK.KK_IDBEBP)
        LEFT JOIN tPPS_SKKALV
            ON tPPS_SKKALV.PSV_IDSKKV = tSK_KALK.KK_IDSKKV)
        LEFT JOIN tBE_BELP
            ON tBE_BELP.ID = tSK_KALK.KK_IDBEBP)
        LEFT JOIN
        (
            SELECT tSK_KALP.ID AS IDSKKP,
                   (tSK_KALP.KP_MENGE
                    * CASE
                          WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                              CASE
                                  WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                      tBE_BELP_MESU.BP_MESU_FE_MENGE
                                  ELSE
                                      ROUND(tBE_BELP_MESU.BP_MESU_FE_MENGE * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO, 4)
                              END
                          ELSE
                              1
                      END
                   ) AS KP_MENGE_SUM,
                   ISNULL(KP_BEST_MENGE_SUM, 0) AS KP_BEST_MENGE_SUM,
                   ISNULL(BP_LIEF_MENGE_SUM, 0) AS BP_LIEF_MENGE_SUM,
                   ISNULL(KP_BEST_MENGE_ERLEDIGT_SUM, 0) AS KP_BEST_MENGE_ERLEDIGT_SUM,
                   ISNULL(KP_ANGEBOT_MENGE_SUM, 0) AS KP_ANGEBOT_MENGE_SUM,
                   KP_IDLI AS IDLI_KP_SUM
            FROM tSK_KALP
                LEFT JOIN tSK_KALK
                    ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                LEFT JOIN tBE_BELP_MESU
                    ON tBE_BELP_MESU.BP_MESU_IDBEBP = tSK_KALK.KK_IDBEBP
                LEFT JOIN
                (
                    SELECT KP_BEST_IDSKKP,
                           SUM(KP_BEST_MENGE) AS KP_BEST_MENGE_ERLEDIGT_SUM
                    FROM tSK_KALP_BEST
                    WHERE KP_BEST_TYP_BEARBEITUNG = 0
                          AND ISNULL(KP_BEST_IDEKBP_BEST, 0) = 0
                          AND KP_BEST_TYP <> 2
                    GROUP BY KP_BEST_IDSKKP
                ) AS tSK_KALP_BEST_ERLEDIGT
                    ON tSK_KALP_BEST_ERLEDIGT.KP_BEST_IDSKKP = tSK_KALP.ID
                LEFT JOIN
                (
                    SELECT KP_BEST_IDSKKP,
                           SUM(   CASE
                                      WHEN tEK_BELK.BK_TYP_BELEG = 2 THEN
                                          KP_BEST_MENGE
                                      ELSE
                                          CASE
                                              WHEN
                                              (
                                                  tEK_BELK.BK_TYP_BELEG <> 2
                                                  AND tEK_BELK_LIEF.BK_TYP_BELEG = 2
                                              ) THEN
                                                  tEK_BELP_LIEF.BP_LIEF_MENGE
                                              ELSE
                                                  0
                                          END
                                  END
                              ) AS KP_BEST_MENGE_SUM,
                           SUM(   CASE
                                      WHEN tEK_BELK.BK_TYP_BELEG = 4 THEN
                                          KP_BEST_MENGE
                                      ELSE
                                          CASE
                                              WHEN
                                              (
                                                  tEK_BELK.BK_TYP_BELEG <> 4
                                                  AND tEK_BELK_LIEF.BK_TYP_BELEG = 4
                                              ) THEN
                                                  tEK_BELP_LIEF.BP_LIEF_MENGE
                                              ELSE
                                                  0
                                          END
                                  END
                              ) AS KP_ANGEBOT_MENGE_SUM
                    FROM tSK_KALP_BEST
                        LEFT JOIN tEK_BELP
                            ON tEK_BELP.ID = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                        LEFT JOIN tEK_BELK
                            ON tEK_BELK.ID = tEK_BELP.BP_IDEKBK
                        LEFT JOIN tEK_BELP_LIEF
                            ON tEK_BELP_LIEF.BP_LIEF_IDEKBP = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                        LEFT JOIN tEK_BELP AS tEK_BELP_LI
                            ON tEK_BELP_LI.ID = tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF
                        LEFT JOIN tEK_BELK AS tEK_BELK_LIEF
                            ON tEK_BELK_LIEF.ID = tEK_BELP_LI.BP_IDEKBK
                    WHERE ISNULL(KP_BEST_IDEKBP_BEST, 0) > 0
                          AND (
                                  tEK_BELK.BK_TYP_BELEG IN ( 2, 4 )
                                  OR (
                                         tEK_BELK.BK_TYP_BELEG NOT IN ( 2, 4 )
                                         AND tEK_BELK_LIEF.BK_TYP_BELEG IN ( 2, 4 )
                                     )
                              )
                    GROUP BY KP_BEST_IDSKKP
                ) AS tSK_KALP_BEST
                    ON tSK_KALP_BEST.KP_BEST_IDSKKP = tSK_KALP.ID
                LEFT JOIN
                (
                    SELECT tSK_KALP_BEST.KP_BEST_IDSKKP,
                           SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUM
                    FROM
                    (
                        SELECT KP_BEST_IDSKKP,
                               CASE
                                   WHEN tEK_BELK.BK_TYP_BELEG = 2 THEN
                                       KP_BEST_IDEKBP_BEST
                                   ELSE
                                       CASE
                                           WHEN
                                           (
                                               tEK_BELK.BK_TYP_BELEG <> 2
                                               AND tEK_BELK_BEST.BK_TYP_BELEG = 2
                                           ) THEN
                                               tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF
                                           ELSE
                                               0
                                       END
                               END AS KP_BEST_IDEKBP_BEST
                        FROM tSK_KALP_BEST
                            LEFT JOIN tEK_BELP
                                ON tEK_BELP.ID = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                            LEFT JOIN tEK_BELK
                                ON tEK_BELK.ID = tEK_BELP.BP_IDEKBK
                            LEFT JOIN tEK_BELP_LIEF
                                ON tEK_BELP_LIEF.BP_LIEF_IDEKBP = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                            LEFT JOIN tEK_BELP AS tEK_BELP_BE
                                ON tEK_BELP_BE.ID = tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF
                            LEFT JOIN tEK_BELK AS tEK_BELK_BEST
                                ON tEK_BELK_BEST.ID = tEK_BELP_BE.BP_IDEKBK
                        WHERE ISNULL(KP_BEST_IDEKBP_BEST, 0) > 0
                              AND (
                                      tEK_BELK.BK_TYP_BELEG = 2
                                      OR (
                                             tEK_BELK.BK_TYP_BELEG <> 2
                                             AND tEK_BELK_BEST.BK_TYP_BELEG = 2
                                         )
                                  )
                        GROUP BY KP_BEST_IDSKKP,
                                 CASE
                                     WHEN tEK_BELK.BK_TYP_BELEG = 2 THEN
                                         KP_BEST_IDEKBP_BEST
                                     ELSE
                                         CASE
                                             WHEN
                                             (
                                                 tEK_BELK.BK_TYP_BELEG <> 2
                                                 AND tEK_BELK_BEST.BK_TYP_BELEG = 2
                                             ) THEN
                                                 tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF
                                             ELSE
                                                 0
                                         END
                                 END
                    ) AS tSK_KALP_BEST
                        LEFT JOIN tEK_BELP_LIEF
                            ON tEK_BELP_LIEF.BP_LIEF_IDEKBP = tSK_KALP_BEST.KP_BEST_IDEKBP_BEST
                        LEFT JOIN tEK_BELP
                            ON tEK_BELP.ID = tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF
                        LEFT JOIN tEK_BELK
                            ON tEK_BELK.ID = tEK_BELP.BP_IDEKBK
                    WHERE ISNULL(KP_BEST_IDEKBP_BEST, 0) > 0
                          AND ISNULL(tEK_BELP_LIEF.ID, 0) > 0
                          AND ISNULL(tEK_BELP_LIEF.BP_LIEF_IDEKBP_LIEF, 0) > 0
                          AND tEK_BELK.BK_TYP_BELEG = 3
                    GROUP BY KP_BEST_IDSKKP
                ) AS tEK_BELP_LIEF_SKKALP
                    ON tEK_BELP_LIEF_SKKALP.KP_BEST_IDSKKP = tSK_KALP.ID
        ) AS tKP_SUMMEN
            ON tKP_SUMMEN.IDSKKP = tSK_KALP.ID)
        LEFT JOIN
        (
            select tmp_id,
                   left(tmp_merged, len(tmp_merged) - 1) as JOIN_KP_FORMEL_AUFBEREITET
            from
            (
                select tmp_id,
                       tmp_merged = (case
                                         when var0 <> '' then
                                             var0 + ': ' + val0 + ' ' + dim0 + '; '
                                         else
                                             ''
                                     end
                                    ) + (case
                                             when var1 <> '' then
                                                 var1 + ': ' + val1 + ' ' + dim1 + '; '
                                             else
                                                 ''
                                         end
                                        ) + (case
                                                 when var2 <> '' then
                                                     var2 + ': ' + val2 + ' ' + dim2 + '; '
                                                 else
                                                     ''
                                             end
                                            ) + (case
                                                     when var3 <> '' then
                                                         var3 + ': ' + val3 + ' ' + dim3 + '; '
                                                     else
                                                         ''
                                                 end
                                                ) + (case
                                                         when var4 <> '' then
                                                             var4 + ': ' + val4 + ' ' + dim4 + '; '
                                                         else
                                                             ''
                                                     end
                                                    ) + (case
                                                             when var5 <> '' then
                                                                 var5 + ': ' + val5 + ' ' + dim5 + '; '
                                                             else
                                                                 ''
                                                         end
                                                        ) + (case
                                                                 when var6 <> '' then
                                                                     var6 + ': ' + val6 + ' ' + dim6 + '; '
                                                                 else
                                                                     ''
                                                             end
