                                                )
                                                - (charindex(
                                                                ';',
                                                                kp_dimensionen,
                                                                charindex(
                                                                             ';',
                                                                             kp_dimensionen,
                                                                             charindex(
                                                                                          ';',
                                                                                          kp_dimensionen,
                                                                                          charindex(
