                                                                                                                                 kp_dimensionen,
                                                                                                                                 charindex(
                                                                                                                                              ';',
                                                                                                                                              kp_dimensionen,
                                                                                                                                              charindex(
                                                                                                                                                           ';',
                                                                                                                                                           kp_dimensionen,
                                                                                                                                                           charindex(
                                                                                                                                                                        ';',
                                                                                                                                                                        kp_dimensionen,
                                                                                                                                                                        1
                                                                                                                                                                    )
                                                                                                                                                           + 1
                                                                                                                                                       )
                                                                                                                                              + 1
                                                                                                                                          )
                                                                                                                                 + 1
                                                                                                                             )
                                                                                                                    + 1
