                                               ) - 1
                                           )
                    from tSK_KalP
                    where cast(kp_variablen as varchar(8000)) <> ''
                          and cast(kp_werte as varchar(8000)) <> ''
                          and cast(kp_dimensionen as varchar(8000)) <> ''
                          and cast(kp_variablen as varchar(8000)) <> ';;;;;;;;;;'
                ) as tmp_tbl
            ) as tmp_tbl
        ) As JOIN_TABLE_FORMEL
            on JOIN_TABLE_FORMEL.tmp_id = tSK_KALP.ID)
        LEFT JOIN
        (
            SELECT LG_KENNZ_IDAR,
                   LG_BESTAND_LAGER_KÖRPERLICH,
                   LG_BESTAND_LAGER_KÖRPERLICH_UNFERTIG,
                   LG_BESTAND_LAGER_KÖRPERLICH_GESPERRT,
                   LG_BESTAND_AUFTRAG,
                   LG_BESTAND_BESTELLT,
                   LG_BESTAND_PRODUKTION_ZUGANG,
                   LG_BESTAND_PRODUKTION_ABGANG,
                   LG_BESTAND_LAGER_VERFÜGBAR,
                   LG_BESTAND_BESTELLT_OHNE_TERMIN,
                   LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN,
                   'LG_BESTAND_BESTELLVORSCHLAG' = CASE
                                                       WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                           CASE
                                                               WHEN AR_LAGER_MENGE_MELDEBESTAND <> 0 THEN
                                                                   CASE
                                                                       WHEN (AR_LAGER_MENGE_MELDEBESTAND
                                                                             - (LG_BESTAND_LAGER_VERFÜGBAR
                                                                                + LG_BESTAND_BESTELLT_OHNE_TERMIN
                                                                                + LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN
                                                                               )
                                                                            ) > 0 THEN
                                                                           AR_LAGER_MENGE_MELDEBESTAND
                                                                           - (LG_BESTAND_LAGER_VERFÜGBAR
                                                                              + LG_BESTAND_BESTELLT_OHNE_TERMIN
                                                                              + LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN
                                                                             )
                                                                       ELSE
                                                                           0
                                                                   END
                                                               ELSE
                                                                   CASE
                                                                       WHEN (LG_BESTAND_LAGER_VERFÜGBAR
                                                                             + LG_BESTAND_BESTELLT_OHNE_TERMIN
                                                                             + LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN
                                                                            ) < 0 THEN
                   (LG_BESTAND_LAGER_VERFÜGBAR + LG_BESTAND_BESTELLT_OHNE_TERMIN
                    + LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN
                   ) * -1
                                                                       ELSE
                                                                           0
                                                                   END
                                                           END
                                                       ELSE
                                                           0
                                                   END
            FROM
            (
                SELECT *,
                       'LG_BESTAND_LAGER_VERFÜGBAR' = ROUND(
                                                               LG_BESTAND_LAGER_KÖRPERLICH
                                                               + (LG_BESTAND_BESTELLT - LG_BESTAND_AUFTRAG)
                                                               + (LG_BESTAND_PRODUKTION_ZUGANG
                                                                  - LG_BESTAND_PRODUKTION_ABGANG
                                                                 ),
                                                               4
                                                           )
                FROM
                (
                    SELECT LG_KENNZ_IDAR,
                           'LG_BESTAND_LAGER_KÖRPERLICH' = CASE
                                                               WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                   ROUND(ISNULL(LG_BESTAND_LAGER_KÖRPERLICH, 0), 4)
                                                               ELSE
                                                                   0
                                                           END,
                           'LG_BESTAND_LAGER_KÖRPERLICH_UNFERTIG' = CASE
                                                                        WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                            ROUND(
                                                                                     ISNULL(
                                                                                               LG_BESTAND_LAGER_KÖRPERLICH_UNFERTIG,
                                                                                               0
                                                                                           ),
                                                                                     4
                                                                                 )
                                                                        ELSE
                                                                            0
                                                                    END,
                           'LG_BESTAND_LAGER_KÖRPERLICH_GESPERRT' = CASE
                                                                        WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                            ROUND(
                                                                                     ISNULL(
                                                                                               LG_BESTAND_LAGER_KÖRPERLICH_GESPERRT,
                                                                                               0
                                                                                           ),
                                                                                     4
                                                                                 )
                                                                        ELSE
                                                                            0
                                                                    END,
                           'LG_BESTAND_AUFTRAG' = CASE
                                                      WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                          ROUND(ISNULL(LG_BESTAND_AUFTRAG, 0), 4)
                                                      ELSE
                                                          0
                                                  END,
                           'LG_BESTAND_BESTELLT' = CASE
                                                       WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                           ROUND(ISNULL(LG_BESTAND_BESTELLT, 0), 4)
                                                       ELSE
                                                           0
                                                   END,
                           'LG_BESTAND_BESTELLT_OHNE_TERMIN' = CASE
                                                                   WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                       ROUND(
                                                                                ISNULL(
                                                                                          LG_BESTAND_BESTELLT_OHNE_TERMIN,
                                                                                          0
                                                                                      ),
                                                                                4
                                                                            )
                                                                   ELSE
                                                                       0
                                                               END,
                           'LG_BESTAND_PRODUKTION_ZUGANG' = CASE
                                                                WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                    ROUND(ISNULL(LG_BESTAND_PRODUKTION_ZUGANG, 0), 4)
                                                                ELSE
                                                                    0
                                                            END,
                           'LG_BESTAND_PRODUKTION_ABGANG' = CASE
                                                                WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                    ROUND(ISNULL(LG_BESTAND_PRODUKTION_ABGANG, 0), 4)
                                                                ELSE
                                                                    0
                                                            END,
                           'LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN' = CASE
                                                                            WHEN AR_TYP_LAGER_BUCHUNG = 1 THEN
                                                                                ROUND(
                                                                                         ISNULL(
                                                                                                   LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN,
                                                                                                   0
                                                                                               ),
                                                                                         4
                                                                                     )
                                                                            ELSE
                                                                                0
                                                                        END,
                           AR_LAGER_MENGE_MELDEBESTAND,
                           AR_TYP_LAGER_BUCHUNG
                    FROM(((((
                    (
                        SELECT ID AS LG_KENNZ_IDAR,
                               AR_TYP_LAGER_BUCHUNG,
                               AR_LAGER_MENGE_MELDEBESTAND
                        FROM tARST
                        WHERE AR_TYP_LAGER_BUCHUNG = 1
                    ) AS tARST_LG_KENNZ
                        LEFT JOIN
                        (
                            SELECT LBW_IDAR,
                                   ISNULL(SUM(LBW_MENGE_FE), 0) AS LG_BESTAND_LAGER_KÖRPERLICH
                            FROM tLG_BEWE
                                LEFT JOIN tLG_ORTE
                                    ON tLG_ORTE.ID = tLG_BEWE.LBW_IDLGOR
                            WHERE LO_STATUS = 0
                            GROUP BY LBW_IDAR
                        ) AS tLG_BEST_BESTAND_KÖRPERLICH
                            ON tLG_BEST_BESTAND_KÖRPERLICH.LBW_IDAR = tARST_LG_KENNZ.LG_KENNZ_IDAR)
                        LEFT JOIN
                        (
                            SELECT LBW_IDAR,
                                   ISNULL(SUM(LBW_MENGE_FE), 0) AS LG_BESTAND_LAGER_KÖRPERLICH_UNFERTIG
                            FROM tLG_BEWE
                                LEFT JOIN tLG_ORTE
                                    ON tLG_ORTE.ID = tLG_BEWE.LBW_IDLGOR
                            WHERE LO_STATUS = 1
                            GROUP BY LBW_IDAR
                        ) AS tLG_BEST_BESTAND_KÖRPERLICH_UNFERTIG
                            ON tLG_BEST_BESTAND_KÖRPERLICH_UNFERTIG.LBW_IDAR = tARST_LG_KENNZ.LG_KENNZ_IDAR)
                        LEFT JOIN
                        (
                            SELECT LBW_IDAR,
                                   ISNULL(SUM(LBW_MENGE_FE), 0) AS LG_BESTAND_LAGER_KÖRPERLICH_GESPERRT
                            FROM tLG_BEWE
                                LEFT JOIN tLG_ORTE
                                    ON tLG_ORTE.ID = tLG_BEWE.LBW_IDLGOR
                            WHERE LO_STATUS = 2
                            GROUP BY LBW_IDAR
                        ) AS tLG_BEST_BESTAND_KÖRPERLICH_GESPERRT
                            ON tLG_BEST_BESTAND_KÖRPERLICH_GESPERRT.LBW_IDAR = tARST_LG_KENNZ.LG_KENNZ_IDAR)
                        LEFT JOIN
                        (
                            SELECT tARST.ID AS LG_AU_IDAR_AR,
                                   'LG_BESTAND_AUFTRAG' = ROUND(
                                                                   ISNULL(LG_BESTAND_BELP, 0)
                                                                   + ISNULL(LG_BESTAND_SKKALK, 0),
                                                                   4
                                                               ),
                                   'LG_BESTAND_PRODUKTION_ZUGANG' = ROUND(
                                                                             ISNULL(
                                                                                       LG_BESTAND_BELP_PRODUKTION_ZUGANG,
                                                                                       0
                                                                                   ),
                                                                             4
                                                                         ),
                                   'LG_BESTAND_PRODUKTION_ABGANG' = ROUND(
                                                                             ISNULL(
                                                                                       LG_BESTAND_SKKALK_PRODUKTION_ABGANG,
                                                                                       0
                                                                                   ),
                                                                             4
                                                                         ),
                                   'LG_BESTAND_PRODUKTION_ZUGANG_OHNE_TERMIN' = ROUND(
                                                                                         ISNULL(
                                                                                                   LG_BESTAND_BELP_PRODUKTION_ZUGANG_OHNE_TERMIN,
                                                                                                   0
                                                                                               ),
                                                                                         4
                                                                                     )
                            FROM((
                            (SELECT ID FROM tARST WHERE AR_TYP_LAGER_BUCHUNG = 1) AS tARST
                                LEFT JOIN
                                (
                                    SELECT LG_AU_IDAR,
                                           SUM(LG_AU_MENGE) AS LG_BESTAND_BELP,
                                           SUM(LG_AU_MENGE_PRODUKTION_ZUGANG) AS LG_BESTAND_BELP_PRODUKTION_ZUGANG,
                                           SUM(LG_AU_MENGE_PRODUKTION_ZUGANG_OHNE_TERMIN) AS LG_BESTAND_BELP_PRODUKTION_ZUGANG_OHNE_TERMIN
                                    FROM
                                    (
                                        SELECT 'LG_AU_IDAR' = BP_IDAR,
                                               'LG_AU_MENGE' = CASE
                                                                   WHEN BK_BKBE_TYP_BELEG_ART = 0 THEN
                                                                       CASE
                                                                           WHEN ISNULL(BP_MESU_FE_MENGE, 0)
                                                                                - ISNULL(BP_LIEF_MENGE_SUMME, 0) < 0 THEN
                                                                               0
                                                                           ELSE
                                                                               ISNULL(BP_MESU_FE_MENGE, 0)
                                                                               - ISNULL(BP_LIEF_MENGE_SUMME, 0)
                                                                       END
                                                                   ELSE
                                                                       0
                                                               END,
                                               'LG_AU_MENGE_PRODUKTION_ZUGANG' = CASE
                                                                                     WHEN BK_BKBE_TYP_BELEG_ART = 1 THEN
                                                                                         CASE
                                                                                             WHEN CASE
                                                                                                      WHEN BP_PP_DATUM_TERMIN IS NULL
                                                                                                           AND BP_LI_DATUM IS NULL
                                                                                                           AND BK_BKBE_AU_LI_DATUM IS NULL THEN
                                                                                                          0
                                                                                                      ELSE
                                                                                                          1
                                                                                                  END = 1 THEN
                                                                                                 CASE
                                                                                                     WHEN ISNULL(
                                                                                                                    BP_MESU_FE_MENGE,
                                                                                                                    0
                                                                                                                )
                                                                                                          - ISNULL(
                                                                                                                      BP_LIEF_MENGE_SUMME,
                                                                                                                      0
                                                                                                                  ) < 0 THEN
                                                                                                         0
                                                                                                     ELSE
                                                                                                         ISNULL(
                                                                                                                   BP_MESU_FE_MENGE,
                                                                                                                   0
                                                                                                               )
                                                                                                         - ISNULL(
                                                                                                                     BP_LIEF_MENGE_SUMME,
                                                                                                                     0
                                                                                                                 )
                                                                                                 END
                                                                                             ELSE
                                                                                                 0
                                                                                         END
                                                                                     ELSE
                                                                                         0
                                                                                 END,
                                               'LG_AU_MENGE_PRODUKTION_ZUGANG_OHNE_TERMIN' = CASE
                                                                                                 WHEN BK_BKBE_TYP_BELEG_ART = 1 THEN
                                                                                                     CASE
                                                                                                         WHEN CASE
                                                                                                                  WHEN BP_PP_DATUM_TERMIN IS NULL
                                                                                                                       AND BP_LI_DATUM IS NULL
                                                                                                                       AND BK_BKBE_AU_LI_DATUM IS NULL THEN
                                                                                                                      0
                                                                                                                  ELSE
                                                                                                                      1
                                                                                                              END = 0 THEN
                                                                                                             CASE
                                                                                                                 WHEN ISNULL(
                                                                                                                                BP_MESU_FE_MENGE,
                                                                                                                                0
                                                                                                                            )
                                                                                                                      - ISNULL(
                                                                                                                                  BP_LIEF_MENGE_SUMME,
                                                                                                                                  0
                                                                                                                              ) < 0 THEN
                                                                                                                     0
                                                                                                                 ELSE
                                                                                                                     ISNULL(
                                                                                                                               BP_MESU_FE_MENGE,
                                                                                                                               0
                                                                                                                           )
                                                                                                                     - ISNULL(
                                                                                                                                 BP_LIEF_MENGE_SUMME,
                                                                                                                                 0
                                                                                                                             )
                                                                                                             END
                                                                                                         ELSE
                                                                                                             0
                                                                                                     END
                                                                                                 ELSE
                                                                                                     0
                                                                                             END
                                        FROM((((
                                        (
                                            SELECT ID,
                                                   BP_IDAR,
                                                   BP_IDBEBK,
                                                   BP_LAGER_STATUS_BUCHUNG,
                                                   BP_LI_DATUM,
                                                   BP_PP_DATUM_TERMIN
                                            FROM tBE_BELP
                                            WHERE BP_POSITION_TYP = 0
                                        ) AS tBE_BELP
                                            INNER JOIN
                                            (
                                                SELECT BP_MESU_FE_MENGE,
                                                       BP_MESU_GEWICHT_NETTO,
                                                       BP_MESU_IDBEBP
                                                FROM tBE_BELP_MESU
                                                    INNER JOIN
                                                    (
                                                        SELECT ID,
                                                               BP_IDLGOR
                                                        FROM tBE_BELP
                                                            INNER JOIN
                                                            (
                                                                SELECT BK_BKBE_IDBEBK
                                                                FROM tBE_BELK_BKBE
                                                                WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                      AND BK_BKBE_TYP_BELEG = 2
                                                            ) AS tBE_BELK_BKBE_OFFEN
                                                                ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                        WHERE BP_POSITION_TYP = 0
                                                    ) AS tBE_BELP
                                                        ON tBE_BELP.ID = tBE_BELP_MESU.BP_MESU_IDBEBP
                                                    LEFT JOIN tLG_ORTE
                                                        ON tLG_ORTE.ID = tBE_BELP.BP_IDLGOR
                                                WHERE (ISNULL(tBE_BELP.BP_IDLGOR, 0) = 0)
                                                      OR (
                                                             ISNULL(tBE_BELP.BP_IDLGOR, 0) > 0
                                                             AND ISNULL(tLG_ORTE.LO_STATUS, 0) = 0
                                                         )
                                            ) AS tBE_BELP_MESU
                                                ON tBE_BELP_MESU.BP_MESU_IDBEBP = tBE_BELP.ID)
                                            LEFT JOIN
                                            (
                                                SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME,
                                                       BP_LIEF_IDBEBP
                                                FROM
                                                (
                                                    SELECT tBE_BELP_LIEF.*
                                                    FROM tBE_BELP_LIEF
                                                        LEFT JOIN
                                                        (
                                                            SELECT ID,
                                                                   BP_IDBEBK
                                                            FROM tBE_BELP
                                                            WHERE BP_POSITION_TYP = 0
                                                        ) AS tBE_BELP
                                                            ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                        INNER JOIN
                                                        (
                                                            SELECT BK_BKBE_IDBEBK
                                                            FROM tBE_BELK_BKBE
                                                            WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                  AND BK_BKBE_TYP_BELEG = 2
                                                        ) AS tBE_BELK_BKBE_OFFEN
                                                            ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                ) AS tBE_BELP_LIEF
                                                WHERE BP_LIEF_TYP_BEARBEITUNG = 0
                                                      AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                      AND BP_LIEF_TYP_BEWEGUNG = 0
                                                GROUP BY BP_LIEF_IDBEBP
                                            ) AS tBE_BELP_LIEF
                                                ON tBE_BELP_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID)
                                            LEFT JOIN
                                            (
                                                SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME_MANUELL,
                                                       BP_LIEF_IDBEBP
                                                FROM
                                                (
                                                    SELECT tBE_BELP_LIEF.*
                                                    FROM tBE_BELP_LIEF
                                                        LEFT JOIN
                                                        (
                                                            SELECT ID,
                                                                   BP_IDBEBK
                                                            FROM tBE_BELP
                                                            WHERE BP_POSITION_TYP = 0
                                                        ) AS tBE_BELP
                                                            ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                        INNER JOIN
                                                        (
                                                            SELECT BK_BKBE_IDBEBK
                                                            FROM tBE_BELK_BKBE
                                                            WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                  AND BK_BKBE_TYP_BELEG = 2
                                                        ) AS tBE_BELK_BKBE_OFFEN
                                                            ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                ) AS tBE_BELP_LIEF
                                                WHERE BP_LIEF_TYP = 0
                                                      AND BP_LIEF_TYP_BEARBEITUNG = 0
                                                      AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                      AND BP_LIEF_TYP_BEWEGUNG = 0
                                                GROUP BY BP_LIEF_IDBEBP
                                            ) AS tBE_BELP_LIEF_MANUELL
                                                ON tBE_BELP_LIEF_MANUELL.BP_LIEF_IDBEBP = tBE_BELP.ID)
                                            LEFT JOIN
                                            (
                                                SELECT BK_BKBE_TYP_BELEG,
                                                       BK_BKBE_TYP_BELEG_ART,
                                                       'BKBE_BELEG_ART' = BK_BKBE_TYP_BELEG_ART,
                                                       BK_BKBE_STATUS_BEARBEITUNG,
                                                       BK_BKBE_IDBEBK,
                                                       BK_BKBE_DATUM_BELEG,
                                                       ID
                                                FROM tBE_BELK_BKBE
                                            ) AS tBE_BELK_BKBE
                                                ON tBE_BELK_BKBE.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK)
                                            LEFT JOIN
                                            (
                                                SELECT ID,
                                                       BK_BKBE_AU_IDBKBE,
                                                       BK_BKBE_AU_LI_DATUM
                                                FROM tBE_BELK_BKBE_AU
                                            ) AS tBE_BELK_BKBE_AU
                                                ON tBE_BELK_BKBE_AU.BK_BKBE_AU_IDBKBE = tBE_BELK_BKBE.ID
                                        WHERE BK_BKBE_TYP_BELEG = 2
                                              AND BK_BKBE_STATUS_BEARBEITUNG = 0
                                              AND BP_LAGER_STATUS_BUCHUNG = 0
                                              AND (
                                            (
                                                BK_BKBE_TYP_BELEG_ART = 0
                                                AND tBE_BELP.ID NOT IN (
                                                                           SELECT KK_IDBEBP
                                                                           FROM tSK_KALK
                                                                           WHERE tSK_KALK.KK_IDBEBP = tBE_BELP.ID
                                                                                 AND KK_TYP_LAGER_BUCHUNG = 1
                                                                                 AND ISNULL(
                                                                                     (
                                                                                         SELECT COUNT(KP_IDSKKK)
                                                                                         FROM tSK_KALP
                                                                                         WHERE tSK_KALP.KP_IDSKKK = tSK_KALK.ID
                                                                                     ),
                                                                                     0
                                                                                           ) > 0
                                                                       )
                                            )
                                                  )
                                        UNION ALL
                                        SELECT 'LG_AU_IDAR' = BP_IDAR,
                                               'LG_AU_MENGE' = CASE
                                                                   WHEN BK_BKBE_TYP_BELEG_ART = 0 THEN
                                                                       CASE
                                                                           WHEN ISNULL(BP_MESU_FE_MENGE, 0)
                                                                                - ISNULL(BP_LIEF_MENGE_SUMME, 0) < 0 THEN
                                                                               0
                                                                           ELSE
                                                                               ISNULL(BP_MESU_FE_MENGE, 0)
                                                                               - ISNULL(BP_LIEF_MENGE_SUMME, 0)
                                                                       END
                                                                   ELSE
                                                                       0
                                                               END,
                                               'LG_AU_MENGE_PRODUKTION_ZUGANG' = CASE
                                                                                     WHEN BK_BKBE_TYP_BELEG_ART = 1 THEN
                                                                                         CASE
                                                                                             WHEN CASE
                                                                                                      WHEN BP_PP_DATUM_TERMIN IS NULL
                                                                                                           AND BP_LI_DATUM IS NULL
                                                                                                           AND BK_BKBE_AU_LI_DATUM IS NULL THEN
                                                                                                          0
                                                                                                      ELSE
                                                                                                          1
                                                                                                  END = 1 THEN
                                                                                                 CASE
                                                                                                     WHEN ISNULL(
                                                                                                                    BP_MESU_FE_MENGE,
                                                                                                                    0
                                                                                                                )
                                                                                                          - ISNULL(
                                                                                                                      BP_LIEF_MENGE_SUMME,
                                                                                                                      0
                                                                                                                  ) < 0 THEN
                                                                                                         0
                                                                                                     ELSE
                                                                                                         ISNULL(
                                                                                                                   BP_MESU_FE_MENGE,
                                                                                                                   0
                                                                                                               )
                                                                                                         - ISNULL(
                                                                                                                     BP_LIEF_MENGE_SUMME,
                                                                                                                     0
                                                                                                                 )
                                                                                                 END
                                                                                             ELSE
                                                                                                 0
                                                                                         END
                                                                                     ELSE
                                                                                         0
                                                                                 END,
                                               'LG_AU_MENGE_PRODUKTION_ZUGANG_OHNE_TERMIN' = CASE
                                                                                                 WHEN BK_BKBE_TYP_BELEG_ART = 1 THEN
                                                                                                     CASE
                                                                                                         WHEN CASE
                                                                                                                  WHEN BP_PP_DATUM_TERMIN IS NULL
                                                                                                                       AND BP_LI_DATUM IS NULL
                                                                                                                       AND BK_BKBE_AU_LI_DATUM IS NULL THEN
                                                                                                                      0
                                                                                                                  ELSE
                                                                                                                      1
                                                                                                              END = 0 THEN
                                                                                                             CASE
                                                                                                                 WHEN ISNULL(
                                                                                                                                BP_MESU_FE_MENGE,
                                                                                                                                0
                                                                                                                            )
                                                                                                                      - ISNULL(
                                                                                                                                  BP_LIEF_MENGE_SUMME,
                                                                                                                                  0
                                                                                                                              ) < 0 THEN
                                                                                                                     0
                                                                                                                 ELSE
                                                                                                                     ISNULL(
                                                                                                                               BP_MESU_FE_MENGE,
                                                                                                                               0
                                                                                                                           )
                                                                                                                     - ISNULL(
                                                                                                                                 BP_LIEF_MENGE_SUMME,
                                                                                                                                 0
                                                                                                                             )
                                                                                                             END
                                                                                                         ELSE
                                                                                                             0
                                                                                                     END
                                                                                                 ELSE
                                                                                                     0
                                                                                             END
                                        FROM((((
                                        (
                                            SELECT ID,
                                                   BP_IDAR,
                                                   BP_IDBEBK,
                                                   BP_LAGER_STATUS_BUCHUNG,
                                                   BP_LI_DATUM,
                                                   BP_PP_DATUM_TERMIN
                                            FROM tBE_BELP
                                            WHERE BP_POSITION_TYP = 0
                                        ) AS tBE_BELP
                                            INNER JOIN
                                            (
                                                SELECT BP_MESU_FE_MENGE,
                                                       BP_MESU_GEWICHT_NETTO,
                                                       BP_MESU_IDBEBP
                                                FROM tBE_BELP_MESU
                                                    INNER JOIN
                                                    (
                                                        SELECT ID,
                                                               BP_IDLGOR
                                                        FROM tBE_BELP
                                                            INNER JOIN
                                                            (
                                                                SELECT BK_BKBE_IDBEBK
                                                                FROM tBE_BELK_BKBE
                                                                WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                      AND BK_BKBE_TYP_BELEG = 2
                                                            ) AS tBE_BELK_BKBE_OFFEN
                                                                ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                        WHERE BP_POSITION_TYP = 0
                                                    ) AS tBE_BELP
                                                        ON tBE_BELP.ID = tBE_BELP_MESU.BP_MESU_IDBEBP
                                                    LEFT JOIN tLG_ORTE
                                                        ON tLG_ORTE.ID = tBE_BELP.BP_IDLGOR
                                                WHERE (ISNULL(tBE_BELP.BP_IDLGOR, 0) = 0)
                                                      OR (
                                                             ISNULL(tBE_BELP.BP_IDLGOR, 0) > 0
                                                             AND ISNULL(tLG_ORTE.LO_STATUS, 0) = 0
                                                         )
                                            ) AS tBE_BELP_MESU
                                                ON tBE_BELP_MESU.BP_MESU_IDBEBP = tBE_BELP.ID)
                                            LEFT JOIN
                                            (
                                                SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME,
                                                       BP_LIEF_IDBEBP
                                                FROM
                                                (
                                                    SELECT tBE_BELP_LIEF.*
                                                    FROM tBE_BELP_LIEF
                                                        LEFT JOIN
                                                        (
                                                            SELECT ID,
                                                                   BP_IDBEBK
                                                            FROM tBE_BELP
                                                            WHERE BP_POSITION_TYP = 0
                                                        ) AS tBE_BELP
                                                            ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                        INNER JOIN
                                                        (
                                                            SELECT BK_BKBE_IDBEBK
                                                            FROM tBE_BELK_BKBE
                                                            WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                  AND BK_BKBE_TYP_BELEG = 2
                                                        ) AS tBE_BELK_BKBE_OFFEN
                                                            ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                ) AS tBE_BELP_LIEF
                                                WHERE BP_LIEF_TYP_BEARBEITUNG = 0
                                                      AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                      AND BP_LIEF_TYP_BEWEGUNG = 0
                                                GROUP BY BP_LIEF_IDBEBP
                                            ) AS tBE_BELP_LIEF
                                                ON tBE_BELP_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID)
                                            LEFT JOIN
                                            (
                                                SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME_MANUELL,
                                                       BP_LIEF_IDBEBP
                                                FROM
                                                (
                                                    SELECT tBE_BELP_LIEF.*
                                                    FROM tBE_BELP_LIEF
                                                        LEFT JOIN
                                                        (
                                                            SELECT ID,
                                                                   BP_IDBEBK
                                                            FROM tBE_BELP
                                                            WHERE BP_POSITION_TYP = 0
                                                        ) AS tBE_BELP
                                                            ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                        INNER JOIN
                                                        (
                                                            SELECT BK_BKBE_IDBEBK
                                                            FROM tBE_BELK_BKBE
                                                            WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                  AND BK_BKBE_TYP_BELEG = 2
                                                        ) AS tBE_BELK_BKBE_OFFEN
                                                            ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                ) AS tBE_BELP_LIEF
                                                WHERE BP_LIEF_TYP = 0
                                                      AND BP_LIEF_TYP_BEARBEITUNG = 0
                                                      AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                      AND BP_LIEF_TYP_BEWEGUNG = 0
                                                GROUP BY BP_LIEF_IDBEBP
                                            ) AS tBE_BELP_LIEF_MANUELL
                                                ON tBE_BELP_LIEF_MANUELL.BP_LIEF_IDBEBP = tBE_BELP.ID)
                                            LEFT JOIN
                                            (
                                                SELECT BK_BKBE_TYP_BELEG,
                                                       BK_BKBE_TYP_BELEG_ART,
                                                       'BKBE_BELEG_ART' = BK_BKBE_TYP_BELEG_ART,
                                                       BK_BKBE_STATUS_BEARBEITUNG,
                                                       BK_BKBE_IDBEBK,
                                                       BK_BKBE_DATUM_BELEG,
                                                       ID
                                                FROM tBE_BELK_BKBE
                                            ) AS tBE_BELK_BKBE
                                                ON tBE_BELK_BKBE.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK)
                                            LEFT JOIN
                                            (
                                                SELECT ID,
                                                       BK_BKBE_AU_IDBKBE,
                                                       BK_BKBE_AU_LI_DATUM
                                                FROM tBE_BELK_BKBE_AU
                                            ) AS tBE_BELK_BKBE_AU
                                                ON tBE_BELK_BKBE_AU.BK_BKBE_AU_IDBKBE = tBE_BELK_BKBE.ID
                                        WHERE BK_BKBE_TYP_BELEG = 2
                                              AND BK_BKBE_STATUS_BEARBEITUNG = 0
                                              AND BP_LAGER_STATUS_BUCHUNG = 0
                                              AND (BK_BKBE_TYP_BELEG_ART = 1)
                                    ) AS tBE_BELP_BESTAND_AUFTRAG_1
                                    GROUP BY LG_AU_IDAR
                                ) AS tBE_BELP_BESTAND_AUFTRAG
                                    ON tBE_BELP_BESTAND_AUFTRAG.LG_AU_IDAR = tARST.ID)
                                LEFT JOIN
                                (
                                    SELECT KP_IDAR AS LG_AU_IDAR_SK,
                                           SUM(KP_MENGE_KUM) AS LG_BESTAND_SKKALK,
                                           SUM(KP_MENGE_KUM_PRODUKTION_ABGANG) AS LG_BESTAND_SKKALK_PRODUKTION_ABGANG
                                    FROM
                                    (
                                        SELECT KP_IDAR,
                                               KP_MENGE_KUM,
                                               KP_MENGE_KUM_PRODUKTION_ABGANG
                                        FROM
                                        (
                                            SELECT KP_IDSKKK,
                                                   'KP_MENGE_KUM' = SUM(KP_MENGE_KUM),
                                                   'KP_MENGE_KUM_PRODUKTION_ABGANG' = SUM(KP_MENGE_KUM_PRODUKTION_ABGANG),
                                                   KP_IDAR
                                            FROM
                                            (
                                                SELECT KP_IDSKKK,
                                                       'KP_MENGE_KUM' = CASE
                                                                            WHEN BK_BKBE_TYP_BELEG_ART = 0 THEN
                                                                                ROUND(
                                                                                         ISNULL(
                                                                                                   CASE
                                                                                                       WHEN ISNULL(
                                                                                                                      KK_IDBEBP_BASIS,
                                                                                                                      0
                                                                                                                  ) <> 0 THEN
                                                                                                           CASE
                                                                                                               WHEN (KP_MENGE
                                                                                                                     * KK_MENGE_GES
                                                                                                                     * case
                                                                                                                           when KP_TYP_MENGE_BASIS = 0 then
                                                                                                                               case
                                                                                                                                   when KP_HK_MENGE_BASIS = 0 then
                                                                                                                                       case
                                                                                                                                           when isnull(
                                                                                                                                                          BP_MESU_FE_MENGE,
                                                                                                                                                          0
                                                                                                                                                      )
                                                                                                                                                - CASE
                                                                                                                                                      WHEN ISNULL(
                                                                                                                                                                     SUMME_LGBEWE_SKKALP,
                                                                                                                                                                     0
                                                                                                                                                                 ) = 0 THEN
                                                                                                                                                          isnull(
                                                                                                                                                                    BP_LIEF_MENGE_SUMME,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                      ELSE
                                                                                                                                                          ISNULL(
                                                                                                                                                                    BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                  END < 0 then
                                                                                                                                               0
                                                                                                                                           else
                                                                                                                                               isnull(
                                                                                                                                                         BP_MESU_FE_MENGE,
                                                                                                                                                         0
                                                                                                                                                     )
                                                                                                                                               - CASE
                                                                                                                                                     WHEN ISNULL(
                                                                                                                                                                    SUMME_LGBEWE_SKKALP,
                                                                                                                                                                    0
                                                                                                                                                                ) = 0 THEN
                                                                                                                                                         isnull(
                                                                                                                                                                   BP_LIEF_MENGE_SUMME,
                                                                                                                                                                   0
                                                                                                                                                               )
                                                                                                                                                     ELSE
                                                                                                                                                         ISNULL(
                                                                                                                                                                   BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                   0
                                                                                                                                                               )
                                                                                                                                                 END
                                                                                                                                       end
                                                                                                                                   else
                                                                                                                                       case
                                                                                                                                           when isnull(
                                                                                                                                                          BP_MESU_FE_MENGE,
                                                                                                                                                          0
                                                                                                                                                      )
                                                                                                                                                - CASE
                                                                                                                                                      WHEN ISNULL(
                                                                                                                                                                     SUMME_LGBEWE_SKKALP,
                                                                                                                                                                     0
                                                                                                                                                                 ) = 0 THEN
                                                                                                                                                          isnull(
                                                                                                                                                                    BP_LIEF_MENGE_SUMME,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                      ELSE
                                                                                                                                                          ISNULL(
                                                                                                                                                                    BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                  END < 0 then
                                                                                                                                               0
                                                                                                                                           else
                                                                                                                                               round(
                                                                                                                                                        (isnull(
                                                                                                                                                                   BP_MESU_FE_MENGE,
                                                                                                                                                                   0
                                                                                                                                                               )
                                                                                                                                                         - CASE
                                                                                                                                                               WHEN ISNULL(
                                                                                                                                                                              SUMME_LGBEWE_SKKALP,
                                                                                                                                                                              0
                                                                                                                                                                          ) = 0 THEN
                                                                                                                                                                   isnull(
                                                                                                                                                                             BP_LIEF_MENGE_SUMME,
                                                                                                                                                                             0
                                                                                                                                                                         )
                                                                                                                                                               ELSE
                                                                                                                                                                   ISNULL(
                                                                                                                                                                             BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                             0
                                                                                                                                                                         )
                                                                                                                                                           END
                                                                                                                                                        )
                                                                                                                                                        * isnull(
                                                                                                                                                                    BP_MESU_GEWICHT_NETTO,
                                                                                                                                                                    0
                                                                                                                                                                ),
                                                                                                                                                        4
                                                                                                                                                    )
                                                                                                                                       end
                                                                                                                               end
                                                                                                                           else
                                                                                                                               case
                                                                                                                                   when isnull(
                                                                                                                                                  BP_MESU_FE_MENGE,
                                                                                                                                                  0
                                                                                                                                              )
                                                                                                                                        - CASE
                                                                                                                                              WHEN ISNULL(
                                                                                                                                                             SUMME_LGBEWE_SKKALP,
                                                                                                                                                             0
                                                                                                                                                         ) = 0 THEN
                                                                                                                                                  isnull(
                                                                                                                                                            BP_LIEF_MENGE_SUMME,
                                                                                                                                                            0
                                                                                                                                                        )
                                                                                                                                              ELSE
                                                                                                                                                  ISNULL(
                                                                                                                                                            BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                            0
                                                                                                                                                        )
                                                                                                                                          END <= 0 then
                                                                                                                                       0
                                                                                                                                   else
                                                                                                                                       1
                                                                                                                               end
                                                                                                                       end
                                                                                                                    )
                                                                                                                    - ISNULL(
                                                                                                                                SUMME_LGBEWE_SKKALP,
                                                                                                                                0
                                                                                                                            ) <= 0 THEN
                                                                                                                   0
                                                                                                               ELSE
                                                                                                   (KP_MENGE
                                                                                                    * KK_MENGE_GES
                                                                                                    * case
                                                                                                          when KP_TYP_MENGE_BASIS = 0 then
                                                                                                              case
                                                                                                                  when KP_HK_MENGE_BASIS = 0 then
                                                                                                                      case
                                                                                                                          when isnull(
                                                                                                                                         BP_MESU_FE_MENGE,
                                                                                                                                         0
                                                                                                                                     )
                                                                                                                               - CASE
                                                                                                                                     WHEN ISNULL(
                                                                                                                                                    SUMME_LGBEWE_SKKALP,
                                                                                                                                                    0
                                                                                                                                                ) = 0 THEN
                                                                                                                                         isnull(
                                                                                                                                                   BP_LIEF_MENGE_SUMME,
                                                                                                                                                   0
                                                                                                                                               )
                                                                                                                                     ELSE
                                                                                                                                         ISNULL(
                                                                                                                                                   BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                   0
                                                                                                                                               )
                                                                                                                                 END < 0 then
                                                                                                                              0
                                                                                                                          else
                                                                                                                              isnull(
                                                                                                                                        BP_MESU_FE_MENGE,
                                                                                                                                        0
                                                                                                                                    )
                                                                                                                              - CASE
                                                                                                                                    WHEN ISNULL(
                                                                                                                                                   SUMME_LGBEWE_SKKALP,
                                                                                                                                                   0
                                                                                                                                               ) = 0 THEN
                                                                                                                                        isnull(
                                                                                                                                                  BP_LIEF_MENGE_SUMME,
                                                                                                                                                  0
                                                                                                                                              )
                                                                                                                                    ELSE
                                                                                                                                        ISNULL(
                                                                                                                                                  BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                  0
                                                                                                                                              )
                                                                                                                                END
                                                                                                                      end
                                                                                                                  else
                                                                                                                      case
                                                                                                                          when isnull(
                                                                                                                                         BP_MESU_FE_MENGE,
                                                                                                                                         0
                                                                                                                                     )
                                                                                                                               - CASE
                                                                                                                                     WHEN ISNULL(
                                                                                                                                                    SUMME_LGBEWE_SKKALP,
                                                                                                                                                    0
                                                                                                                                                ) = 0 THEN
                                                                                                                                         isnull(
                                                                                                                                                   BP_LIEF_MENGE_SUMME,
                                                                                                                                                   0
                                                                                                                                               )
                                                                                                                                     ELSE
                                                                                                                                         ISNULL(
                                                                                                                                                   BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                   0
                                                                                                                                               )
                                                                                                                                 END < 0 then
                                                                                                                              0
                                                                                                                          else
                                                                                                                              round(
                                                                                                                                       (isnull(
                                                                                                                                                  BP_MESU_FE_MENGE,
                                                                                                                                                  0
                                                                                                                                              )
                                                                                                                                        - CASE
                                                                                                                                              WHEN ISNULL(
                                                                                                                                                             SUMME_LGBEWE_SKKALP,
                                                                                                                                                             0
                                                                                                                                                         ) = 0 THEN
                                                                                                                                                  isnull(
                                                                                                                                                            BP_LIEF_MENGE_SUMME,
                                                                                                                                                            0
                                                                                                                                                        )
                                                                                                                                              ELSE
                                                                                                                                                  ISNULL(
                                                                                                                                                            BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                            0
                                                                                                                                                        )
                                                                                                                                          END
                                                                                                                                       )
                                                                                                                                       * isnull(
                                                                                                                                                   BP_MESU_GEWICHT_NETTO,
                                                                                                                                                   0
                                                                                                                                               ),
                                                                                                                                       4
                                                                                                                                   )
                                                                                                                      end
                                                                                                              end
                                                                                                          else
                                                                                                              case
                                                                                                                  when isnull(
                                                                                                                                 BP_MESU_FE_MENGE,
                                                                                                                                 0
                                                                                                                             )
                                                                                                                       - CASE
                                                                                                                             WHEN ISNULL(
                                                                                                                                            SUMME_LGBEWE_SKKALP,
                                                                                                                                            0
                                                                                                                                        ) = 0 THEN
                                                                                                                                 isnull(
                                                                                                                                           BP_LIEF_MENGE_SUMME,
                                                                                                                                           0
                                                                                                                                       )
                                                                                                                             ELSE
                                                                                                                                 ISNULL(
                                                                                                                                           BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                           0
                                                                                                                                       )
                                                                                                                         END <= 0 then
                                                                                                                      0
                                                                                                                  else
                                                                                                                      1
                                                                                                              end
                                                                                                      end
                                                                                                   )
                                                                                                   - ISNULL(
                                                                                                               SUMME_LGBEWE_SKKALP,
                                                                                                               0
                                                                                                           )
                                                                                                           END
                                                                                                       ELSE
                                                                                                           CASE
                                                                                                               WHEN (KP_MENGE
                                                                                                                     * case
                                                                                                                           when KP_TYP_MENGE_BASIS = 0 then
                                                                                                                               case
                                                                                                                                   when KP_HK_MENGE_BASIS = 0 then
                                                                                                                                       case
                                                                                                                                           when isnull(
                                                                                                                                                          BP_MESU_FE_MENGE,
                                                                                                                                                          0
                                                                                                                                                      )
