                                                                                                                                                                                  )
                                                                                                                                                                        ELSE
                                                                                                                                                                            ISNULL(
                                                                                                                                                                                      BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                                      0
                                                                                                                                                                                  )
                                                                                                                                                                    END < 0 then
                                                                                                                                                                 0
                                                                                                                                                             else
                                                                                                                                                                 round(
                                                                                                                                                                          (isnull(
                                                                                                                                                                                     BP_MESU_FE_MENGE,
                                                                                                                                                                                     0
                                                                                                                                                                                 )
                                                                                                                                                                           - CASE
                                                                                                                                                                                 WHEN ISNULL(
                                                                                                                                                                                                SUMME_LGBEWE_SKKALP,
                                                                                                                                                                                                0
                                                                                                                                                                                            ) = 0 THEN
                                                                                                                                                                                     isnull(
                                                                                                                                                                                               BP_LIEF_MENGE_SUMME,
                                                                                                                                                                                               0
                                                                                                                                                                                           )
                                                                                                                                                                                 ELSE
                                                                                                                                                                                     ISNULL(
                                                                                                                                                                                               BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                                               0
                                                                                                                                                                                           )
                                                                                                                                                                             END
                                                                                                                                                                          )
                                                                                                                                                                          * isnull(
                                                                                                                                                                                      BP_MESU_GEWICHT_NETTO,
                                                                                                                                                                                      0
                                                                                                                                                                                  ),
                                                                                                                                                                          4
                                                                                                                                                                      )
                                                                                                                                                         end
                                                                                                                                                 end
                                                                                                                                             else
                                                                                                                                                 case
                                                                                                                                                     when isnull(
                                                                                                                                                                    BP_MESU_FE_MENGE,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                          - CASE
                                                                                                                                                                WHEN ISNULL(
                                                                                                                                                                               SUMME_LGBEWE_SKKALP,
                                                                                                                                                                               0
                                                                                                                                                                           ) = 0 THEN
                                                                                                                                                                    isnull(
                                                                                                                                                                              BP_LIEF_MENGE_SUMME,
                                                                                                                                                                              0
                                                                                                                                                                          )
                                                                                                                                                                ELSE
                                                                                                                                                                    ISNULL(
                                                                                                                                                                              BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                              0
                                                                                                                                                                          )
                                                                                                                                                            END <= 0 then
                                                                                                                                                         0
                                                                                                                                                     else
                                                                                                                                                         1
                                                                                                                                                 end
                                                                                                                                         end
                                                                                                                                      )
                                                                                                                                      - ISNULL(
                                                                                                                                                  SUMME_LGBEWE_SKKALP,
                                                                                                                                                  0
                                                                                                                                              ) <= 0 THEN
                                                                                                                                     0
                                                                                                                                 ELSE
                                                                                                                     (KP_MENGE
                                                                                                                      * case
                                                                                                                            when KP_TYP_MENGE_BASIS = 0 then
                                                                                                                                case
                                                                                                                                    when KP_HK_MENGE_BASIS = 0 then
                                                                                                                                        case
                                                                                                                                            when isnull(
                                                                                                                                                           BP_MESU_FE_MENGE,
                                                                                                                                                           0
                                                                                                                                                       )
                                                                                                                                                 - CASE
                                                                                                                                                       WHEN ISNULL(
                                                                                                                                                                      SUMME_LGBEWE_SKKALP,
                                                                                                                                                                      0
                                                                                                                                                                  ) = 0 THEN
                                                                                                                                                           isnull(
                                                                                                                                                                     BP_LIEF_MENGE_SUMME,
                                                                                                                                                                     0
                                                                                                                                                                 )
                                                                                                                                                       ELSE
                                                                                                                                                           ISNULL(
                                                                                                                                                                     BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                     0
                                                                                                                                                                 )
                                                                                                                                                   END < 0 then
                                                                                                                                                0
                                                                                                                                            else
                                                                                                                                                isnull(
                                                                                                                                                          BP_MESU_FE_MENGE,
                                                                                                                                                          0
                                                                                                                                                      )
                                                                                                                                                - CASE
                                                                                                                                                      WHEN ISNULL(
                                                                                                                                                                     SUMME_LGBEWE_SKKALP,
                                                                                                                                                                     0
                                                                                                                                                                 ) = 0 THEN
                                                                                                                                                          isnull(
                                                                                                                                                                    BP_LIEF_MENGE_SUMME,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                      ELSE
                                                                                                                                                          ISNULL(
                                                                                                                                                                    BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                  END
                                                                                                                                        end
                                                                                                                                    else
                                                                                                                                        case
                                                                                                                                            when isnull(
                                                                                                                                                           BP_MESU_FE_MENGE,
                                                                                                                                                           0
                                                                                                                                                       )
                                                                                                                                                 - CASE
                                                                                                                                                       WHEN ISNULL(
                                                                                                                                                                      SUMME_LGBEWE_SKKALP,
                                                                                                                                                                      0
                                                                                                                                                                  ) = 0 THEN
                                                                                                                                                           isnull(
                                                                                                                                                                     BP_LIEF_MENGE_SUMME,
                                                                                                                                                                     0
                                                                                                                                                                 )
                                                                                                                                                       ELSE
                                                                                                                                                           ISNULL(
                                                                                                                                                                     BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                     0
                                                                                                                                                                 )
                                                                                                                                                   END < 0 then
                                                                                                                                                0
                                                                                                                                            else
                                                                                                                                                round(
                                                                                                                                                         (isnull(
                                                                                                                                                                    BP_MESU_FE_MENGE,
                                                                                                                                                                    0
                                                                                                                                                                )
                                                                                                                                                          - CASE
                                                                                                                                                                WHEN ISNULL(
                                                                                                                                                                               SUMME_LGBEWE_SKKALP,
                                                                                                                                                                               0
                                                                                                                                                                           ) = 0 THEN
                                                                                                                                                                    isnull(
                                                                                                                                                                              BP_LIEF_MENGE_SUMME,
                                                                                                                                                                              0
                                                                                                                                                                          )
                                                                                                                                                                ELSE
                                                                                                                                                                    ISNULL(
                                                                                                                                                                              BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                                              0
                                                                                                                                                                          )
                                                                                                                                                            END
                                                                                                                                                         )
                                                                                                                                                         * isnull(
                                                                                                                                                                     BP_MESU_GEWICHT_NETTO,
                                                                                                                                                                     0
                                                                                                                                                                 ),
                                                                                                                                                         4
                                                                                                                                                     )
                                                                                                                                        end
                                                                                                                                end
                                                                                                                            else
                                                                                                                                case
                                                                                                                                    when isnull(
                                                                                                                                                   BP_MESU_FE_MENGE,
                                                                                                                                                   0
                                                                                                                                               )
                                                                                                                                         - CASE
                                                                                                                                               WHEN ISNULL(
                                                                                                                                                              SUMME_LGBEWE_SKKALP,
                                                                                                                                                              0
                                                                                                                                                          ) = 0 THEN
                                                                                                                                                   isnull(
                                                                                                                                                             BP_LIEF_MENGE_SUMME,
                                                                                                                                                             0
                                                                                                                                                         )
                                                                                                                                               ELSE
                                                                                                                                                   ISNULL(
                                                                                                                                                             BP_LIEF_MENGE_SUMME_MANUELL,
                                                                                                                                                             0
                                                                                                                                                         )
                                                                                                                                           END <= 0 then
                                                                                                                                        0
                                                                                                                                    else
                                                                                                                                        1
                                                                                                                                end
                                                                                                                        end
                                                                                                                     )
                                                                                                                     - ISNULL(
                                                                                                                                 SUMME_LGBEWE_SKKALP,
                                                                                                                                 0
                                                                                                                             )
                                                                                                                             END
                                                                                                                     END,
                                                                                                                     0
                                                                                                                 ),
                                                                                                           4
                                                                                                       )
                                                                                              ELSE
                                                                                                  0
                                                                                          END,
                                                       KP_IDAR
                                                FROM((((((((tSK_KALP
                                                    LEFT JOIN
                                                    (
                                                        SELECT SUM(ISNULL(KPLG_MENGE, 0)) AS SUMME_LGBEWE_SKKALP,
                                                               KPLG_IDSKKP
                                                        FROM tSK_KALP_LGBEWE
                                                        GROUP BY KPLG_IDSKKP
                                                    ) AS tSUMME_LGBEWE_SKKALP
                                                        ON tSUMME_LGBEWE_SKKALP.KPLG_IDSKKP = tSK_KALP.ID)
                                                    RIGHT JOIN
                                                    (SELECT * FROM tSK_KALK WHERE KK_TYP_LAGER_BUCHUNG = 1) AS tSK_KALK
                                                        ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK)
                                                    RIGHT JOIN
                                                    (SELECT * FROM tBE_BELP) AS tBE_BELP
                                                        ON tBE_BELP.ID = CASE
                                                                             WHEN ISNULL(tSK_KALK.KK_IDBEBP, 0) <> 0 THEN
                                                                                 ISNULL(tSK_KALK.KK_IDBEBP, 0)
                                                                             WHEN ISNULL(tSK_KALK.KK_IDBEBP_BASIS, 0) <> 0 THEN
                                                                                 ISNULL(tSK_KALK.KK_IDBEBP_BASIS, 0)
                                                                         END)
                                                    RIGHT JOIN
                                                    (
                                                        SELECT tBE_BELK_BKBE.*,
                                                               'BKBE_BELEG_ART' = BK_BKBE_TYP_BELEG_ART
                                                        FROM tBE_BELK_BKBE
                                                        WHERE BK_BKBE_TYP_BELEG = 2
                                                              AND BK_BKBE_STATUS_BEARBEITUNG = 0
                                                    ) AS tBE_BELK_BKBE
                                                        ON tBE_BELK_BKBE.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK)
                                                    LEFT JOIN
                                                    (SELECT * FROM tBE_BELK_BKBE_AU) AS tBE_BELK_BKBE_AU
                                                        ON tBE_BELK_BKBE_AU.BK_BKBE_AU_IDBKBE = tBE_BELK_BKBE.ID
                                                    LEFT JOIN
                                                    (
                                                        SELECT BP_MESU_FE_MENGE,
                                                               BP_MESU_GEWICHT_NETTO,
                                                               BP_MESU_IDBEBP
                                                        FROM tBE_BELP_MESU
                                                    ) AS tBE_BELP_MESU
                                                        ON tBE_BELP_MESU.BP_MESU_IDBEBP = tBE_BELP.ID)
                                                    LEFT JOIN tLG_ORTE
                                                        ON tLG_ORTE.ID = tSK_KALP.KP_IDLGOR
                                                    LEFT JOIN
                                                    (
                                                        SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME,
                                                               BP_LIEF_IDBEBP
                                                        FROM
                                                        (
                                                            SELECT tBE_BELP_LIEF.*
                                                            FROM tBE_BELP_LIEF
                                                                LEFT JOIN
                                                                (
                                                                    SELECT ID,
                                                                           BP_IDBEBK
                                                                    FROM tBE_BELP
                                                                    WHERE BP_POSITION_TYP = 0
                                                                ) AS tBE_BELP
                                                                    ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                                INNER JOIN
                                                                (
                                                                    SELECT BK_BKBE_IDBEBK
                                                                    FROM tBE_BELK_BKBE
                                                                    WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                          AND BK_BKBE_TYP_BELEG = 2
                                                                ) AS tBE_BELK_BKBE_OFFEN
                                                                    ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                        ) AS tBE_BELP_LIEF
                                                        WHERE BP_LIEF_TYP_BEARBEITUNG = 0
                                                              AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                              AND BP_LIEF_TYP_BEWEGUNG = 0
                                                        GROUP BY BP_LIEF_IDBEBP
                                                    ) AS tBE_BELP_LIEF
                                                        ON tBE_BELP_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID)
                                                    LEFT JOIN
                                                    (
                                                        SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME_MANUELL,
                                                               BP_LIEF_IDBEBP
                                                        FROM
                                                        (
                                                            SELECT tBE_BELP_LIEF.*
                                                            FROM tBE_BELP_LIEF
                                                                LEFT JOIN
                                                                (
                                                                    SELECT ID,
                                                                           BP_IDBEBK
                                                                    FROM tBE_BELP
                                                                    WHERE BP_POSITION_TYP = 0
                                                                ) AS tBE_BELP
                                                                    ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                                INNER JOIN
                                                                (
                                                                    SELECT BK_BKBE_IDBEBK
                                                                    FROM tBE_BELK_BKBE
                                                                    WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                          AND BK_BKBE_TYP_BELEG = 2
                                                                ) AS tBE_BELK_BKBE_OFFEN
                                                                    ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                        ) AS tBE_BELP_LIEF
                                                        WHERE BP_LIEF_TYP = 0
                                                              AND BP_LIEF_TYP_BEARBEITUNG = 0
                                                              AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                              AND BP_LIEF_TYP_BEWEGUNG = 0
                                                        GROUP BY BP_LIEF_IDBEBP
                                                    ) AS tBE_BELP_LIEF_MANUELL
                                                        ON tBE_BELP_LIEF_MANUELL.BP_LIEF_IDBEBP = tBE_BELP.ID)
                                                    LEFT JOIN
                                                    (
                                                        SELECT ID AS KK_ID_UNTEREBENE,
                                                               KK_TYP_LAGER_BUCHUNG AS KK_TYP_LAGER_BUCHUNG_UNTEREBENE
                                                        FROM tSK_KALK
                                                    ) AS tSK_KALK_UNTEREBENE
                                                        ON tSK_KALK_UNTEREBENE.KK_ID_UNTEREBENE = tSK_KALP.KP_IDSKKK_POS)
                                                    LEFT JOIN
                                                    (
                                                        SELECT SUM(BP_LIEF_MENGE) AS BP_LIEF_MENGE_SUMME_LIEF,
                                                               BP_LIEF_IDBEBP
                                                        FROM
                                                        (
                                                            SELECT tBE_BELP_LIEF.*
                                                            FROM tBE_BELP_LIEF
                                                                LEFT JOIN
                                                                (
                                                                    SELECT ID,
                                                                           BP_IDBEBK
                                                                    FROM tBE_BELP
                                                                    WHERE BP_POSITION_TYP = 0
                                                                ) AS tBE_BELP
                                                                    ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP
                                                                INNER JOIN
                                                                (
                                                                    SELECT BK_BKBE_IDBEBK
                                                                    FROM tBE_BELK_BKBE
                                                                    WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                                          AND BK_BKBE_TYP_BELEG = 2
                                                                ) AS tBE_BELK_BKBE_OFFEN
                                                                    ON tBE_BELK_BKBE_OFFEN.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                                                        ) AS tBE_BELP_LIEF
                                                        WHERE BP_LIEF_TYP_BEARBEITUNG = 0
                                                              AND BP_LIEF_STATUS_LIEFERUNG = 0
                                                              AND BP_LIEF_TYP_BEWEGUNG = 0
                                                        GROUP BY BP_LIEF_IDBEBP
                                                    ) AS tBE_BELP_LIEF_SUMME_LIEF
                                                        ON tBE_BELP_LIEF_SUMME_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID
                                                WHERE (
                                                          KP_TYP_POSITION = 0
                                                          OR (
                                                                 KP_TYP_POSITION = 1
                                                                 AND ISNULL(KK_TYP_LAGER_BUCHUNG_UNTEREBENE, -1) = 0
                                                             )
                                                      )
                                                      AND KP_IDAR IS NOT NULL
                                                      AND BK_BKBE_TYP_BELEG = 2
                                                      AND BK_BKBE_STATUS_BEARBEITUNG = 0
                                                      AND KK_TYP_LAGER_BUCHUNG = 1
                                                      AND KP_LAGER_STATUS_BUCHUNG = 0
                                                      AND (
                                                              (ISNULL(KP_IDLGOR, 0) = 0)
                                                              OR (
                                                                     ISNULL(KP_IDLGOR, 0) > 0
                                                                     AND ISNULL(tLG_ORTE.LO_STATUS, 0) = 0
                                                                 )
                                                          )
                                            ) AS tSK_KALP
                                            GROUP BY KP_IDSKKK,
                                                     KP_IDAR
                                        ) AS tSK_KALP
                                    ) AS tSK_KALP_BESTAND_AUFTRAG_1
                                    GROUP BY KP_IDAR
                                ) AS tSK_KALP_BESTAND_AUFTRAG
                                    ON tSK_KALP_BESTAND_AUFTRAG.LG_AU_IDAR_SK = tARST.ID)
                        ) AS tBE_BELP_BESTAND_AUFTRAG
                            ON tBE_BELP_BESTAND_AUFTRAG.LG_AU_IDAR_AR = LG_KENNZ_IDAR)
                        LEFT JOIN
                        (
                            SELECT BP_IDAR,
                                   SUM(   CASE
                                              WHEN CASE
                                                       WHEN tEK_BELP.BP_LI_DATUM IS NULL
                                                            AND tEK_BELK_BKBE_BE.BK_BKBE_BE_LI_DATUM IS NULL THEN
                                                           0
                                                       ELSE
                                                           1
                                                   END = 1 THEN
                                                  CASE
                                                      WHEN tEK_BELP_MESU.BP_MESU_FE_MENGE IS NOT NULL
                                                           AND tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME IS NOT NULL THEN
                                                          CASE
                                                              WHEN tEK_BELP_MESU.BP_MESU_FE_MENGE
                                                                   - tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME < 0 THEN
                                                                  0
                                                              ELSE
                                                                  tEK_BELP_MESU.BP_MESU_FE_MENGE
                                                                  - tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME
                                                          END
                                                      ELSE
                                                          CASE
                                                              WHEN tEK_BELP_MESU.BP_MESU_FE_MENGE IS NOT NULL THEN
                                                                  tEK_BELP_MESU.BP_MESU_FE_MENGE
                                                              ELSE
                                                                  CASE
                                                                      WHEN tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME IS NOT NULL THEN
                                                                          tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME * -1
                                                                      ELSE
                                                                          0
                                                                  END
                                                          END
                                                  END
                                              ELSE
                                                  0
                                          END
                                      ) As LG_BESTAND_BESTELLT,
                                   SUM(   CASE
                                              WHEN CASE
                                                       WHEN tEK_BELP.BP_LI_DATUM IS NULL
                                                            AND tEK_BELK_BKBE_BE.BK_BKBE_BE_LI_DATUM IS NULL THEN
                                                           0
                                                       ELSE
                                                           1
                                                   END = 0 THEN
                                                  CASE
                                                      WHEN tEK_BELP_MESU.BP_MESU_FE_MENGE IS NOT NULL
                                                           AND tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME IS NOT NULL THEN
                                                          CASE
                                                              WHEN tEK_BELP_MESU.BP_MESU_FE_MENGE
                                                                   - tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME < 0 THEN
                                                                  0
                                                              ELSE
                                                                  tEK_BELP_MESU.BP_MESU_FE_MENGE
                                                                  - tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME
                                                          END
                                                      ELSE
                                                          CASE
                                                              WHEN tEK_BELP_MESU.BP_MESU_FE_MENGE IS NOT NULL THEN
                                                                  tEK_BELP_MESU.BP_MESU_FE_MENGE
                                                              ELSE
                                                                  CASE
                                                                      WHEN tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME IS NOT NULL THEN
                                                                          tEK_BELP_LIEF.BP_LIEF_MENGE_SUMME * -1
                                                                      ELSE
                                                                          0
                                                                  END
                                                          END
                                                  END
                                              ELSE
                                                  0
                                          END
                                      ) As LG_BESTAND_BESTELLT_OHNE_TERMIN
                            FROM(((((tEK_BELP
                                LEFT JOIN
                                (
                                    SELECT BP_MESU_IDEKBP,
                                           CASE
                                               WHEN ISNULL(BP_MESU_EK_IDAD, 0) = 0 THEN
                                                   BP_MESU_FE_MENGE
                                               ELSE
                                                   CASE
                                                       WHEN BP_MESU_EK_AD_FAKTOR = 0 THEN
                                                           0
                                                       ELSE
                                                           BP_MESU_FE_MENGE / BP_MESU_EK_AD_FAKTOR
                                                   END
                                           END AS BP_MESU_FE_MENGE
                                    FROM tEK_BELP_MESU
                                ) AS tEK_BELP_MESU
                                    ON tEK_BELP_MESU.BP_MESU_IDEKBP = tEK_BELP.ID)
                                LEFT JOIN
                                (
                                    SELECT BP_LIEF_IDEKBP,
                                           SUM(   CASE
                                                      WHEN ISNULL(tEK_BELP_MESU.BP_MESU_EK_IDAD, 0) = 0 THEN
                                                          BP_LIEF_MENGE
                                                      ELSE
                                                          CASE
                                                              WHEN ISNULL(tEK_BELP_MESU.BP_MESU_EK_AD_FAKTOR, 0) = 0 THEN
                                                                  0
                                                              ELSE
                                                                  BP_LIEF_MENGE / tEK_BELP_MESU.BP_MESU_EK_AD_FAKTOR
                                                          END
                                                  END
                                              ) AS BP_LIEF_MENGE_SUMME
                                    FROM
                                    (
                                        SELECT tEK_BELP_LIEF.*
                                        FROM tEK_BELP_LIEF
                                            LEFT JOIN
                                            (
                                                SELECT ID,
                                                       BP_IDEKBK
                                                FROM tEK_BELP
                                                WHERE BP_POSITION_TYP = 0
                                            ) AS tEK_BELP
                                                ON tEK_BELP.ID = tEK_BELP_LIEF.BP_LIEF_IDEKBP
                                            INNER JOIN
                                            (
                                                SELECT BK_BKBE_IDEKBK
                                                FROM tEK_BELK_BKBE
                                                WHERE BK_BKBE_STATUS_BEARBEITUNG = 0
                                                      AND BK_BKBE_TYP_BELEG = 2
                                            ) AS tEK_BELK_BKBE_OFFEN
                                                ON tEK_BELK_BKBE_OFFEN.BK_BKBE_IDEKBK = tEK_BELP.BP_IDEKBK
                                    ) AS tEK_BELP_LIEF
                                        LEFT JOIN tEK_BELP_MESU AS tEK_BELP_MESU
                                            ON tEK_BELP_MESU.BP_MESU_IDEKBP = tEK_BELP_LIEF.BP_LIEF_IDEKBP
                                    WHERE BP_LIEF_TYP_BEARBEITUNG = 0
                                    GROUP BY BP_LIEF_IDEKBP
                                ) AS tEK_BELP_LIEF
                                    ON tEK_BELP_LIEF.BP_LIEF_IDEKBP = tEK_BELP.ID)
                                LEFT JOIN tEK_BELK_BKBE
                                    ON tEK_BELK_BKBE.BK_BKBE_IDEKBK = tEK_BELP.BP_IDEKBK)
                                LEFT JOIN tEK_BELK_ALLG
                                    ON tEK_BELK_ALLG.BK_ALLG_IDEKBK = tEK_BELP.BP_IDEKBK)
                                LEFT JOIN tEK_BELK_BKBE_BE
                                    ON tEK_BELK_BKBE_BE.BK_BKBE_BE_IDBKEK = tEK_BELK_BKBE.ID)
                            WHERE BK_BKBE_TYP_BELEG = 2
                                  AND BK_BKBE_STATUS_BEARBEITUNG = 0
                                  AND (
                                          (
                                              (
                                              (
                                                  ISNULL(tEK_BELP.BP_IDBEBKBE_AU, 0) = 0
                                                  AND ISNULL(tEK_BELK_ALLG.BK_ALLG_IDBEBKBE_AU, 0) = 0
                                                  AND ISNULL(tEK_BELP.BP_IDPVPK, 0) = 0
                                                  AND ISNULL(tEK_BELK_ALLG.BK_ALLG_IDPVPK, 0) = 0
                                              )
                                              )
                                              OR BP_TYP_LAGER_BUCHUNG_EK_PROJEKT = 1
                                          )
                                          AND BP_LAGER_STATUS_BUCHUNG = 0
                                      )
                            GROUP BY tEK_BELP.BP_IDAR
                        ) AS tEK_BELP_BESTAND_BESTELLT
                            ON tEK_BELP_BESTAND_BESTELLT.BP_IDAR = LG_KENNZ_IDAR)
                ) AS tLG_KENNZ
            ) AS tLG_KENNZ
        ) AS tLG_KENNZ
            ON tLG_KENNZ.LG_KENNZ_IDAR = KP_IDAR)
        LEFT JOIN
        (
            SELECT KPLG_IDSKKP,
                   MIN(KP_STATUS_ARST_IDENT) AS STATUS_ARID,
                   CASE
                       WHEN SUM(ISNULL(KPLG_MENGE, 0)) = 0 THEN
                           0
                       ELSE
                           CASE
                               WHEN SUM(ISNULL(KPLG_MENGE, 0)) < MIN(KP_MENGE_GESAMT) THEN
                                   1
                               ELSE
                                   2
                           END
                   END AS STATUS_LAGER,
                   SUM(ISNULL(KPLG_MENGE, 0)) AS KPLG_MENGE_GESAMT
            FROM
            (
                SELECT tSK_KALP_LGBEWE.*,
                       CASE
                           WHEN NK_TYP_ARTIKEL_IDENT_VALID = 0 THEN
                               CASE
                                   WHEN NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 THEN
                                       0
                                   ELSE
                                       CASE
                                           WHEN NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 1 THEN
                                               CASE
                                                   WHEN AR_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 THEN
                                                       0
                                                   ELSE
                                                       CASE
                                                           WHEN ABS(ISNULL(AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN
                                                               1
                                                           ELSE
                                                               CASE
                                                                   WHEN ISNULL(AIBP_MENGE_GESAMT, 0) = 0 THEN
                                                                       CASE
                                                                           WHEN KPLG_IDAIBK IS NULL THEN
                                                                               3
                                                                           ELSE
                                                                               2
                                                                       END
                                                                   ELSE
                                                                       2
                                                               END
                                                       END
                                               END
                                           ELSE
                                               CASE
                                                   WHEN ABS(ISNULL(AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN
                                                       1
                                                   ELSE
                                                       CASE
                                                           WHEN ISNULL(AIBP_MENGE_GESAMT, 0) = 0 THEN
                                                               CASE
                                                                   WHEN KPLG_IDAIBK IS NULL THEN
                                                                       3
                                                                   ELSE
                                                                       2
                                                               END
                                                           ELSE
                                                               2
                                                       END
                                               END
                                       END
                               END
                           ELSE
                               CASE
                                   WHEN NK_TYP_ARTIKEL_IDENT_VALID = 1 THEN
                                       CASE
                                           WHEN KP_TYP_PRUEFUNG_ARTIKEL_IDENT = 0 THEN
                                               CASE
                                                   WHEN AR_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0 THEN
                                                       CASE
                                                           WHEN NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 0
                                                                OR NK_TYP_ARTIKEL_IDENT_DARSTELLUNG = 1 THEN
                                                               0
                                                           ELSE
                                                               CASE
                                                                   WHEN ABS(ISNULL(AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN
                                                                       1
                                                                   ELSE
                                                                       CASE
                                                                           WHEN ISNULL(AIBP_MENGE_GESAMT, 0) = 0 THEN
                                                                               CASE
                                                                                   WHEN KPLG_IDAIBK IS NULL THEN
                                                                                       3
                                                                                   ELSE
                                                                                       2
                                                                               END
                                                                           ELSE
                                                                               2
                                                                       END
                                                               END
                                                       END
                                                   ELSE
                                                       CASE
                                                           WHEN ABS(ISNULL(AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN
                                                               1
                                                           ELSE
                                                               CASE
                                                                   WHEN ISNULL(AIBP_MENGE_GESAMT, 0) = 0 THEN
                                                                       CASE
                                                                           WHEN KPLG_IDAIBK IS NULL THEN
                                                                               3
                                                                           ELSE
                                                                               2
                                                                       END
                                                                   ELSE
                                                                       2
                                                               END
                                                       END
                                               END
                                           ELSE
                                               CASE
                                                   WHEN ABS(ISNULL(AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN
                                                       1
                                                   ELSE
                                                       CASE
                                                           WHEN ISNULL(AIBP_MENGE_GESAMT, 0) = 0 THEN
                                                               CASE
                                                                   WHEN KP_IDAIBK IS NULL THEN
                                                                       4
                                                                   ELSE
                                                                       2
                                                               END
                                                           ELSE
                                                               2
                                                       END
                                               END
                                       END
                                   ELSE
                                       CASE
                                           WHEN ABS(ISNULL(AIBP_MENGE_GESAMT, 0)) >= ABS(KPLG_MENGE) THEN
                                               1
                                           ELSE
                                               CASE
                                                   WHEN ISNULL(AIBP_MENGE_GESAMT, 0) = 0 THEN
                                                       CASE
                                                           WHEN KPLG_IDAIBK IS NULL THEN
                                                               4
                                                           ELSE
                                                               2
                                                       END
                                                   ELSE
                                                       2
                                               END
                                       END
                               END
                       END AS KP_STATUS_ARST_IDENT,
                       tJOIN_SKKALP.KP_MENGE_GESAMT
                FROM tSK_KALP_LGBEWE
                    LEFT JOIN
                    (
                        SELECT SUM(AIBP_MENGE) AS AIBP_MENGE_GESAMT,
                               AIBP_IDAIBK
                        FROM tARID_BEWP
                        GROUP BY AIBP_IDAIBK
                    ) AS tARID_BEWP_MENGEN
                        ON tARID_BEWP_MENGEN.AIBP_IDAIBK = tSK_KALP_LGBEWE.KPLG_IDAIBK
                    INNER JOIN
                    (
                        SELECT tSK_KALP.*,
                               tKALP_MENGE_GESAMT.*,
                               tNUKR.NK_TYP_ARTIKEL_IDENT_DARSTELLUNG,
                               tNUKR.NK_TYP_ARTIKEL_IDENT_VALID,
                               tARST.AR_TYP_ARTIKEL_IDENT_DARSTELLUNG,
                               tSK_KALP.ID AS BASE_ID
                        FROM tSK_KALP
                            LEFT JOIN tARST
                                ON tARST.ID = tSK_KALP.KP_IDAR
                            LEFT JOIN
                            (
                                SELECT ID AS KK_BEBP_ID,
                                       KK_IDBEBP AS KK_BEBP_IDBEBP,
                                       KK_IDBEBP_BASIS AS KK_BEBP_IDBEBP_BASIS
                                FROM tSK_KALK
                            ) AS tSK_KALK_BEBP
                                ON tSK_KALK_BEBP.KK_BEBP_ID = tSK_KALP.KP_IDSKKK
                            LEFT JOIN tBE_BELP
                                ON tBE_BELP.ID = CASE
                                                     WHEN tSK_KALK_BEBP.KK_BEBP_IDBEBP IS NOT NULL THEN
                                                         tSK_KALK_BEBP.KK_BEBP_IDBEBP
                                                     ELSE
                                                         CASE
                                                             WHEN tSK_KALK_BEBP.KK_BEBP_IDBEBP_BASIS IS NOT NULL THEN
                                                                 tSK_KALK_BEBP.KK_BEBP_IDBEBP_BASIS
                                                             ELSE
                                                                 0
                                                         END
                                                 END
                            LEFT JOIN tBE_BELK
                                ON tBE_BELK.ID = tBE_BELP.BP_IDBEBK
                            LEFT JOIN tBE_BELK_BKBE
                                ON tBE_BELK_BKBE.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                            LEFT JOIN tBE_BELK_BKBU
                                ON tBE_BELK_BKBU.BK_BKBU_IDBEBK = tBE_BELP.BP_IDBEBK
                            LEFT JOIN tNUKR
                                ON tNUKR.ID = CASE
                                                  WHEN tBE_BELK.BK_TYP = 0 THEN
                                                      tBE_BELK_BKBU.BK_BKBU_IDNK
                                                  ELSE
                                                      CASE
                                                          WHEN tBE_BELK.BK_TYP = 1 THEN
                                                              tBE_BELK_BKBE.BK_BKBE_IDNK
                                                          ELSE
                                                              0
                                                      END
                                              END
                            LEFT JOIN
                            (
                                SELECT tSK_KALP.ID AS ID_KALP,
                                       'KP_MENGE_GESAMT' = KP_MENGE * CASE
                                                                          WHEN ISNULL(KK_IDBEBP_BASIS, 0) = 0 THEN
                                                                              CASE
                                                                                  WHEN KK_MENGE_GES = 0 THEN
                                                                                      1
                                                                                  ELSE
                                                                                      KK_MENGE_GES
                                                                              END
                                                                          ELSE
                                                                              KK_MENGE_GES
                                                                      END
                                                           * case
                                                                 when tSK_KALP.KP_TYP_MENGE_BASIS = 0 then
                                                                     case
                                                                         when tSK_KALP.KP_HK_MENGE_BASIS = 0 then
                                                                             BP_MESU_FE_MENGE
                                                                         else
                                                                             round(
                                                                                      tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                                      * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                                      4
                                                                                  )
                                                                     end
                                                                 else
                                                                     1
                                                             end
                                FROM tSK_KALP
                                    LEFT JOIN tSK_KALK
                                        ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                                    LEFT JOIN tBE_BELP_MESU
                                        ON tBE_BELP_MESU.BP_MESU_IDBEBP = CASE
                                                                              WHEN ISNULL(tSK_KALK.KK_IDBEBP, 0) <> 0 THEN
                                                                                  tSK_KALK.KK_IDBEBP
                                                                              ELSE
                                                                                  CASE
                                                                                      WHEN ISNULL(
                                                                                                     tSK_KALK.KK_IDBEBP_BASIS,
                                                                                                     0
                                                                                                 ) <> 0 THEN
                                                                                          tSK_KALK.KK_IDBEBP_BASIS
                                                                                      ELSE
                                                                                          0
                                                                                  END
                                                                          END
                                WHERE KP_TYP_POSITION = 0 /*SKKALP_TYP_POSITION_ARST*/
                                      OR (
                                             KP_TYP_POSITION = 1 /*SKKALP_TYP_POSITION_KALK*/
                                             AND KP_TYP_KALK_POS = 1 /*SKKALP_TYP_KALK_POS_ARTIKEL*/
                                         )
                            ) AS tKALP_MENGE_GESAMT
                                ON tKALP_MENGE_GESAMT.ID_KALP = tSK_KALP.ID
                            LEFT JOIN
                            (
                                SELECT ID AS KP_EBENE_POS_IDSKKK,
                                       KK_TYP_LAGER_BUCHUNG AS KP_EBENE_POS_TYP_LAGER_BUCHUNG
                                FROM tSK_KALK
                            ) AS tSK_KALK_EBENE_POS
                                ON tSK_KALK_EBENE_POS.KP_EBENE_POS_IDSKKK = tSK_KALP.KP_IDSKKK
                    ) AS tJOIN_SKKALP
                        ON tJOIN_SKKALP.BASE_ID = tSK_KALP_LGBEWE.KPLG_IDSKKP
            ) AS tTABLE
            GROUP BY KPLG_IDSKKP
        ) AS tSKKALP_LGBEWE_ARID
            ON tSKKALP_LGBEWE_ARID.KPLG_IDSKKP = tSK_KALP.ID)
        LEFT JOIN
        (
            SELECT CASE
                       WHEN tSK_KALK.KK_TYP_LAGER_BUCHUNG = 1 THEN
                           CASE
                               WHEN tSK_KALK.KK_TYP_LAGER_BUCHUNG_AUFTRAG = 1 THEN
                                   ISNULL(tSK_KALP_LGBEWE.SUM_KPLG, 0)
                               ELSE
                                   ISNULL(tLG_BEWE.LBW_MENGE_FE, 0)
                           END
                       ELSE
                           0
                   END AS MENGE_KPLG,
                   tSK_KALP.ID AS SKKALP_ID
            FROM tSK_KALP
                LEFT JOIN tSK_KALK
                    ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                LEFT JOIN
                (
                    SELECT SUM(ISNULL(tSK_KALP_LGBEWE.KPLG_MENGE, 0)) AS SUM_KPLG,
                           tSK_KALP_LGBEWE.KPLG_IDSKKP
                    FROM tSK_KALP_LGBEWE
                    GROUP BY tSK_KALP_LGBEWE.KPLG_IDSKKP
                ) AS tSK_KALP_LGBEWE
                    ON tSK_KALP_LGBEWE.KPLG_IDSKKP = tSK_KALP.ID
                LEFT JOIN tLG_BEWE
                    ON tLG_BEWE.ID = tSK_KALP.KP_IDLGBW
        ) AS SKKALP_LGMENGE
            ON SKKALP_LGMENGE.SKKALP_ID = tSK_KALP.ID
        LEFT JOIN
        (
            SELECT tSK_KALP.ID,
                   ROUND(SUM(ISNULL(tSK_KALP_PR.KALP_MENGE_PR, 0)), 4) AS KALP_MENGE_PR
            FROM tSK_KALP
                LEFT JOIN tSK_KALK
                    ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                LEFT JOIN tBE_BELP
                    ON tBE_BELP.ID = tSK_KALK.KK_IDBEBP
                LEFT JOIN
                (
                    SELECT tBE_BELP_LIEF.BP_LIEF_IDBEBP,
                           -1 * tLG_BEWE.LBW_MENGE_FE AS KALP_MENGE_PR,
                           tSK_KALP.*
                    FROM tBE_BELP_LIEF
                        LEFT JOIN tBE_BELP
                            ON tBE_BELP.ID = tBE_BELP_LIEF.BP_LIEF_IDBEBP_LIEF
                        LEFT JOIN tBE_BELP_MESU
                            ON tBE_BELP_MESU.BP_MESU_IDBEBP = tBE_BELP.ID
                        INNER JOIN
                        (
                            SELECT *
                            FROM tBE_BELK_BKBE
                            WHERE BK_BKBE_IDNK IN (
                                                      SELECT ID FROM tNUKR WHERE NK_TYP = 3 AND NK_TYP_BELEG_ART = 1
                                                  )
                        ) AS tBE_BELK_BKBE
                            ON tBE_BELK_BKBE.BK_BKBE_IDBEBK = tBE_BELP.BP_IDBEBK
                        LEFT JOIN tSK_KALK
                            ON tSK_KALK.KK_IDBEBP = tBE_BELP.ID
                        LEFT JOIN tSK_KALP
                            ON tSK_KALP.KP_IDSKKK = tSK_KALK.ID
                        INNER JOIN tLG_BEWE
                            ON tLG_BEWE.ID = tSK_KALP.KP_IDLGBW
                ) AS tSK_KALP_PR
                    ON tSK_KALP_PR.BP_LIEF_IDBEBP = tBE_BELP.ID
            WHERE tSK_KALP_PR.KP_IDAR = tSK_KALP.KP_IDAR
                  AND tSK_KALP_PR.KP_POSITION_NUMMER = tSK_KALP.KP_POSITION_NUMMER
            GROUP BY tSK_KALP.ID
        ) AS SKKALP_PR
            ON SKKALP_PR.ID = tSK_KALP.ID
        LEFT JOIN
        (
            SELECT KPLG_IDSKKP,
                   SUM(ISNULL(KPLG_MENGE, 0)) AS KPLG_MENGE
            FROM tSK_KALP_LGBEWE
            GROUP BY KPLG_IDSKKP
        ) AS tSK_KALP_LGBEWE_IST
            ON tSK_KALP_LGBEWE_IST.KPLG_IDSKKP = tSK_KALP.ID)
        LEFT JOIN
        (
            SELECT KALP_ID,
                   SUM(KP_PREIS_GP_MATERIAL) AS KP_SUMME_PREIS_GP_MATERIAL,
                   SUM(KP_PREIS_GP_MATERIAL_IST) AS KP_SUMME_PREIS_GP_MATERIAL_IST,
                   SUM(KP_PREIS_GP_LEISTUNG) AS KP_SUMME_PREIS_GP_LEISTUNG,
                   SUM(KP_PREIS_EK_GP_MATERIAL) AS KP_SUMME_PREIS_EK_GP_MATERIAL,
                   SUM(KP_PREIS_EK_GP_LEISTUNG) AS KP_SUMME_PREIS_EK_GP_LEISTUNG,
                   SUM(KP_PREIS_EK_GP_MATERIAL_IST) AS KP_SUMME_PREIS_EK_GP_MATERIAL_IST,
                   SUM(KP_PREIS_GP_LEISTUNG_IST) AS KP_SUMME_PREIS_GP_LEISTUNG_IST,
                   SUM(KP_PREIS_EK_GP_LEISTUNG_IST) AS KP_SUMME_PREIS_EK_GP_LEISTUNG_IST,
                   SUM(KP_MENGE_MATERIAL_IST) AS KP_SUMME_MENGE_MATERIAL_IST,
                   SUM(KP_MENGE_LEISTUNG_IST) AS KP_SUMME_MENGE_LEISTUNG_IST,
                   SUM(KP_PREIS_GP_KOSTEN) AS KP_SUMME_PREIS_GP_KOSTEN,
                   SUM(KP_PREIS_GP_KOSTEN_IST) AS KP_SUMME_PREIS_GP_KOSTEN_IST,
                   SUM(KP_PREIS_EK_GP_KOSTEN) AS KP_SUMME_PREIS_EK_GP_KOSTEN,
                   SUM(KP_PREIS_EK_GP_KOSTEN_IST) AS KP_SUMME_PREIS_EK_GP_KOSTEN_IST,
                   SUM(KP_MENGE_KOSTEN_IST) AS KP_SUMME_MENGE_KOSTEN_IST
            FROM
            (
                SELECT tSK_KALP.ID AS KALP_ID,
                       case
                           when tARST.AR_ART IN ( 0, 2 ) then
                               round(
                                        tSK_KALP.KP_PREIS_GP * tSK_KALP.KP_MENGE
                                        * CASE
                                              WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                  CASE
                                                      WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                      ELSE
                                                          ROUND(
                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                   * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                   4
                                                               )
                                                  END
                                              ELSE
                                                  1
                                          END / case
                                                    when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                         and tSK_KALP.KP_PE_MENGE > 0 then
                                                        tSK_KALP.KP_PE_MENGE
                                                    else
                                                        1
                                                end,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_GP_MATERIAL,
                       case
                           when tARST.AR_ART IN ( 0, 2 ) then
                               round(
                                        CASE
                                            WHEN ISNULL(tSK_KALP_LGBEWE_IST.KPLG_MENGE, 0) <> 0 THEN
                                                tSK_KALP.KP_PREIS_VK_EP * tSK_KALP_LGBEWE_IST.KPLG_MENGE
                                                / case
                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                          tSK_KALP.KP_PE_MENGE
                                                      else
                                                          1
                                                  end
                                            ELSE
                                                CASE
                                                    WHEN ISNULL(SUMME_MATERIAL, 0) <> 0 then
                                                        SUMME_MATERIAL
                                                    ELSE
                                                        CASE
                                                            WHEN ISNULL(SUMME_MATERIAL_PROD_RUECK_VK, 0) <> 0 THEN
                                                                SUMME_MATERIAL_PROD_RUECK_VK
                                                                / case
                                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                                          tSK_KALP.KP_PE_MENGE
                                                                      else
                                                                          1
                                                                  end
                                                            ELSE
                                                                0 /*CASE WHEN  0  = 0 THEN tSK_KALP.KP_PREIS_GP *   tSK_KALP.KP_MENGE * CASE WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN CASE WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN tBE_BELP_MESU.BP_MESU_FE_MENGE ELSE ROUND(tBE_BELP_MESU.BP_MESU_FE_MENGE * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO, 4) END ELSE 1 END    ELSE 0 END*/
                                                        END
                                                END
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_GP_MATERIAL_IST,
                       case
                           when tARST.AR_ART = 1 then
                               round(
                                        tSK_KALP.KP_PREIS_GP * tSK_KALP.KP_MENGE
                                        * CASE
                                              WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                  CASE
                                                      WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                      ELSE
                                                          ROUND(
                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                   * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                   4
                                                               )
                                                  END
                                              ELSE
                                                  1
                                          END / case
                                                    when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                         and tSK_KALP.KP_PE_MENGE > 0 then
                                                        tSK_KALP.KP_PE_MENGE
                                                    else
                                                        1
                                                end,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_GP_LEISTUNG,
                       case
                           when tARST.AR_ART IN ( 0, 2 ) then
                               round(
                                        round((tSK_KALP.KP_PREIS_EK_EP), 4) * tSK_KALP.KP_MENGE
                                        * CASE
                                              WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                  CASE
                                                      WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                      ELSE
                                                          ROUND(
                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                   * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                   4
                                                               )
                                                  END
                                              ELSE
                                                  1
                                          END / case
                                                    when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                         and tSK_KALP.KP_PE_MENGE > 0 then
                                                        tSK_KALP.KP_PE_MENGE
                                                    else
                                                        1
                                                end,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_EK_GP_MATERIAL,
                       case
                           when tARST.AR_ART IN ( 0, 2 ) then
                               round(
                                        CASE
                                            WHEN ISNULL(tSK_KALP_LGBEWE_IST.KPLG_MENGE, 0) <> 0 THEN
                                                tSK_KALP.KP_PREIS_EK_EP * tSK_KALP_LGBEWE_IST.KPLG_MENGE
                                                / case
                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                          tSK_KALP.KP_PE_MENGE
                                                      else
                                                          1
                                                  end
                                            ELSE
                                                CASE
                                                    WHEN ISNULL(SUMME_MATERIAL, 0) <> 0 then
                                                        SUMME_MATERIAL
                                                    ELSE
                                                        CASE
                                                            WHEN ISNULL(SUMME_MATERIAL_PROD_RUECK, 0) <> 0 THEN
                                                                SUMME_MATERIAL_PROD_RUECK
                                                                / case
                                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                                          tSK_KALP.KP_PE_MENGE
                                                                      else
                                                                          1
                                                                  end
                                                            ELSE
                                                                tSK_KALP.KP_PREIS_EK_EP * 0 /*CASE WHEN  0  = 0 THEN tSK_KALP.KP_MENGE *   tSK_KALP.KP_MENGE * CASE WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN CASE WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN tBE_BELP_MESU.BP_MESU_FE_MENGE ELSE ROUND(tBE_BELP_MESU.BP_MESU_FE_MENGE * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO, 4) END ELSE 1 END    /   case when tSK_KALP.KP_PE_ABWEICHEND = 1 and tSK_KALP.KP_PE_MENGE > 0 then     tSK_KALP.KP_PE_MENGE else     1 end  ELSE 0 END*/
                                                        END
                                                END
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_EK_GP_MATERIAL_IST,
                       case
                           when tARST.AR_ART = 1 then
                               round(
                                        round((tSK_KALP.KP_PREIS_EK_EP), 4) * tSK_KALP.KP_MENGE
                                        * CASE
                                              WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                  CASE
                                                      WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                      ELSE
                                                          ROUND(
                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                   * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                   4
                                                               )
                                                  END
                                              ELSE
                                                  1
                                          END / case
                                                    when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                         and tSK_KALP.KP_PE_MENGE > 0 then
                                                        tSK_KALP.KP_PE_MENGE
                                                    else
                                                        1
                                                end,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_EK_GP_LEISTUNG,
                       case
                           when tARST.AR_ART = 1 then
                               round(   CASE
                                            WHEN ISNULL(SUMME_FREMDLEISTUNG, 0) <> 0 then
                                                SUMME_FREMDLEISTUNG
                                            ELSE
                                                0
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_GP_LEISTUNG_IST,
                       case
                           when tARST.AR_ART = 1 then
                               round(   CASE
                                            WHEN ISNULL(SUMME_FREMDLEISTUNG, 0) <> 0 then
                                                SUMME_FREMDLEISTUNG
                                            ELSE
                                                tSK_KALP.KP_PREIS_EK_EP * 0
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_EK_GP_LEISTUNG_IST,
                       case
                           when tARST.AR_ART IN ( 0, 2 ) then
                               round(   CASE
                                            WHEN ISNULL(tSK_KALP_LGBEWE_IST.KPLG_MENGE, 0) <> 0 THEN
                                                tSK_KALP_LGBEWE_IST.KPLG_MENGE
                                            ELSE
                                                CASE
                                                    WHEN ISNULL(SUMME_MATERIAL_MENGE, 0) <> 0 then
                                                        SUMME_MATERIAL_MENGE
                                                    ELSE
                                                        CASE
                                                            WHEN ISNULL(SUMME_MATERIAL_MENGE_PROD_RUECK, 0) <> 0 THEN
                                                                SUMME_MATERIAL_MENGE_PROD_RUECK
                                                            ELSE
                                                                0
                                                        END
                                                END
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_MENGE_MATERIAL_IST,
                       case
                           when tARST.AR_ART = 1 then
                               round(   CASE
                                            WHEN ISNULL(SUMME_FREMDLEISTUNG_MENGE, 0) <> 0 then
                                                SUMME_FREMDLEISTUNG_MENGE
                                            ELSE
                                                0
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_MENGE_LEISTUNG_IST,
                       case
                           when tARST.AR_ART = 3
                                AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 then
                               round(
                                        tSK_KALP.KP_PREIS_GP * tSK_KALP.KP_MENGE
                                        * CASE
                                              WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                  CASE
                                                      WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                      ELSE
                                                          ROUND(
                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                   * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                   4
                                                               )
                                                  END
                                              ELSE
                                                  1
                                          END / case
                                                    when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                         and tSK_KALP.KP_PE_MENGE > 0 then
                                                        tSK_KALP.KP_PE_MENGE
                                                    else
                                                        1
                                                end,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_GP_KOSTEN,
                       case
                           when tARST.AR_ART = 3
                                AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 then
                               round(
                                        CASE
                                            WHEN ISNULL(tSK_KALP_LGBEWE_IST.KPLG_MENGE, 0) <> 0 THEN
                                                tSK_KALP.KP_PREIS_VK_EP * tSK_KALP_LGBEWE_IST.KPLG_MENGE
                                                / case
                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                          tSK_KALP.KP_PE_MENGE
                                                      else
                                                          1
                                                  end
                                            ELSE
                                                CASE
                                                    WHEN ISNULL(SUMME_KOSTEN, 0) <> 0 then
                                                        SUMME_KOSTEN
                                                    ELSE
                                                        CASE
                                                            WHEN ISNULL(SUMME_KOSTEN_PROD_RUECK_VK, 0) <> 0 THEN
                                                                SUMME_KOSTEN_PROD_RUECK_VK
                                                                / case
                                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                                          tSK_KALP.KP_PE_MENGE
                                                                      else
                                                                          1
                                                                  end
                                                            ELSE
                                                                0 /*CASE WHEN  0  = 0 THEN tSK_KALP.KP_PREIS_GP *   tSK_KALP.KP_MENGE * CASE WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN CASE WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN tBE_BELP_MESU.BP_MESU_FE_MENGE ELSE ROUND(tBE_BELP_MESU.BP_MESU_FE_MENGE * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO, 4) END ELSE 1 END    ELSE 0 END*/
                                                        END
                                                END
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_GP_KOSTEN_IST,
                       case
                           when tARST.AR_ART = 3
                                AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 then
                               round(
                                        round((tSK_KALP.KP_PREIS_EK_EP), 4) * tSK_KALP.KP_MENGE
                                        * CASE
                                              WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                  CASE
                                                      WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                          tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                      ELSE
                                                          ROUND(
                                                                   tBE_BELP_MESU.BP_MESU_FE_MENGE
                                                                   * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO,
                                                                   4
                                                               )
                                                  END
                                              ELSE
                                                  1
                                          END / case
                                                    when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                         and tSK_KALP.KP_PE_MENGE > 0 then
                                                        tSK_KALP.KP_PE_MENGE
                                                    else
                                                        1
                                                end,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_EK_GP_KOSTEN,
                       case
                           when tARST.AR_ART = 3
                                AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 then
                               round(
                                        CASE
                                            WHEN ISNULL(tSK_KALP_LGBEWE_IST.KPLG_MENGE, 0) <> 0 THEN
                                                tSK_KALP.KP_PREIS_EK_EP * tSK_KALP_LGBEWE_IST.KPLG_MENGE
                                                / case
                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                          tSK_KALP.KP_PE_MENGE
                                                      else
                                                          1
                                                  end
                                            ELSE
                                                CASE
                                                    WHEN ISNULL(SUMME_KOSTEN, 0) <> 0 then
                                                        SUMME_KOSTEN
                                                    ELSE
                                                        CASE
                                                            WHEN ISNULL(SUMME_KOSTEN_PROD_RUECK, 0) <> 0 THEN
                                                                SUMME_KOSTEN_PROD_RUECK
                                                                / case
                                                                      when tSK_KALP.KP_PE_ABWEICHEND = 1
                                                                           and tSK_KALP.KP_PE_MENGE > 0 then
                                                                          tSK_KALP.KP_PE_MENGE
                                                                      else
                                                                          1
                                                                  end
                                                            ELSE
                                                                tSK_KALP.KP_PREIS_EK_EP * 0 /*CASE WHEN  0  = 0 THEN tSK_KALP.KP_MENGE *   tSK_KALP.KP_MENGE * CASE WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN CASE WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN tBE_BELP_MESU.BP_MESU_FE_MENGE ELSE ROUND(tBE_BELP_MESU.BP_MESU_FE_MENGE * tBE_BELP_MESU.BP_MESU_GEWICHT_NETTO, 4) END ELSE 1 END    /   case when tSK_KALP.KP_PE_ABWEICHEND = 1 and tSK_KALP.KP_PE_MENGE > 0 then     tSK_KALP.KP_PE_MENGE else     1 end  ELSE 0 END*/
                                                        END
                                                END
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_PREIS_EK_GP_KOSTEN_IST,
                       case
                           when tARST.AR_ART = 3
                                AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 then
                               round(   CASE
                                            WHEN ISNULL(tSK_KALP_LGBEWE_IST.KPLG_MENGE, 0) <> 0 THEN
                                                tSK_KALP_LGBEWE_IST.KPLG_MENGE
                                            ELSE
                                                CASE
                                                    WHEN ISNULL(SUMME_KOSTEN_MENGE, 0) <> 0 then
                                                        SUMME_KOSTEN_MENGE
                                                    ELSE
                                                        CASE
                                                            WHEN ISNULL(SUMME_KOSTEN_MENGE_PROD_RUECK, 0) <> 0 THEN
                                                                SUMME_KOSTEN_MENGE_PROD_RUECK
                                                            ELSE
                                                                0
                                                        END
                                                END
                                        END,
                                        4
                                    )
                           else
                               0
                       end as KP_MENGE_KOSTEN_IST
                FROM tSK_KALP
                    LEFT JOIN tSK_KALK
                        ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                    LEFT JOIN tSK_KALV
                        ON tSK_KALV.ID = tSK_KALP.KP_IDSKKV_POS
                    LEFT JOIN tBE_BELP_MESU
                        ON tBE_BELP_MESU.BP_MESU_IDBEBP = tSK_KALK.KK_IDBEBP
                    LEFT JOIN tARST
                        ON tARST.ID = tSK_KALP.KP_IDAR
                    LEFT JOIN
                    (
                        SELECT KPLG_IDSKKP,
                               SUM(KPLG_MENGE) AS KPLG_MENGE
                        FROM tSK_KALP_LGBEWE
                        WHERE CONVERT(DATETIME, KPLG_DATUM, 104) <= CONVERT(DATETIME, GETDATE(), 104)
                        GROUP BY KPLG_IDSKKP
                    ) AS tSK_KALP_LGBEWE_IST
                        ON tSK_KALP_LGBEWE_IST.KPLG_IDSKKP = tSK_KALP.ID
                    LEFT JOIN
                    (
                        SELECT ROUND(ISNULL(SUMME_FREMDLEISTUNG, 0), 4) AS SUMME_FREMDLEISTUNG,
                               ROUND(ISNULL(SUMME_FREMDLEISTUNG_MENGE, 0), 4) AS SUMME_FREMDLEISTUNG_MENGE,
                               PM_IDAR,
                               PM_IDBEBP
                        FROM
                        (
                            SELECT SUM(   CASE
                                              WHEN CNT_ID = 0 THEN
                                                  0
                                              ELSE
                                                  CASE
                                                      WHEN AR_ART = 1 THEN
                                                          ISNULL(PM_MENGE_FE, 0) * ISNULL(PM_EK_EP_NETTO, 0)
                                                      ELSE
                                                          0
                                                  END / CNT_ID
                                          END
                                      ) AS SUMME_FREMDLEISTUNG,
                                   SUM(   CASE
                                              WHEN CNT_ID = 0 THEN
                                                  0
                                              ELSE
                                                  CASE
                                                      WHEN AR_ART = 1 THEN
                                                          ISNULL(PM_MENGE_FE, 0)
                                                      ELSE
                                                          0
                                                  END / CNT_ID
                                          END
                                      ) AS SUMME_FREMDLEISTUNG_MENGE,
                                   PM_IDAR,
                                   PM_IDBEBP
                            FROM
                            (
                                SELECT tPV_PROM.*,
                                       AR_ART,
                                       tBE_BELP_MESU.BP_MESU_FE_MENGE
                                FROM tPV_PROM
                                    LEFT JOIN tARST
                                        ON tARST.ID = tPV_PROM.PM_IDAR
                                    LEFT JOIN tBE_BELP_MESU
                                        ON tBE_BELP_MESU.BP_MESU_IDBEBP = tPV_PROM.PM_IDBEBP
                                WHERE ISNULL(tPV_PROM.PM_IDBEBP, 0) <> 0
                                      AND CONVERT(DATETIME, PM_DATUM, 104) <= CONVERT(DATETIME, GETDATE(), 104)
                                      AND AR_ART = 1
                            ) AS TEMP_SUM_PROM
                                LEFT JOIN tSK_KALK
                                    ON tSK_KALK.KK_IDBEBP = TEMP_SUM_PROM.PM_IDBEBP
                                LEFT JOIN
                                (
                                    SELECT COUNT(ID) AS CNT_ID,
                                           KP_IDAR,
                                           KP_IDSKKK
                                    FROM tSK_KALP
                                    WHERE tSK_KALP.ID NOT IN (
                                                                 SELECT KPLG_IDSKKP FROM tSK_KALP_LGBEWE
                                                             )
                                    GROUP BY KP_IDAR,
                                             KP_IDSKKK
                                ) AS KALP
                                    ON KALP.KP_IDSKKK = tSK_KALK.ID
                                       AND KALP.KP_IDAR = TEMP_SUM_PROM.PM_IDAR
                            GROUP BY PM_IDAR,
                                     PM_IDBEBP
                        ) TEMP_GRP_PROV
                    ) AS tSUMME_FK_ARST
                        ON tSUMME_FK_ARST.PM_IDAR = tSK_KALP.KP_IDAR
                           AND tSUMME_FK_ARST.PM_IDBEBP = tSK_KALK.KK_IDBEBP
                    LEFT JOIN
                    (
                        SELECT ROUND(ISNULL(SUMME_MATERIAL, 0), 4) AS SUMME_MATERIAL,
                               ROUND(ISNULL(SUMME_MATERIAL_MENGE, 0), 4) AS SUMME_MATERIAL_MENGE,
                               PM_IDAR,
                               PM_IDBEBP
                        FROM
                        (
                            SELECT SUM(   CASE
                                              WHEN CNT_ID = 0 THEN
                                                  0
                                              ELSE
                                                  CASE
                                                      WHEN AR_ART = 0
                                                           OR AR_ART = 2 THEN
                                                          ISNULL(PM_MENGE_FE, 0) * ISNULL(PM_EK_EP_NETTO, 0)
                                                      ELSE
                                                          0
                                                  END / CNT_ID
                                          END
                                      ) AS SUMME_MATERIAL,
                                   SUM(   CASE
                                              WHEN CNT_ID = 0 THEN
                                                  0
                                              ELSE
                                                  CASE
                                                      WHEN AR_ART = 0
                                                           OR AR_ART = 2 THEN
                                                          ISNULL(PM_MENGE_FE, 0)
                                                      ELSE
                                                          0
                                                  END / CNT_ID
                                          END
                                      ) AS SUMME_MATERIAL_MENGE,
                                   PM_IDAR,
                                   PM_IDBEBP
                            FROM
                            (
                                SELECT tPV_PROM.*,
                                       AR_ART,
                                       tBE_BELP_MESU.BP_MESU_FE_MENGE
                                FROM tPV_PROM
                                    LEFT JOIN tARST
                                        ON tARST.ID = tPV_PROM.PM_IDAR
                                    LEFT JOIN tBE_BELP_MESU
                                        ON tBE_BELP_MESU.BP_MESU_IDBEBP = tPV_PROM.PM_IDBEBP
                                WHERE ISNULL(tPV_PROM.PM_IDBEBP, 0) <> 0
                                      AND AR_ART IN ( 0, 2 )
                            ) AS TEMP_SUM_PROM
                                LEFT JOIN tSK_KALK
                                    ON tSK_KALK.KK_IDBEBP = TEMP_SUM_PROM.PM_IDBEBP
                                LEFT JOIN
                                (
                                    SELECT COUNT(ID) AS CNT_ID,
                                           KP_IDAR,
                                           KP_IDSKKK
                                    FROM tSK_KALP
                                    WHERE tSK_KALP.ID NOT IN (
                                                                 SELECT KPLG_IDSKKP FROM tSK_KALP_LGBEWE
                                                             )
                                    GROUP BY KP_IDAR,
                                             KP_IDSKKK
                                ) AS KALP
                                    ON KALP.KP_IDSKKK = tSK_KALK.ID
                                       AND KALP.KP_IDAR = TEMP_SUM_PROM.PM_IDAR
                            GROUP BY PM_IDAR,
                                     PM_IDBEBP
                        ) TEMP_GRP_PROV
                    ) AS tSUMME_MAT_ARST
                        ON tSUMME_MAT_ARST.PM_IDAR = tSK_KALP.KP_IDAR
                           AND tSUMME_MAT_ARST.PM_IDBEBP = tSK_KALK.KK_IDBEBP
                    LEFT JOIN
                    (
                        SELECT ROUND(ISNULL(SUMME_KOSTEN, 0), 4) AS SUMME_KOSTEN,
                               ROUND(ISNULL(SUMME_KOSTEN_MENGE, 0), 4) AS SUMME_KOSTEN_MENGE,
                               PM_IDAR,
                               PM_IDBEBP
                        FROM
                        (
                            SELECT SUM(   CASE
                                              WHEN CNT_ID = 0 THEN
                                                  0
                                              ELSE
                                                  CASE
                                                      WHEN AR_ART = 3 THEN
                                                          ISNULL(PM_MENGE_FE, 0) * ISNULL(PM_EK_EP_NETTO, 0)
                                                      ELSE
                                                          0
                                                  END / CNT_ID
                                          END
                                      ) AS SUMME_KOSTEN,
                                   SUM(   CASE
                                              WHEN CNT_ID = 0 THEN
                                                  0
                                              ELSE
                                                  CASE
                                                      WHEN AR_ART = 3 THEN
                                                          ISNULL(PM_MENGE_FE, 0)
                                                      ELSE
                                                          0
                                                  END / CNT_ID
                                          END
                                      ) AS SUMME_KOSTEN_MENGE,
                                   PM_IDAR,
                                   PM_IDBEBP
                            FROM
                            (
                                SELECT tPV_PROM.*,
                                       AR_ART,
                                       tBE_BELP_MESU.BP_MESU_FE_MENGE
                                FROM tPV_PROM
                                    LEFT JOIN tARST
                                        ON tARST.ID = tPV_PROM.PM_IDAR
                                    LEFT JOIN tBE_BELP_MESU
                                        ON tBE_BELP_MESU.BP_MESU_IDBEBP = tPV_PROM.PM_IDBEBP
                                WHERE ISNULL(tPV_PROM.PM_IDBEBP, 0) <> 0
                                      AND AR_ART = 3
                            ) AS TEMP_SUM_PROM
                                LEFT JOIN tSK_KALK
                                    ON tSK_KALK.KK_IDBEBP = TEMP_SUM_PROM.PM_IDBEBP
                                LEFT JOIN
                                (
                                    SELECT COUNT(ID) AS CNT_ID,
                                           KP_IDAR,
                                           KP_IDSKKK
                                    FROM tSK_KALP
                                    WHERE tSK_KALP.ID NOT IN (
                                                                 SELECT KPLG_IDSKKP FROM tSK_KALP_LGBEWE
                                                             )
                                    GROUP BY KP_IDAR,
                                             KP_IDSKKK
                                ) AS KALP
                                    ON KALP.KP_IDSKKK = tSK_KALK.ID
                                       AND KALP.KP_IDAR = TEMP_SUM_PROM.PM_IDAR
                            GROUP BY PM_IDAR,
                                     PM_IDBEBP
                        ) TEMP_GRP_PROV
                    ) AS tSUMME_KOST_ARST
                        ON tSUMME_KOST_ARST.PM_IDAR = tSK_KALP.KP_IDAR
                           AND tSUMME_KOST_ARST.PM_IDBEBP = tSK_KALK.KK_IDBEBP
                    LEFT JOIN
                    (
                        SELECT ROUND(SUMME_MATERIAL, 4) AS SUMME_MATERIAL_PROD_RUECK,
                               ROUND(SUMME_MATERIAL_VK, 4) AS SUMME_MATERIAL_PROD_RUECK_VK,
                               ROUND(SUMME_MATERIAL_VK_MENGE, 4) AS SUMME_MATERIAL_MENGE_PROD_RUECK,
                               ARST_ID,
                               KALP_ID
                        FROM
                        (
                            SELECT SUM(   CASE
                                              WHEN AR_ART = 0
                                                   OR AR_ART = 2 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        ) * ISNULL(KP_PREIS_EK_EP, 0)
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_MATERIAL,
                                   SUM(   CASE
                                              WHEN AR_ART = 0
                                                   OR AR_ART = 2 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        ) * ISNULL(KP_PREIS_VK_EP, 0)
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_MATERIAL_VK,
                                   SUM(   CASE
                                              WHEN AR_ART = 0
                                                   OR AR_ART = 2 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        )
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_MATERIAL_VK_MENGE,
                                   tARST.ID AS ARST_ID,
                                   tSK_KALP.ID AS KALP_ID
                            FROM tSK_KALP
                                LEFT JOIN tARST
                                    ON tARST.ID = tSK_KALP.KP_IDAR
                                LEFT JOIN tSK_KALK
                                    ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                                LEFT JOIN tBE_BELP
                                    ON tBE_BELP.ID = tSK_KALK.KK_IDBEBP
                                LEFT JOIN tBE_BELP_MESU
                                    ON tBE_BELP_MESU.BP_MESU_IDBEBP = tSK_KALK.KK_IDBEBP
                                LEFT JOIN tBE_BELP_LIEF
                                    ON tBE_BELP_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID
                                LEFT JOIN tBE_BELP_MESU AS tBE_BELP_MESU_PR
                                    ON tBE_BELP_MESU_PR.BP_MESU_IDBEBP = tBE_BELP_LIEF.BP_LIEF_IDBEBP_LIEF
                            WHERE tARST.AR_TYP_LAGER_BUCHUNG = 1
                            GROUP BY tARST.ID,
                                     tSK_KALP.ID
                        ) TEMP_GRP_LGBW
                    ) AS TMP_SUMMEN_PROD_RUECK
                        ON TMP_SUMMEN_PROD_RUECK.ARST_ID = tSK_KALP.KP_IDAR
                           AND TMP_SUMMEN_PROD_RUECK.KALP_ID = tSK_KALP.ID
                    LEFT JOIN
                    (
                        SELECT ROUND(SUMME_LEISTUNG, 4) AS SUMME_LEISTUNG_PROD_RUECK,
                               ROUND(SUMME_LEISTUNG_VK, 4) AS SUMME_LEISTUNG_PROD_RUECK_VK,
                               ROUND(SUMME_LEISTUNG_MENGE, 4) AS SUMME_LEISTUNG_MENGE_PROD_RUECK,
                               ARST_ID,
                               KALP_ID
                        FROM
                        (
                            SELECT SUM(   CASE
                                              WHEN AR_ART = 1 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        ) * ISNULL(KP_PREIS_EK_EP, 0)
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_LEISTUNG,
                                   SUM(   CASE
                                              WHEN AR_ART = 1 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        ) * ISNULL(KP_PREIS_VK_EP, 0)
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_LEISTUNG_VK,
                                   SUM(   CASE
                                              WHEN AR_ART = 1 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        )
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_LEISTUNG_MENGE,
                                   tARST.ID AS ARST_ID,
                                   tSK_KALP.ID AS KALP_ID
                            FROM tSK_KALP
                                LEFT JOIN tARST
                                    ON tARST.ID = tSK_KALP.KP_IDAR
                                LEFT JOIN tSK_KALK
                                    ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                                LEFT JOIN tBE_BELP
                                    ON tBE_BELP.ID = tSK_KALK.KK_IDBEBP
                                LEFT JOIN tBE_BELP_MESU
                                    ON tBE_BELP_MESU.BP_MESU_IDBEBP = tSK_KALK.KK_IDBEBP
                                LEFT JOIN tBE_BELP_LIEF
                                    ON tBE_BELP_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID
                                LEFT JOIN tBE_BELP_MESU AS tBE_BELP_MESU_PR
                                    ON tBE_BELP_MESU_PR.BP_MESU_IDBEBP = tBE_BELP_LIEF.BP_LIEF_IDBEBP_LIEF
                            GROUP BY tARST.ID,
                                     tSK_KALP.ID
                        ) TEMP_GRP_LGBW
                    ) AS TMP_SUMMEN_PROD_RUECK_LEISTUNG
                        ON TMP_SUMMEN_PROD_RUECK_LEISTUNG.ARST_ID = tSK_KALP.KP_IDAR
                           AND TMP_SUMMEN_PROD_RUECK_LEISTUNG.KALP_ID = tSK_KALP.ID
                    LEFT JOIN
                    (
                        SELECT ROUND(SUMME_KOSTEN, 4) AS SUMME_KOSTEN_PROD_RUECK,
                               ROUND(SUMME_KOSTEN_VK, 4) AS SUMME_KOSTEN_PROD_RUECK_VK,
                               ROUND(SUMME_KOSTEN_MENGE, 4) AS SUMME_KOSTEN_MENGE_PROD_RUECK,
                               ARST_ID,
                               KALP_ID
                        FROM
                        (
                            SELECT SUM(   CASE
                                              WHEN AR_ART = 3
                                                   AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        ) * ISNULL(KP_PREIS_EK_EP, 0)
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_KOSTEN,
                                   SUM(   CASE
                                              WHEN AR_ART = 3
                                                   AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        ) * ISNULL(KP_PREIS_VK_EP, 0)
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_KOSTEN_VK,
                                   SUM(   CASE
                                              WHEN AR_ART = 3
                                                   AND tSK_KALP.KP_TYP_KOSTEN_KALKULATION = 0 THEN
                                                  ISNULL(
                                                            tSK_KALP.KP_MENGE
                                                            * CASE
                                                                  WHEN tSK_KALP.KP_TYP_MENGE_BASIS = 0 THEN
                                                                      CASE
                                                                          WHEN tSK_KALP.KP_HK_MENGE_BASIS = 0 THEN
                                                                              tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                          ELSE
                                                                              ROUND(
                                                                                       tBE_BELP_MESU_PR.BP_MESU_FE_MENGE
                                                                                       * tBE_BELP_MESU_PR.BP_MESU_GEWICHT_NETTO,
                                                                                       4
                                                                                   )
                                                                      END
                                                                  ELSE
                                                                      1
                                                              END,
                                                            0
                                                        )
                                              ELSE
                                                  0
                                          END
                                      ) AS SUMME_KOSTEN_MENGE,
                                   tARST.ID AS ARST_ID,
                                   tSK_KALP.ID AS KALP_ID
                            FROM tSK_KALP
                                LEFT JOIN tARST
                                    ON tARST.ID = tSK_KALP.KP_IDAR
                                LEFT JOIN tSK_KALK
                                    ON tSK_KALK.ID = tSK_KALP.KP_IDSKKK
                                LEFT JOIN tBE_BELP
                                    ON tBE_BELP.ID = tSK_KALK.KK_IDBEBP
                                LEFT JOIN tBE_BELP_MESU
                                    ON tBE_BELP_MESU.BP_MESU_IDBEBP = tSK_KALK.KK_IDBEBP
                                LEFT JOIN tBE_BELP_LIEF
                                    ON tBE_BELP_LIEF.BP_LIEF_IDBEBP = tBE_BELP.ID
                                LEFT JOIN tBE_BELP_MESU AS tBE_BELP_MESU_PR
                                    ON tBE_BELP_MESU_PR.BP_MESU_IDBEBP = tBE_BELP_LIEF.BP_LIEF_IDBEBP_LIEF
                            GROUP BY tARST.ID,
                                     tSK_KALP.ID
                        ) TEMP_GRP_LGBW
                    ) AS TMP_SUMMEN_PROD_RUECK_KOSTEN
                        ON TMP_SUMMEN_PROD_RUECK_KOSTEN.ARST_ID = tSK_KALP.KP_IDAR
                           AND TMP_SUMMEN_PROD_RUECK_KOSTEN.KALP_ID = tSK_KALP.ID
            ) AS tSK_KALK_JOIN
            GROUP BY KALP_ID
        ) AS SKKALK_IST
            ON SKKALK_IST.KALP_ID = tSK_KALP.ID)
    WHERE tSK_KALP.KP_IDSKKK IN ( 69825 )
) AS tPPS_SKKALP
WHERE (
          tPPS_SKKALP.PSP_IDSKKK IN ( 69825 )
          OR tPPS_SKKALP.PSP_IDPSKKK = 70153
      )
ORDER BY PSP_POSITION_NUMMER ASC,
         D4IV_TYP_HERKUNFT
go